INSERT INTO `news_translations` (`id`, `news_id`, `title`, `slug`, `short_description`, `content`, `meta_title`, `meta_keyword`, `meta_description`, `lang`) VALUES
(14, 1, 'تكافئ الفرص والموضوعية في برامجنا', 'تكافئHg', 'نفخر كادارة في الأكاديمية السويدية للتدريب الرياضي SAST اننا نحافظ على معيار العدالة و الموضوعية في التقييم العلمي. يمثل نظام امتحان التقييم الشامل المعمول به', '<p>نفخر كادارة في الأكاديمية السويدية للتدريب الرياضي SAST اننا نحافظ على معيار العدالة و الموضوعية في التقييم العلمي. يمثل نظام امتحان التقييم الشامل المعمول به في تقييم جميع الطلاب المسجلين في أي من البرامج التي تنفذها الأكاديمية السويدية للتدريب الرياضي SAST بشكل يضمن أعلى مستوى من العدالة والموضوعية في عملية التقييم بالاستناد إلى اعتماد نظام الأسئلة المتعددة الخيارات التي يتم تصحيحها بشكل مؤتمن والكتروني تماماً مما يجنب الطالب إشكاليات الرؤى الشخصية والذاتية في عملية تقييم إنجازه التي قد تختلف من مقيم إلى آخر في حالة الأنظمة الامتحانية الكتابية التقليدية، بالإضافة إلى أن نظام الأسئلة المتعددة الخيارات في جوهره يوفر على الطالب العناء المضني للاستذكار و الاستحفاظ كما هو الحال في متطلبات التحضير للامتحانات الكتابية التقليدية. حيث أن الأسئلة المتعددة الخيارات تقدم للطالب الإجابة الصحيحة مدرجة أمامه من ضمن مجموعة من الإجابات الخاطئة، &nbsp;ويتوجب عليه حينئذ أن يعمل عقله بالاستناد إلى المعلومات والمعارف التي كونها خلال عملية التحضير للامتحان التقييمي العلمي لاختيار الإجابات الصحيحة فقط. ولقد أثبتت الأبحاث العلمية الحديثة أن نظام امتحان التقييم العلمي الذي يعتمد آلية الأسئلة المتعددة الخيارات هو النموذج الامتحاني الأكثر كفاءة من كل الأنظمة ووسائل التقييم العلمي المتاحة لتقييم إنجاز الطالب بشكل موضوعي وعادل.</p>\r\n\r\n<p>تتميز الأكاديمية السويدية للتدريب الرياضي SAST بالتعاون مع أرقي هيئات التعليم والتدريب السويدية والاوربية والدولية على حد سواء. حيث تقوم الأكاديمية السويدية للتدريب الرياضي SAST بتنفيذ نخبة من البرامج الدراسية التي تقدمها أرقي هيئات التعليم والتدريب الرياضي المشهود لها بالرفعة والتفرد والمختصة بتقديم برامج التعليم والتدريب المهني الأكثر طلباً في سوق العمل العالمي. وترتبط الأكاديمية السويدية للتدريب الرياضي SAST باتفاقيات تعاون وتمثيل حصري مع مجموعة استثنائية من الهيئات الرياضية الريادية في القارة الاوربية بما يضمن حصول الطلبة من أبناء الوطن العربي المسجلين في الأكاديمية السويدية للتدريب الرياضي SAST على أفضل البرامج التدريبية الرياضية وأكثرها كفاءة وفق أرقي المعايير المعمول بها دوليا.</p>', NULL, NULL, NULL, 'ar'),
(15, 1, 'Equal opportunities and objectivity in our programs', 'تكافئh8', 'As a board at the Swedish Academy of Sport Training (SAST), we are proud to maintain the standard of justice and objectivity in scientific assessment\r\n', '<p dir=\"ltr\"> \r\nAs a board at the Swedish Academy of Sport Training (SAST), we are proud to maintain the standard of justice and objectivity in scientific assessment. The SAST Comprehensive Assessment Exam System is used to assess all students enrolled in any of the SAST programs in a manner that ensures the highest level of Justice and objectivity in the assessment process based on the adoption of the multiple-choice questioning system that is properly corrected and electronically, thus avoiding personal and subjective problems in assessing their achievement that may vary from resident to resident in the case of traditional written probation systems, and the multiple choice system provides the students with the traditional memorabilia requirements.\r\nAs multiple choice questions provide the student with the correct answer listed in a set of incorrect answers, they should work their mind based on the information and knowledge that they have created during the preparation of the scientific assessment exam to choose only the correct answers. Recent scientific research has shown that the system of the Scientific Assessment Exam, which adopts the multiple-choice question mechanism, is the most efficient testing model of all systems and scientific assessment available to assess student achievement objectively and fairly.</p>\r\n\r\n<p dir =\"ltr\"> The Swedish Academy of Sport Training (SAST) is distinguished in cooperation with the finest Swedish, European and international education and training agencies. The Swedish Academy of Sport Training (SAST) is implementing a selection of courses offered by the highest-level sports education and training institutions, which are recognized for their sophistication, individuality and specialized in offering the most demanding vocational education and training programs in the world labor market. The Swedish Academy of Sport Training (SAST) is linked to exclusive cooperation and representation agreements with an exceptional group of leading sports organizations in the European continent, which ensures that students from the Arab World enrolled in the Swedish Academy of Sport Training (SAST) get the best and most efficient sports training programs according to the highest international standards. </p>', NULL, NULL, NULL, 'en'),
(16, 2, 'متواصلون مع طلبتنا', 'متواصUo', 'التواصل التفاعلي المستمر مع الطلبة، وبغض النظر عن المكان الذي يتواجد فيه الطالب، فإن التواصل مع إدارة الأكاديمية السويدية للتدريب الرياضي SAST متاح و ميسر', '<p>التواصل التفاعلي المستمر مع الطلبة، وبغض النظر عن المكان الذي يتواجد فيه الطالب، فإن التواصل مع إدارة الأكاديمية السويدية للتدريب الرياضي SAST متاح و ميسر بطرائق متعددة توفر حرية استثنائية لتواصل الطالب مع ادارة الأكاديمية السويدية للتدريب الرياضي SAST بشكل سهل و ميسر و دون عوائق. حيث يمكن للمتقدم استخدام أي من أقنية التواصل من خلال منظومة التواصل المباشر Online &nbsp;، أو من خلال صفحة الأكاديمية السويدية للتدريب الرياضي SAST على موقع التواصل الاجتماعي Facebook او الانستغرام، أو من خلال حيز التواصل مع الإدارة في ملف التسجيل الإلكتروني الخاص بكل طالب ، أو من خلال حيز التواصل مع الناصح الدراسي في ملف التسجيل الإلكتروني الخاص بالطالب، والتي توفر جميعها أقصى درجات الرعاية المهنية الرفيعة لجميع الطلبة و تقوم بتلبية متطلبات توجيههم بالشكل الأمثل للاستفادة العلمية و العملية من برنامجهم التدريبي تمهيداً لحصولهم على المؤهل العلمي الذي يطمحون إليه.</p>', NULL, NULL, NULL, 'ar'),
(17, 2, 'We keep touch with our students', 'Continuous', 'To keep in touch with students, regardless of where the student is located, contact with the Swedish Academy of Sport Training (SAST) is available and facilitated', '<p style=\"align-text:left;direction:ltr\">\r\n\r\nTo keep in touch with students, regardless of where the student is located, contact with the Swedish Academy of Sport Training (SAST) is available and facilitated in many ways, providing exceptional student freedom to communicate with the Swedish Academy of Sport Training (SAST) easily, easily and unhindered. The applicant can use any of the communication channels through the Online communication system, the SAST web page on the social media Facebook or Instagram , through the communication with management in each student\'s electronic registration file, or through the communication with the presenter in the student\'s e-registration file, which all provide the highest professional standards for all students and meets the requirements of their guidance In preparation for getting the scientific qualification they aspire to.\r\n\r\n</p>\r\n', NULL, NULL, NULL, 'en'),
(18, 3, 'لماذا تختار الاكاديمية السويدية', 'لماذاFK', 'تتمتع الأكاديمية السويدية للتدريب الرياضي SAST بالعديد من المزايا الاستثنائية سواء في  نظامها التعليمي الفريد أو برامجها التدريبية النوعية  أو البنية الإدارية', '<p>تتمتع الأكاديمية السويدية للتدريب الرياضي SAST بالعديد من المزايا الاستثنائية سواء في &nbsp;نظامها التعليمي الفريد أو برامجها التدريبية النوعية &nbsp;أو البنية الإدارية و الإشرافية &nbsp;الرفيعة . حيث قامت بتبني أحدث نظم التعليم المفتوح، حيث يتم استخدام أرقى المنهجيات و أدوات و تقنيات التعليم التفاعلي النشط البناء المعمول بها بعد تعريبها و تقديمها بلغة عربية ناصعة و بطريقة سهلة و ميسرة الى الرياضي العربي.</p>\r\n\r\n<p>ولا بد من الاشارة الى تواضع تكاليف التسجيل. حيث تعتبر التكاليف التي يتم تقاضيها للتسجيل في أي من البرامج &nbsp;التي تنفذها الأكاديمية السويدية للتدريب الرياضي SAST من أقل التكاليف اذا ما قورنت بالرسوم التي تتقاضاها المؤسسات والمراكز التدريبية الاخرى &nbsp;للبرامج الموازية والمشابهة للبرامج التي تنفذها الأكاديمية السويدية للتدريب الرياضي SAST . و ذلك نظراً لأن الأكاديمية السويدية للتدريب الرياضي SAST مؤسسة تعليمية وتدريبية هدفها الاساس ايصال العلوم الحديثة والمتطورة ، و ليست مؤسسة تجارية تبحث عن الربح الاقتصادي البحت. لذا لابد ان نكون شفافين مع جماهيرنا ونعلن ان هامش الأرباح التي تتقاضاها الأكاديمية السويدية للتدريب الرياضي SAST متواضعاً جداً، و التي يتم إضافتها للتكاليف الأساسية لتنفيذ برامجها الدراسية. حيث يتم استخدام تلك الأرباح المتواضعة في تأمين نفقات التشغيل و الموظفين العاملين في الأكاديمية السويدية للتدريب الرياضي SAST ، بالإضافة إلى المجموعة الاستثنائية من البرامج التنويرية و التوعوية الرياضية التي تحرص على تنفذها الأكاديمية السويدية للتدريب الرياضي SAST في الوطن العربي من خلال مرجعيتها الاساسية وهو المجلس العالمي للعلوم الرياضية في السويد GCSS، وعلى سبيل المثال المركز الدولي لكرة اليد، والمكتبة الاكاديمية للكتب والابحاث العلمية، فضلا عن المجلة السويدية للبحوث العلمية.</p>\r\n\r\n<p>الحداثة و المعاصرة وفق أرقى المعايير الدولية، حيث يتم تدقيق و تطوير و مراجعة كافة المقررات التدريبية الخاصة بجميع البرامج التي تنفذها الأكاديمية السويدية للتدريب الرياضي SAST بشكل دوري و مستمر، و بما يضمن تقديم أرقى المعارف العلمية المعمول بها في المملكة السويدية وفق المعايير المعاصرة و الحديثة المعتمدة دوليا واوربيا.</p>', NULL, NULL, NULL, 'ar'),
(19, 3, 'Why Choose Swedish Academy', 'Why', 'The Swedish Academy of Sport Training (SAST) has many exceptional advantages in its unique educational system, quality training programs, and high management and supervisory structure', '<p style= \"text-align:left;direction:ltr;\">\r\nThe Swedish Academy of Sport Training (SAST) has many exceptional advantages in its unique educational system, quality training programs, and high management and supervisory structure. It has adopted the latest open education systems, using the finest methodologies, tools and techniques of active and constructive interactive education that are applied after being introduced in a very good Arabic language and easily accessible to the Arab athlete.</p>\r\n\r\n<p style= \"text-align:left;direction:ltr;\">\r\nThe modest costs of registration must be noted. The costs charged for registration in any of the SAST programs are lower compared to the fees charged by other institutions and training centers for parallel and similar programs implemented by SAST. This is because the Swedish Academy of Sport Training (SAST) is an educational and training institution whose primary objective is to deliver modern and advanced science, and is not a commercial institution that seeks pure economic profit.\r\n</br>\r\nSo we must be transparent to our audiences and declare that the profit margin of  SAST is very modest, which is added to the core costs of implementing their study programs. These modest profits are used to secure operating expenses and staff of the Swedish Academy of Sport Training (SAST), as well as the exceptional range of sports educational and developmental programs that SAST is implementing in the Arab World through its main reference, the World Council of Sport Sciences of Sweden (GCSS), for example, the International Handball Center, and the Academic Library of Books and Research. \r\n</p>\r\n\r\n<p style= \"text-align:left;direction:ltr;\"> Modern and contemporary according to the highest international standards, all training courses for all programs implemented by the Swedish Academy of Sport Training (SAST) are regularly and continuously scrutinized, ensuring that the highest scientific knowledge in the Kingdom of Sweden is presented according to contemporary and modern standards adopted internationally and in Europe.</p>\r\n', NULL, NULL, NULL, 'en'),
(20, 4, 'تميزنا بمعيار الجودة العالمي', 'تميزنr3', 'تتمتع جميع البرامج  التي تنفذها الأكاديمية السويدية للتدريب الرياضي SAST  بعلامة الجودة و ميدالية التميز في التصميم والتنفيذ جودة التعليم الرياضي الشاملة في مج', '<p>تتمتع جميع البرامج &nbsp;التي تنفذها الأكاديمية السويدية للتدريب الرياضي SAST &nbsp;بعلامة الجودة و ميدالية التميز في التصميم والتنفيذ جودة التعليم الرياضي الشاملة في مجال التدريب الرياضي التخصصي من قبل International Accreditation of Sport Education (IASE)، كذلك حصول مناهجنا التدريبية الاعتماد من قبل EuropeActive.</p>\r\n\r\n<p>و يضاف إلى ذلك خضوع جميع البرامج الدراسية المترجمة &nbsp;من اللغة الإنجليزية إلى اللغة العربية إلى تقييم هيئة مستقلة من المترجمين المحترفين قبل اعتماد أي برنامج دراسي مترجم لتقديمه باللغة العربية عن طريق الأكاديمية السويدية للتدريب الرياضي SAST &nbsp;للطلاب من أبناء العالم العربي ، بحيث يحصل الطالب الذي درس باللغة العربية عند إتمامه لكافة المتطلبات النظرية والعملية على مؤهله العلمي بشكل يتطابق تماماً مع المؤهل الذي يحصل عليه الطالب في حال دراسته باللغة الإنجليزية.<br />\r\n&nbsp;</p>', NULL, NULL, NULL, 'ar'),
(21, 4, 'We have a world-class quality\r\n', 'تميزنdA', 'All programs implemented by the Swedish Academy of Sport Training (SAST) have the Quality Mark and the Excellence in Design and implementation Medal', '<p  style=\"test-align:left;direction:ltr\"> All programs implemented by the Swedish Academy of Sport Training (SAST) have the Quality Mark and the Excellence in Design and implementation Medal, the quality of comprehensive sports education in specialized sports training by International acceleration of Sport Education (IASE), and our training courses have been accredited by EuropeActive. </p>\r\n\r\n<p  style=\"test-align:left;direction:ltr\"> In addition, all courses translated from English into Arabic are subject to the evaluation of an independant body of professional translators prior to the adoption of any translated study program to be presented in Arabic through the Swedish Academy of Sport Training (SAST) for Arab students, so that the student who studied in Arabic upon completion of all theoretical and practical requirements will receive his or her scientific qualifications in full accordance with the qualification obtained by the student in English.</p>', NULL, NULL, NULL, 'en'),
(22, 5, 'وداعا للتعليم التقليدي', 'وداعا72', 'شكلت ثورة الاتصالات ومنجزات ثورة المعلومات قفزة استثنائية في التاريخ الحضاري المعاصر، لذا كانت الأكاديمية السويدية للتدريب الرياضي SAST إحدى المؤسسات التعليمية', '<p>شكلت ثورة الاتصالات ومنجزات ثورة المعلومات قفزة استثنائية في التاريخ الحضاري المعاصر، لذا كانت الأكاديمية السويدية للتدريب الرياضي SAST إحدى المؤسسات التعليمية التابعة للمجلس العالمي للعلوم الرياضية في السويد التي قامت باستثمار تلك المنجزات بشكلها الأمثل والأكثر جدوى بما يخدم متطلبات تطوير إمكانيات عقل الإنسان المبدع والمنتج والتي استقت منها الأكاديمية السويدية للتدريب الرياضي منهجيتها في تنفيذ برامج مختلفة في العلوم الرياضية وبالتعاون مع نخبة من الهيئات التعليمية و التدريبية داخل السويد وخارجه ، والذي شكل نجاحه المنقطع النظير إنجازاً غير مسبوق في ميدان التعليم والتدريب الرياضي عن بعد ومختلف أنظمة التعليم المفتوح المعروفة في الدول العربية ، &nbsp;حيث تمخض عنه خلال السنوات الماضية من مشوارنا العملي في التعليم الرياضي من خلال دورات المجلس العالمي للعلوم الرياضية في السويد قوة جبارة تمكنت من تجاوز العقبات البنيوية الصعبة في العالم العربي والتي تعيق استفادة أبناء العالم العربي من إمكانيات الدراسة والتحصيل العلمي والتدريب الرياضي المهني في العالم الغربي وهو حقيقة ما تفخر به إدارة المجلس GCSS والأكاديمية السويدية للتدريب الرياضي SAST &nbsp;المئات من الخريجين ابتداءً من الدفعة الأولى عام 2014 وحتى الوقت الراهن والذين يشغلون في الوقت الحالي أرقى المناصب الرياضية المهنية والاكاديمية بالاستناد إلى مؤهلاتهم العلمية المعتمدة بأعلى شكل دولي .</p>\r\n\r\n<p>الدراسة أون لاين تعني الدراسة الحقيقية من مكان إقامة الطالب اينما يكون ، ليس بالضرورة أن تكون في نفس البلد الذي يقيم فيه الطالب ، وليس ضروريا الحضور في الموعد المخصص للمحاضرات المباشرة التي يؤديها الاساتذة والخبراء. ولا يتوجب على الطالب أيضاً أداء الفروض المنزلية المطلوبة منه وتقديمها في وقتها ، لكن نحتاجه ان يؤدي في نهاية البرنامج الدراسي امتحان (أون لاين) يتوجب على الطالب حضوره و اجتيازه للحصول على الشهادة من الاكاديمية السويدية للتدريب الرياضي SAST.</p>', NULL, NULL, NULL, 'ar'),
(23, 5, 'Goodbye to traditional education', 'وداعا5f', 'The communications revolution and the achievements of the information revolution represented an exceptional leap in contemporary urban history, so the Swedish Academy of Sport Training (SAST)', '<p style=\"align-text:left;direction:ltr;\"> The communications revolution and the achievements of the information revolution represented an exceptional leap in contemporary urban history. The Swedish Academy of Sport Training (SAST) was one of the educational institutions of the World Council for Sport Sciences in Sweden, which invested these achievements in the best and most useful form in order to meet the requirements of developing the creative and productive human mind   from which the Swedish Academy of Sport Training has developed its methodology in the execution of various programs in the sports sciences in cooperation with selected educational and training bodies inside and outside Sweden. </br>\r\n', NULL, NULL, NULL, 'en'),
(24, 6, 'انطلاق مشروع الاكاديمية السويدية للتدريب الرياضي', 'انطلاbq', 'نتطلع ونحن نفتتح هذا الصرح العلمي التدريبي الجديد ان نةفق في تنفيذ اهدافنا المرسومة وستراتيجيتنا المنشودة لتحقيق جميع طموحات روادنا وطلابنا في التعليم عبر الان', '<p>نتطلع ونحن نفتتح هذا الصرح العلمي التدريبي الجديد ان نةفق في تنفيذ اهدافنا المرسومة وستراتيجيتنا المنشودة لتحقيق جميع طموحات روادنا وطلابنا في التعليم عبر الانتر نت بافضل واسهل الطرق واحدثها.</p>\r\n\r\n<p>حيث تجتهد إدارة الاكاديمية السويدية للتدريب الرياضي SASTفي تعريب وتطوير منظومات دراسية و بحثية الكترونية متميزة باللغة العربية في ميدان العلوم الرياضية المعاصرة و إعادة صياغتها بما ينسجم مع متطلبات الطالب و الباحث العربي واللغة العربية كعامل أساسي للإبداع والتحصيل والبحث العلمي في مجالات الرياضة وتطبيقاتها .</p>\r\n\r\n<p>لازلنا مستمرين في الاكاديمية السويدية للتدريب الرياضي SASTفي تعريب العديد من البرامج التدريبية ، بما يضمن إتاحة وتقديم المعارف العلمية المعاصرة في القارة العجوز باللغة العربية مع التركيز على قدرة جميع الطلاب على التفاعل الحيوي والذي يؤسس بالنتيجة لخلق فئة متعلمة ومستنيرة تستطيع المساهمة بشكل فعال في عملية البناء والتنوير في العالم العربي.</p>\r\n\r\n<p>تقوم ادارة الاكاديمية السويدية للتدريب الرياضي SASTبالتنسيق الدائم والمستمر مع الكثير من الجامعات والمعاهد والاكاديميات الاوربية والدولية ، والتواصل مع خيرة المدربين والخبراء المحترفين في تخصصاتهم الرياضية لاستقدامهم واستثمارهم في تطوير منظومات عربية متخصصة بجودة الممارسة المهنية للفئات المهنية الراقية في العالم العربي من مدربين ومحاضرين رياضيين او متخصصين في المهن الرياضية المختلفة. وذلك لتسهيل انضمام تلك الفئات العربية في العديد من التخصصات المهنية الأكثر طلباً في السوق العربي والعالمي بما يخدم جهود التنمية و التطوير في المجتمع العربي الكبير من المحيط إلى الخليج.</p>\r\n\r\n<p>يقوم النهج الفكري و التطبيقي في الاكاديمية السويدية للتدريب الرياضي SASTعلى مجموعة من المرتكزات والثوابت المنهجية التي تقوم بنظم استراتيجيات العمل القريبة والبعيدة ، كما تشكل تلك المرتكزات الأدوات الأساسية التي تستخدمها إدارات وأقسام الأكاديمية لتنفيذ حزمة الأهداف التنويرية التي تسعى إليها في الوطن العربي</p>', NULL, NULL, NULL, 'ar'),
(25, 6, 'Swedish Academy of Sport Training Project launched', 'انطلاv9', 'As we open this new scientific training module, we look forward to spending on implementing our goals and our strategy to achieve all the aspirations of our leaders and students in education through the Internet in the best, easiest and most recent way.', '<p style=\"align-text:left;direction:ltr;\"> As we open this new scientific training module, we look forward to spending on implementing our goals and our strategy to achieve all the aspirations of our leaders and students in education through the Internet in the best, easiest and most recent way. </p>\r\n\r\n<p style=\"align-text:left;direction:ltr;\"> The Swedish Academy of Sport Training (SAST) is working to develop and reformulate Arabic-language academic and research systems in the field of contemporary sports science in line with the requirements of the student, Arab researcher and Arabic language as a key factor for creativity, achievement and scientific research in the fields of sports and their applications.</p>\r\n\r\n<p style=\"align-text:left;direction:ltr;\"> We continue at the Swedish Academy of Sport Training (SAST) to express many training programs, ensuring that contemporary scientific knowledge in the ancient continent is available and provided in Arabic, with an emphasis on the ability of all students to interact dynamically and create a well-informed and educated class that can contribute effectively to the construction and enlightenment process in the Arab world. </p>\r\n\r\n<p style=\"align-text:left;direction:ltr;\"> The Swedish Academy of Sport Training (SAST) is continuously coordinating with many European and international universities, institutes and academies, and is communicating with the best trainers and professional experts in their sports disciplines to present and invest in the development of specialized Arab professional systems that are specialized in the quality of the professional practices of the advanced professional groups in the Arab world, from trainers and sports lecturers or specialists in different sports professions. This is to facilitate the inclusion of these Arab groups in many of the most demanding professional disciplines in the Arab and international markets in order to serve the development and development efforts of the large Arab society from the ocean to the Gulf.</p>\r\n\r\n<p style=\"align-text:left;direction:ltr;\"> The intellectual and applied approach of the Swedish Academy of Sport Training (SAST) is based on a range of methodological constants that govern near and far-reaching strategies of action and these are the basic tools used by the departments of the Academy to implement the development goals package that they seek in the Arab world. </p>\r\n', NULL, NULL, NULL, 'en'),
(26, 7, 'افتتاح الاكاديمية السويدية للتدريب الرياضي', 'افتتاZ9', 'في الاول من نيسان في كل سنة تنتشر الاكاذيب في كل مكان احتفاءا بكذبة نيسان. لكن هذه السنة قررت ان اقلب الكذب والخيال الى واقع ملموس.. فبعد سنين من التخطيط وسنة', '<p dir=\"RTL\" style=\"text-align:right\">في الاول من نيسان في كل سنة تنتشر الاكاذيب في كل مكان احتفاءا بكذبة نيسان. لكن هذه السنة قررت ان اقلب الكذب والخيال الى واقع ملموس.. فبعد سنين من التخطيط وسنة من التنفيذ، الاكاديمية السويدية للتدريب الرياضي ترى النور في الاول من نيسان، لتظهر لنا اليوم في حلتها الجميلة وبتصميمها العالمي ونظامها التعليمي الفريد .. الذي افتخر به ما حييت. منصة تعليمية الكترونية مفتوحة وعن بعد مع الاعتمادات الدولية والاجازة الاوربية لمناهجها. صرح تدريبي علمي رياضي متفرد. اخذ منا الكثير من الجهد والتفكير.. لا نبالغ ان نقول اننا اشتغلنا به لمعدل ساعات عمل يومي تصل الى 16 ساعة وبشكل مستمر .. مع فريق عمل رائع من مختلف بقاع الارض.. جمعتنا الغاية وهو صنع التميز والريادة.. &nbsp;شكرا من القلب لملك البرمجة الدكتور مهند سلامي وفريق عمله، الذي سهرنا ليالٍ عجاف معه وهو لا يأبه لكل المشقات والعقبات، حيث ترجم طلباتي الفضائية الى واقع الكتروني ملموس. حتى ايقنت ان كلمة مستحيل غير موجودة في قاموسه المهني المحترف فالشكر والامتنان موصول للدكتور مهند. شكرا لمن تحمل غضبي وهيجاني رغم اجتهاده المنقطع النظير صديقي واخي الاصغر محمود اليحيى.. شكرا لرفيق رحلة العمل البعيد والدائم التواصل وحلال المشاكل المهندس ثائر مخيبر.. شكر وامتنان كبير لمن اخذ على عاتقه بناء الامتحانات الالكترونية كل من الرائعة الدكتورة مها جراد والمتألق المبدع الدكتور حسن جود الله. شكرا لمن ثابر واجتهد في ترجمة اللاف الصفحات من الابحاث العلمية لتزويدنا بالمعلومة الاكيدة والحديثة الاستاذ احمد عبد العزيز وفريق عمله المتميز. شكرا لكل من ساندني بكلمة او بنظرة تشجيع او من ضربة على كتفي محفزا لي ولعملي.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">يروق لي ان اظهر تبختري بين هذه الاسطر ، لاخبركم اننا عملنا على انجاز 15 منهجا دراسيا وتدريبيا وحصلنا على المعيار الدولي لضمان الحقوق. 15 منهجا كتبت والفت بالليل مع النهار. وبمعلومات بعيدة عن التقليد والمألوف.. ترجمنا مئات الابحاث، رصدنا اخر التطورات. عملنا بين التأليف والترجمة والاعداد. من اجل منح هذا الطبق العلمي الذهبي لمن يريد التميز والابداع في الميدان الرياضي.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">سنة بالتمام والكمال انشغلنا بها عن العيال والاصحاب والاهل والاقراب، سنة افتقدنا الكثير من الصحة وتوجت بازمتين قلبيتين. جهد استثنائي جعلني ازيد من وزني 20 كغم لاننا التصقت في الكرسي والطاولة وهجرت الملعب والتمرين الذي ادمنته منذ اربع عقود مضت.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">الاكاديمية السويدية للتدريب الرياضي هي المشروع الرياضي الحقيقي لتطوير جميع المهارات الرياضية وبشكل احترافي. برامج تدريبية مجانية. برامج تدريبية متدرجة. اعتمادات دولية. تخترق الازمان والاماكن، فهي حاضرة بين يديك وفي جوالك وفي جهازك اللوحي والكمبيوتر. تحضر الدروس والمناقشات بكل مرونة واريحية بالصوت والصورة والكتابة. تعطيك المعلومة باسلوب متميز ومتفرد. منصة تعليم الكتروني تنافس بها ارقى الجامعات العالمية، بل اجزم انها تفوقت على بعضها او اغلبها.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">نظام امتحاني الكتروني 100%، يتيح الشفافية والموضوعية في الاختبارات. تمنحك اسئلة عشوائية لتعطيك النتائج بثانية واحد بعد الانتهاء من الاختبار مع الحلول النموذجية. كل شيء خارج المنطق.. لاننا تجاوزنا المألوف وحلقنا في الخيال.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">لمن يريد ان يحلق معنا فاهلا وسهلا بزيارتكم الكريمة على الموقع الالكتروني و يشرفنا ان تتابعنا على صفحتنا في الفيسبوك &nbsp;<a href=\"https://www.facebook.com/swedishacademy/\">https://www.facebook.com/swedishacademy/</a></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>', NULL, NULL, NULL, 'ar'),
(27, 7, 'Swedish Academy of Sport Training Opening\r\n', 'افتتاMH', 'On April 1, every year, lies spread everywhere to celebrate the April fool. This year, however, I decided to turn the lie and imagination into reality', '\r\n<p style=\"text-align:left;direction:ltr;\">On April 1, every year, lies spread everywhere to celebrate the April fool. This year, however, I decided to turn the lie and imagination into reality. After years of planning and a year of implementation, the Swedish Academy of Sport Training sees the light of the day on April 1, showing us today in its beautiful state, with its universal design and unique educational system. Which I am proud of. An open and remote electronic educational platform with international credits and European holiday platforms. A unique sport science training module. it took us a lot of effort and thought.. We do not exaggerate to say that we have worked with it for a daily working hours of 16 hours and continuously. With great staff from different parts of the ground. Our purpose is to make excellence and leadership. </br>\r\nMany thanx for the heart of the programming king Dr. Muhannad Salami and his team, who made us a great night with him and he does not care for all the hardships and obstacles, My impossible requests have been translated into concrete electronic reality. I even thought that the term  impossible  did not exist in his professional career, and thanks and gratitude are attached to Dr. Muhannad. Thank you to those who endured my anger and frustration  despite his exceptional diligence, my friend and my younger brother, Mahmoud Al Yahia. Thank you for your long and permanent business trip companion communication and problem solving engineer Thaer Mukheiber. Thanks and gratitude to those responsible for building e-examinations, both wonderful Dr. Maha Grad and creative brilliance Dr. Hassan Joudallah. Thank you for your persevering and hard work in translating thousands of pages of scientific research to provide us with the assured and modern information Mr. Ahmed Abdel Aziz and his distinguished team.\r\nThank you to each of us for a word, a look of encouragement or a blow to my shoulders and my work </p>\r\n\r\n<p style=\"text-align:left;direction:ltr;\">I would like to show my contempt between these lines, to tell you that we have worked on 15 school and training approaches and obtained the international standard for guaranteeing rights. 15 approaches written and written at night with the day. In addition, with information that is far from traditional and familiar. We have translated hundreds of research, and we have monitored the latest developments. We worked between authoring, translation, and preparation. In order to give this golden scientific class to those who want to excel and innovate in the sports field.</p>\r\n\r\n<p dir\"ltr\" style=\"text-align:left;direction:ltr;\">A complete year, we were completely distracted about the family, the friends and the relatives, a year that we lost a lot of health and culminated in two heart crises. An exceptional effort made me gain 20 kg because I am stuck in the chair and table and the playground and the exercise I have condemned four decades ago have gone. </p>\r\n\r\n<p  style=\"text-align:left;direction:ltr;\">The Swedish Academy of Sport Training is the real sports project for the development of all sports  skills and professionally. Free training programs. Progressive training programs. International appropriations. Times and places go through, they are in your hands, in your mobile, in your tablet, and in your computer. Prepare lessons and discussions flexibly with sound, picture, and writing. The information gives you a unique and distinctive style. An e-learning platform with which the world\'s finest universities compete, I am sure it has surpassed some or most of them.</p>\r\n\r\n<p style=\"text-align:left;direction:ltr;\">100% electronic exam system, allowing transparency and objectivity in the tests. Gives you random questions to give you results one second after completing the test with typical solutions. Everything is beyond logic .. Because we have gone beyond the ordinary and shaved into the imagination. </p>\r\n\r\n<p style=\"text-align:left;direction:ltr;\">For those who would like to fly with us, we welcome your visit on the website and have the honor to follow us on our <a href=\"https://www.facebook.com/swedishacademy\"> Facebook  </a> </p>\r\n\r\n', NULL, NULL, NULL, 'en'),
(28, 9, 'مبروك للطالب الاول', 'مبروكER', 'الف مبروك نقولها للكابتن سلطان علي العنزي لنجاحه في دورة المدرب الشخصي المستوى الاول بطريقة الاون لاين ومن خلال المنصة التعليمية الالكترونية المفتوحة للاكاديمي', '<p dir=\"RTL\" style=\"text-align:right\">الف مبروك نقولها للكابتن سلطان علي العنزي لنجاحه في دورة المدرب الشخصي المستوى الاول بطريقة الاون لاين ومن خلال المنصة التعليمية الالكترونية المفتوحة للاكاديمية السويدية للتدريب الرياضي SAST.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">نتمنى له الموفقية والنجاح في مسيرته التي واصلها معنا الى المستوى الثاني.. ونشكر تفوقه الملحوظ حيث انضم معنا في الاكاديمية في اول يوم انطلاقها الموافق الاحد الاول من ابريل 2017. حيث دأب على الحضور والدراسة يوميا، وهذا ما لمسناه من خلال امتحاناته اليومية والفصلية Quiz.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">يجدر الاشارة الى ان العنزي هو اول طالب مسجل ومتخرج من دوراتنا التدريبية.. شكرا له لثقته التي وضعها في ادارة الاكاديمية ونتمنى ان تكون مناهجنا التدريبية قد اضافت&nbsp;له الشيء الكثير من المعلومات التي تؤهله لان يكون مدربا محترفا في المستقبل.</p>', NULL, NULL, NULL, 'ar'),
(29, 9, 'Congratulations to the first student', 'مبروكf4', 'Congratulations to Captain Sultan Ali Al-Enezi for his success in the first-level Personal Trainer online course and through the open electronic platform of the Swedish Academy', '<p dir=\"ltr\" styyle=\"text-align:left\">Congratulations to Captain Sultan Ali Al-Enezi for his success in the first-level Personal Trainer online course and through the open electronic platform of the Swedish Academy of Sport Training SAST. </p>\r\n\r\n<p dir=\"ltr\" style=\"text-align:left\">\r\nWe wish him success in his journey, which he has reached level 2 with us. We thank him for his remarkable success as he joined us at the Academy on the first day its launch on Sunday 1st April 2017. He has been present and studying every day, and this is what we have seen through his daily and quarterly Quiz.</p>\r\n\r\n<p dir=\"ltr\" style=\"text-align:left\">\r\nIt should be noted that Al-Enezi is the first registered student and graduated from our training courses. We Thank him for his confidence in the Academy management and we hope that our courses have added a lot of information to him to be a future Master Trainer.</p>', NULL, NULL, NULL, 'en'),
(30, 12, 'اختتام دورة الكويت للمدرب الشخصي', 'WEhg', 'اختتمت مؤخرا دورة المدرب الشخصي المستوى الرابع في دولة الكويت وبمشاركة واسعة من مختلف الدول العربية، حيث اقيمت هذه الدورة باعتماد اليورب اكتيف وبتنظيم من قبل ا', '<p dir=\"RTL\" style=\"text-align:right\">اختتمت مؤخرا دورة المدرب الشخصي المستوى الرابع في دولة الكويت وبمشاركة واسعة من مختلف الدول العربية، حيث اقيمت هذه الدورة باعتماد اليورب اكتيف وبتنظيم من قبل الاكاديمية السويدية للتدريب الرياضي والمجلس العالمي للعلوم الرياضية.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">واشرف على الدورة مدير مكتب المجلس العالمي للعلوم الرياضية GCSS في الكويت الدكتور محمد عبد الامير البقشي. والقى المحاضرات كل من المدربين المحترفين كرستوفر سودرستروم وستيفان لوفستروم.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">اشتملت هذه الدور اغلب العلوم النظرية والعملية لمهنة المدرب الشخصي وحسب المعيار الاوربي حيث اشتملت على 40 ساعة تدريبية ضمت كل من تدريب التحمل والتمارين الوظيفية والسرعة وتدريبات القوة وتحسين القوام فضلا عن كيفية التعامل مع المتدربين وبمختلف مستوياتهم الهوات والمحترفين ولكلا الجنسين .</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">تم توزيع شهادات التخرج على الناجحين بالدورة في صالة المؤتمرات في فندق البستكي انترناشيونال وبحضور المتدربين والخبراء وممثل المجلس في دولة قطر الكابتن منصور الانصاري.</p>', NULL, NULL, NULL, 'ar'),
(31, 12, 'Kuwait Personal Trainer Course Closed\r\n', '1Fal', 'The fourth-level personal training course in the State of Kuwait has recently been concluded with the broad participation of various Arab countries,', '<p dir=\"ltr\" style=\"text-align:left\">The fourth-level personal training course in the State of Kuwait has recently been concluded with the broad participation of various Arab countries, with the adoption of the training course by the Swedish Academy of Sport Training and the World Council of Sport Sciences.</p>\r\n\r\n\r\n<p dir=\"ltr\" style=\"text-align:left\">The course was supervised by the Director of the Bureau of the World Council of Sport Sciences (GCSS) in Kuwait, Dr. Mohamed Abdul Amir Al-Baqshi. Lectures were given by Master Trainers Christopher Soderström  and Steven Lofström.</p>\r\n\r\n\r\n<p dir=\"ltr\" style=\"text-align:left\">This course involved most of the theoretical and practical sciences of the personal trainer profession and according to the European standard, which included 40 training hours, including endurance training, career training, speed, strength training, strength improvement, and how to deal with the trainees at different levels; amateurs, professionals and both sexes. </p>\r\n\r\n<p dir=\"ltr\" style=\"text-align:left\">The graduation certificates were distributed to the participants in the course in the conference hall in Al Bastaki International Hotel and in the presence of trainees, experts and the Council representative in Qatar, Captain Mansour Al-Ansari.</p>', NULL, NULL, NULL, 'en'),
(32, 15, 'عضوية المجلس العالمي للعلوم الرياضية مجاناً', 'DrDm', 'يسر ادارة المجلس العالمي للعلوم الرياضية في السويد بفتح التسجيل في عضوية المجلس بشكل مجاني لفترة محدودة، وذلك بمناسبة فتح الموقع الالكتروني الجديد بمواصفات جدي', '<p dir=\"RTL\" style=\"text-align:right\">يسر ادارة المجلس العالمي للعلوم الرياضية في السويد بفتح التسجيل في عضوية المجلس بشكل مجاني لفترة محدودة، وذلك بمناسبة فتح الموقع الالكتروني الجديد بمواصفات جديدة تمنح الاعضاء ميزات كثيرة لعرض نتاجهم العلمي وخبراتهم الرياضية ويناء شبكة تعارف واسعة بين خبراء الرياضة العربية.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">التسجيل للعضوية يكون من خلال مرحلتين.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">اولا. مرحلة تسجيل اسم مستخدم للدخول الى الموقع.. ويحتاج ذلك تأكيد الايميل المرسل لكم بعد التسجيل مباشرة.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">ثانيا. بعد تسجيل اسم المستخدم وتأكيده.. يمكنكم الذهاب الى صفحة استمارة العضوية وتعبئتها وارسالها.. خلال 24 ساعة ستفعل عضويتكم وترسل لكم شهادة العضوية مباشرة الى ايميلكم.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">تتيح لكم عضوية المجلس بانشاء بروفايل خاص بالعضو وفيه كل نتاجه العلمي وشهاداته ومقالاته وسيرته الذاتية والاستفادة من مزايا العضوية كاملة، واشياء اخرى كثيرة.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">لا تنتظر فهي فرصة لوقت محدود جدا.. التحق بخبراء الرياضة.</p>', NULL, NULL, NULL, 'ar'),
(33, 15, 'Free membership of the World Council for Mathematical Sciences', 'oPPP', 'The management of the World Council for Mathematical Sciences in Sweden is pleased to open the membership of the Council free of charge for a limited period, on the occasion of the opening of the new website with new specifications', '<p dir=\"ltr\" style=\"text-align:left\">The administration of the World Council for Mathematical Sciences in Sweden is pleased to open the membership of the Council for free for a limited period, on the occasion of the opening of the new website with new specifications that give members many advantages to display their scientific output and their sports experiences and build a wide network of Arab sports experts.</p>\r\n\r\n<p dir=\"ltr\" style=\"text-align:left\">Registration for membership is in two phases. </p>\r\n\r\n<p dir=\"ltr\" style=\"text-align:left\">First, text first. The stage of registering a username to enter the site. This requires confirmation of the email sent to you immediately after registration</p>\r\n\r\n<p dir=\"ltr\" style=\"text-align:left\">Second, text-align: right. After registering your username and confirming it, you can go to the membership form page and fill it in. Within 24 hours your membership will be activated and your membership certificate will be sent directly to your email address. </p>\r\n\r\n<p dir=\"ltr\" style=\"text-align:left\">Board membership allows you to create a profile for the member with all his scientific output, testimonials, articles, autobiography, and benefit from the benefits of full membership, and many other things. </p>\r\n\r\n<p dir=\"ltr\" style=\"text-align:left\">Don\'t wait, it\'s an opportunity for a very limited time. He joined sports experts. </p>', NULL, NULL, NULL, 'en'),
(34, 16, 'دورة المدرب الشخصي المستوى الاول في السعودية', 'YS5F', NULL, '<p dir=\"LTR\" style=\"text-align:right\"><span dir=\"RTL\" lang=\"AR-IQ\" style=\"font-family:&quot;Arial&quot;,sans-serif\">يعلن المجلس العالمي للعلوم الرياضية في السويد </span><span dir=\"RTL\" lang=\"AR-IQ\" style=\"font-family:&quot;Arial&quot;,sans-serif\">وبالتعاون مع الاكاديمية السويدية للتدريب الرياضي عن انطلاق دوراتها في الممملكة العربية السعودية وتحديدا في الدمام وبأشراف البطل العالمي الكابتن فيصل العليو. والتسجيل مفتوح لكلا الجنسين. </span></p>\r\n\r\n<p dir=\"LTR\" style=\"text-align:right\"><span dir=\"RTL\" lang=\"AR-IQ\" style=\"font-family:&quot;Arial&quot;,sans-serif\"><strong>متى واين:</strong> في الدمام للفترة من 05-07 يوليو/ تموز 2017 من الساعة 04 مساءا- 09 مساءا</span></p>\r\n\r\n<p dir=\"LTR\" style=\"text-align:right\"><span dir=\"RTL\" lang=\"AR-IQ\" style=\"font-family:&quot;Arial&quot;,sans-serif\"><strong>رسوم التسجيل:</strong> 2000 ريال سعودي</span></p>\r\n\r\n<p dir=\"LTR\" style=\"text-align:right\"><span dir=\"RTL\" lang=\"AR-IQ\" style=\"font-family:&quot;Arial&quot;,sans-serif\">تهدف الدورة الى تأسيس المدربين الرياضيين بالطرق الصحيحة للقيام بالتدريب الشخصي. حيث سيتعلم المتدرب خلال الدورة على:</span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">التشريح الرياضي.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">مكونات الخلية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">الهورمونات والانزيمات.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">علم الامراض.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">فسيولوجيا التمارين التطبيقية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">تقييم اللياقة البدنية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">اساسيات كتابة البرامج التدريبية.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">الاتصال مع الزبائن والمتدربين.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">التغذية الرياضية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">اساسيات في المكملات الغذائية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">فسيولوجيا التمارين التطبيقية.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">تقييم اللياقة البدنية</span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">اعتماد الشهادة </span></span></span></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"LTR\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\">The Swedish Academy of Sport Training (SAST).</span></span></span></span></li>\r\n	<li dir=\"LTR\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\">Global Council of Sport Science (GCSS).</span></span></span></span></li>\r\n	<li dir=\"LTR\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\">EuropeActive</span></span></span><span dir=\"RTL\" lang=\"AR-SA\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">.</span></span></span></span></li>\r\n	<li dir=\"LTR\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\">The European Register of Exercise Professionals (EREPS)</span></span></span></span></li>\r\n	<li dir=\"LTR\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\">International Accreditation of Sport Education (IASE).</span></span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"LTR\" style=\"text-align:right\"><span dir=\"RTL\" lang=\"AR-IQ\" style=\"font-family:&quot;Arial&quot;,sans-serif\"><strong>للتسجيل:</strong> يرجى الاتصال على الهاتف 0536677718</span></p>\r\n', NULL, NULL, NULL, 'ar'),
(35, 16, 'Personal Trainer first level in Saudi Arabia', 'P4dW', NULL, NULL, NULL, NULL, NULL, 'en');
INSERT INTO `news_translations` (`id`, `news_id`, `title`, `slug`, `short_description`, `content`, `meta_title`, `meta_keyword`, `meta_description`, `lang`) VALUES
(36, 17, 'دورة اخصائي التغذية الرياضية المستوى الرابع في الكويت', 'o974', NULL, '<p dir=\"RTL\" style=\"text-align:center\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">يقيم المجلس العالمي للعلوم الرياضية في السويد </span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">GCSS</span></span><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"> وبالتعاون مع الاكاديمية السويدية للتدريب الرياضي </span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">SAST</span></span> <span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">دورة اخصائي التغذية الرياضية للمستوى الرابع . </span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"font-size:18px\">اين ومتى؟</span></span></span></strong><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"> الكويت 17-21 نوفمبر 2017</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"font-size:20px\">المحاضر</span>: </span></span></strong><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">الخبير الدولي الكساندر جيرفورت</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:20px\"><strong><span style=\"font-family:&quot;Times New Roman&quot;,serif\">محاور الدورة:</span></strong></span></p>\r\n\r\n<ol>\r\n	<li style=\"list-style-type:none\">\r\n	<ol>\r\n		<li style=\"list-style-type:none\">\r\n		<ol>\r\n			<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">العمل الهورمونات مع مختلف النشاطات الرياضية (هوائي ولاهوائي)</span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">:</span></span></li>\r\n			<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">عمل الهورمونات مع المكملات الغذائية.</span></span></li>\r\n			<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">تصميم البرامج الغذائية لمختلف الالعاب الرياضية.</span></span></li>\r\n			<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">المكملات الغذائية المناسبة لمختلف الانشطة الرياضية.</span></span></li>\r\n			<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">توليف الفيتامينات والمعادن لمختلف الانشطة الرياضية.</span></span></li>\r\n			<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">كيفية التعامل مع العملاء وبناء الثقة بينهم.</span></span></li>\r\n			<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">التسويق لخصوصية واهمية مهنة استشاري التغذية الرياضية.</span></span></li>\r\n		</ol>\r\n		</li>\r\n	</ol>\r\n	</li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:20px\"><strong><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">اعتماد الشهادة</span></span></strong><strong><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"> :</span></span></strong></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">The Swedish Academy of Sport Training (SAST)</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Global Council of Sport Science (GCSS)</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">International Accreditation of Sport Education (IASE)</span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:20px\"><strong><span style=\"font-family:&quot;Times New Roman&quot;,serif\">المشمولون بالتسجيل:</span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">كل من حصل على شهادة اخصائي التغذية الرياضية المستوى الثالث.</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">اذا لم تكن حاصل على المستويات الثلاثة الاولى، يمكنكم الالتحاق مباشرة في الاكاديمية السويدية للتدريب الرياضي ودراستها </span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Online</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">يحصل المتخرج على كارت الهوية لاستشاري التغذية الرياضية</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:20px\"><strong><span style=\"font-family:&quot;Times New Roman&quot;,serif\">رسوم الاشتراك في الدورة:</span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">للمستوى الرابع فقط 1100 دولار</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">للمستويات الاربعة بحزمة واحدة 1500 دولار</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">طرق التسجيل:</span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">يكون التسجيل مباشرة من موقعنا </span></span><a href=\"http://www.swedish-academy.se\"><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">www.swedish-academy.se</span></span></a></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">او من خلال الاتصال بنا عن طريق البريد الالكتروني&nbsp; للمجلس </span></span><a href=\"mailto:admin@gcss.se\"><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">admin@gcss.se</span></span></a></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">او الاتصال على الهاتف النقال: 0046736327465 </span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">او الاتصال بمدراء مكاتبنا وممثلينا المنتشرين في الوطن العربي .</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n', NULL, NULL, NULL, 'ar'),
(37, 17, 'دورة اخصائي التغذية الرياضية المستوى الرابع في الكويت', 'fK9B', NULL, NULL, NULL, NULL, NULL, 'en'),
(38, 18, 'دورة التغذية الرياضية المستوى الاول في الدمام ', 'NhVE', NULL, '<p dir=\"RTL\">يقيم المجلس العالمي للعلوم الرياضية في السويد GCSS وبالتعاون مع الاكاديمية السويدية للتدريب الرياضي SAST عن اقامة دورة التغذية الرياضية للمستوى الاول .</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\"><strong>اين ومتى؟</strong>&nbsp;</p>\r\n\r\n<p dir=\"RTL\">&nbsp;في الدمام في المملكة العربية السعودية للفترة 27-29 يوليو 2017</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\"><strong>يقدمها الخبير الدولي ومدرب المحترفين الكابتن عبد الحميد دشتي</strong></p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\"><strong>محاور الدورة:</strong></p>\r\n\r\n<ol>\r\n	<li>\r\n	<ol>\r\n		<li>\r\n		<ol>\r\n			<li dir=\"RTL\">ماهي الخليه ومكوناتها ؟</li>\r\n			<li dir=\"RTL\">علم الغدد الصماء والهرمونات الداخليه للجسم.</li>\r\n			<li dir=\"RTL\">تشريح الجهاز الهضمي ووظيفته.</li>\r\n			<li dir=\"RTL\">المغذيات الكبرى والصغرى.</li>\r\n			<li dir=\"RTL\">المكملات الغذائي وفوائدها.</li>\r\n			<li dir=\"RTL\">أهمية الماء والسوائل للرياضي.</li>\r\n			<li dir=\"RTL\">ماهي حمية باليو ، وحمية دينز .</li>\r\n			<li dir=\"RTL\">مرض السكري وعلاقته بالتغذية.</li>\r\n		</ol>\r\n		</li>\r\n	</ol>\r\n	</li>\r\n</ol>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\"><strong>اعتماد الشهادة</strong><strong> :</strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\">The Swedish Academy of Sport Training (SAST)</li>\r\n	<li dir=\"RTL\">Global Council of Sport Science (GCSS)</li>\r\n	<li dir=\"RTL\">International Accreditation of Sport Education (IASE)</li>\r\n</ol>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\"><strong>رسوم الاشتراك في الدورة:</strong></p>\r\n\r\n<p dir=\"RTL\">2500 ريال سعودي</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\"><strong>طرق التسجيل:</strong></p>\r\n\r\n<p dir=\"RTL\">الاتصال بممثلنا في المملكة العربية السعودية الكابتن عادل المبيض 00966569616556</p>\r\n\r\n<p dir=\"RTL\">او من خلال الايميل <a href=\"mailto:adelalmubayedh@gcss.se\">adelalmubayedh@gcss.se</a></p>\r\n', NULL, NULL, NULL, 'ar'),
(39, 18, 'دورة التغذية الرياضية المستوى الاول في الدمام ', 'glXM', NULL, NULL, NULL, NULL, NULL, 'en'),
(40, 19, 'دورة المدرب الشخصي للمستوى الثالث في السعودية ', 'hjKi', NULL, '<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">نضع بين ايديكم دورة المدرب الشخصي للمستوى الثالث</span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">. </span></span></span><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">والمعتمد من قبل </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">&quot;Europactive&quot;. </span></span></span><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">والتي تقدمه الاكاديمية السويدية للتدريب الرياضي </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">The Swedish Academy of Sport Training (SAST)</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">وبالتعاون مع المجلس العالمي للعلوم الرياضية في السويد </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">Global Council of Sport Science (GCSS)</span></span></span><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">.</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">وحسب معيار منظمة الاعتماد الدولية للتعليم الرياضي </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">International Accreditation of Sport Education</span></span></span><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">. </span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">قد حاولنا ان نشمل كل ما يحتاجه المتخصص في ميدان التدريب الشخصي واللياقة البدنية، كي</span></span></span> <span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">يكون الشخص الذي ينهي هذه الدورة مدرباً مهنياً محترفاً الذي يكسب ثقة عملاءه</span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">.</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">من يقدمها : </span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"color:gray\">المحاضر المعتمد كابتن مشاري الحجيلي </span></span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">اين ومتى : </span></span></span></u></strong></p>\r\n\r\n<div style=\"float:right\">\r\n<table cellspacing=\"0\" class=\"Table\" dir=\"rtl\" style=\"border-collapse:collapse; border:undefined; margin-left:8.6pt\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\">مكان البرنامج</span></strong></p>\r\n			</td>\r\n			<td style=\"width:121.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\">تاريخه</span></strong></p>\r\n			</td>\r\n			<td style=\"width:117.0pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\">الفئة المستهدفة</span></strong></p>\r\n			</td>\r\n			<td style=\"width:98.25pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\">المدة</span></strong></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#0070c0; width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">الرياض</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#0070c0; width:121.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">4102017</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#0070c0; width:117.0pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">رجال</span></span></strong></p>\r\n			</td>\r\n			<td rowspan=\"3\" style=\"width:98.25pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\">4 ايام</span></strong></p>\r\n\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\">4 - 9 مساء</span></strong></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#bf8f00; width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">الرياض</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#bf8f00; width:121.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">11102017</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#bf8f00; width:117.0pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">نساء</span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#0070c0; width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">جدة</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#0070c0; width:121.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">18102017</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#0070c0; width:117.0pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">رجال ونساء</span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n</div>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">مسمى الشهادة شهادة</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">مدرب اللياقة البدنية المستوى الثالث، مدرب اختصاصي للياقة البدنية.</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:left\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">Personal Trainer Certificate - Level 3, as a Specialist Fitness Trainer</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">مدة الدراسة</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">تشمل الدراسة 144 ساعة دراسية </span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">المؤهلون للتسجيل</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">كل من حصل على شهادة المدرب الشخصي المستوى الثاني.</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">ماذا يمكن ان نتعلم</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">سيتعلم الطالب بعد انهاء هذه الدورة كل مما ياتي:</span></span></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">مفاهيم تدريبات مركز الجسم (الجذع) </span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">مفاهيم تدريبات التوازن </span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">مفاهيم تمارين البلايومتريك وسرعة الاستجابة</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">تدريب السرعة والرشاقة وسرعة البديهة</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">مفهوم التدريب على التحمل</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">تصميم البرامج التدريبية المتكاملة ونموذج التدريب للأداء الأمثل </span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">مدخل إلى طرق ممارسة التمارين </span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">اعتماد الشهادة :</span></span></span></u></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"color:gray\">The Swedish Academy of Sport Training (SAST)</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"color:gray\">Global Council of Sport Science (GCSS)</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"color:gray\">International Accreditation of Sport Education (IASE)</span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">الاختبار النهائي للدورة</span></span></span></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">يجب على الطالب اجتيار اختبار نهاية الدورة وبنسبة نجاح 60%</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">يشمل الامتحان النهائي 20 سؤالا بطريقة اختيار الجواب الصحيح من خلال اربعة اجوبة مقترحة </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">Multichoice</span></span></span> <span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">وقت اداء الاختبار 40 دقيقة من وقت البدأ بالاختبار.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">يمكن لكل طالب اداء الامتحان مرتين كاقصى حد من اجل النجاح.</span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">يمكن للذين لم ينجحوا بالمحاولتين ان يطلبوا امتحان اضافي لقاء مبلغ اضافي قدره 50 دولار امريكي لكل محاولة اضافية</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"color:#00b0f0\">رسوم الاشتراك في الدورة:</span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">2800 ريال سعودي</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:18.0pt\"><span style=\"color:#00b0f0\">طرق التسجيل:</span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">الاتصال بممثلنا في المملكة العربية السعودية الكابتن مشاري الحجيلي</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">0508356640-0557011130</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">او من خلال الايميل </span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"color:#002060\">Malhijily@gmail.com </span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n', NULL, NULL, NULL, 'ar'),
(41, 19, 'دورة المدرب الشخصي للمستوى الثالث في السعودية ', 'JSwX', NULL, NULL, NULL, NULL, NULL, 'en'),
(42, 20, 'اعلان المدرب الشخصي المستوى الثاني في السعودية', 'BYvJ', NULL, '<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">التوصيف :</span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#787878\">هي الخطوة الثانية لمواصلة المشوار في عالم اللياقة البدنية والتدريب الشخصي</span></span></span></span><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">.</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#787878\">الرنامج التدريبي المقدم هنا معتمد من قبل</span></span></span></span><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\"><span style=\"color:#787878\"> &quot;Europactive&quot;. </span></span></span></span><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#787878\">وتقدمها الاكاديمية السويدية للتدريب الرياضي </span></span></span></span><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\"><span style=\"color:#787878\">The Swedish Academy of Sport Training (SAST)</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#787878\">وبالتعاون مع المجلس العالمي للعلوم الرياضية في السويد </span></span></span></span><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\"><span style=\"color:#787878\">Global Council of Sport Science (GCSS).</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">تشمل هذه الدورة الجانبين العملي والنظري. حيث يتطلب في الجانب العملي التطبيقي من كل طالب اداء بعض التمارين التطبيقية العملية .</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">وحسب المتطلبات المشار لها في المنهج الخاص للدورة. اما الجانب النظري فيشمل مادة علمية نظرية، يجب على كل طالب تجاوز اختباراتها النظرية.</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">من يقدمها : </span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">المحاضر المعتمد كابتن مشاري الحجيلي </span></span></span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">اين ومتى : </span></span></span></span></u></strong></p>\r\n\r\n<div style=\"float:right\">\r\n<table cellspacing=\"0\" class=\"Table\" dir=\"rtl\" style=\"border-collapse:collapse; border:undefined; margin-left:8.6pt\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">مكان البرنامج</span></span></strong></p>\r\n			</td>\r\n			<td style=\"width:121.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">تاريخه</span></span></strong></p>\r\n			</td>\r\n			<td style=\"width:117.0pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">الفئة المستهدفة</span></span></strong></p>\r\n			</td>\r\n			<td style=\"width:98.25pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">المدة</span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#0070c0; width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:white\">الرياض</span></span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#0070c0; width:121.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:white\">6  8  2017</span></span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#0070c0; width:117.0pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:white\">رجال</span></span></span></strong></p>\r\n			</td>\r\n			<td rowspan=\"3\" style=\"width:98.25pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">4 ايام</span></span></strong></p>\r\n\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">4 - 9 مساء</span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#f99107; width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:white\">الرياض</span></span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#f99107; width:121.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:white\">27  9  2017</span></span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#f99107; width:117.0pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:white\">نساء</span></span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#0070c0; width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:white\">جدة</span></span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#0070c0; width:121.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:white\">20  8  2017</span></span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#0070c0; width:117.0pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:white\">رجال ونساء</span></span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n</div>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">مسمى الشهادة شهادة</span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">المدرب الشخصي المستوى الثاني، مدرب اللياقة البدنية.</span></span></span></span></p>\r\n\r\n<p><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\"><span style=\"color:#787878\">Personal Trainer Certificate - Level 2, as a Fitness</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">مدة الدراسة</span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">تشمل الدراسة 112 ساعة دراسية </span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">المؤهلون للتسجيل</span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">كل من حصل على شهادة المدرب الشخصي المستوى الاول.</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">ماذا يمكن ان نتعلم</span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">سيتعلم الطالب بعد انهاء هذه الدورة كل مما ياتي:</span></span></span></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">مفاهيم تدريب المرونة.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">تدريبات اللياقة القلبية التنفسية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">تمارين الاستقرار الاساسي.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">التمارين الوظيفية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">التمارين الحركية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">تمارين المرونة</span></span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">اعتماد الشهادة :</span></span></span></span></u></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">The Swedish Academy of Sport Training (SAST)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">Global Council of Sport Science (GCSS)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">International Accreditation of Sport Education (IASE)</span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">الاختبار النهائي للدورة</span></span></span></span></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#787878\">يجب على الطالب اجتيار اختبار نهاية الدورة وبنسبة نجاح 60%</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#787878\">يشمل الامتحان النهائي 20 سؤالا بطريقة اختيار الجواب الصحيح من خلال اربعة اجوبة مقترحة </span></span></span></span><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">Multichoice</span></span></span></span> <span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#787878\">.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#787878\">وقت اداء الاختبار 40 دقيقة من وقت البدأ بالاختبار.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#787878\">يمكن لكل طالب اداء الامتحان مرتين كاقصى حد من اجل النجاح.</span></span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">يمكن للذين لم ينجحوا بالمحاولتين ان يطلبوا امتحان اضافي لقاء مبلغ اضافي قدره 50 دولار امريكي لكل محاولة اضافية</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">رسوم الاشتراك في الدورة:</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">2600</span></span></span><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"> <span style=\"color:gray\">ريال سعودي</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:18.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">طرق التسجيل:</span></span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">الاتصال بممثلنا في المملكة العربية السعودية الكابتن مشاري الحجيلي 0508356640-0557011130</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">او من خلال الايميل </span></span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#002060\">Malhijily@gmail.com </span></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n', NULL, NULL, NULL, 'ar'),
(43, 20, 'اعلان المدرب الشخصي المستوى الثاني في السعودية', 'AO88', NULL, NULL, NULL, NULL, NULL, 'en');
INSERT INTO `news_translations` (`id`, `news_id`, `title`, `slug`, `short_description`, `content`, `meta_title`, `meta_keyword`, `meta_description`, `lang`) VALUES
(44, 21, 'اعلان المدرب الشخصي المستوى الاول في السعودية', 'Kt8U', NULL, '<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">التوصيف :</span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:gray\">نحن ومن خلال برنامج المدرب الشخصي المستوى الاول متحمسون ومهتمون لأن نضع بين يديك ما يساعدك على بناء وتطوير مهاراتك فـي مجال التدريب الشخصي واللياقة البدنية .</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:gray\">إذا كنت تريد أن تتعلم أفضل الممارسات في &ldquo;التدريب الشخصي&rdquo; والــحصول عـلـى مـؤهـلات جـوهـريـة ومـوضـوعـيـة تسـتـنـد عـلـى مـنـهـجـيـة عـلـمـية وعلى أساس متين من الخبرة العمليّة </span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:gray\">ما عليك الا الاستمرار معنا من خلال هذه الدورة التي تعد الخطوة الى مستقبل الاحتراف المهني. حيث سنتعلم في هذه الدورة على اساسيات مهنة المدرب الشخصي</span></span></span></span><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:gray\">.</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">من يقدمها : </span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">المحاضر المعتمد كابتن مشاري الحجيلي </span></span></span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">اين ومتى : </span></span></span></span></u></strong></p>\r\n\r\n<div style=\"float:right\">\r\n<table cellspacing=\"0\" class=\"Table\" dir=\"rtl\" style=\"border-collapse:collapse; border:undefined; margin-left:4.85pt\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">مكان البرنامج</span></span></span></span></strong></p>\r\n			</td>\r\n			<td style=\"width:98.75pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">تاريخه</span></span></span></span></strong></p>\r\n			</td>\r\n			<td style=\"width:111.7pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">الفئة المستهدفة</span></span></span></span></strong></p>\r\n			</td>\r\n			<td style=\"width:100.3pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">المدة</span></span></span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#ffc000; width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">الرياض</span></span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#ffc000; width:98.75pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">3  8  2017</span></span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#ffc000; width:111.7pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">نساء</span></span></span></strong></p>\r\n			</td>\r\n			<td rowspan=\"4\" style=\"width:100.3pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\">&nbsp;</p>\r\n\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">3 ايام</span></span></span></span></strong></p>\r\n\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">4 &ndash; 9 مساء</span></span></span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#5b9bd5; width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">الرياض</span></span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#5b9bd5; width:98.75pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">10  8  2017</span></span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#5b9bd5; width:111.7pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">رجال</span></span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#ffc000; width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">جدة </span></span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#ffc000; width:98.75pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">17  8  2017</span></span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#ffc000; width:111.7pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">نساء ورجال</span></span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#5b9bd5; width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">المدينة</span></span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#5b9bd5; width:98.75pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">24 8  2017</span></span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#5b9bd5; width:111.7pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">نساء ورجال</span></span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n</div>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">مسمى الشهادة شهادة</span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">المدرب الشخصي المستوى الاول، مساعد مدرب اللياقة البدنية.</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:left\"><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\"><span style=\"color:#787878\">Personal Trainer Certificate - Level 1, as an Assistant Fitness Trainer</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">مدة الدراسة</span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">تشمل الدراسة 96 ساعة دراسية </span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">المؤهلون للتسجيل</span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">كل من له الرغبة والطموح في دخول ميدان التدريب الشخصي واللياقة البدنية (الخبرات السابقة غير مطلوبة).</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">ماذا يمكن ان نتعلم</span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">سيتعلم الطالب بعد انهاء هذه الدورة كل مما ياتي:</span></span></span></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">التشريح الرياضي.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">مكونات الخلية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">الهورمونات والانزيمات.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">علم الامراض.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">فسيولوجيا التمارين التطبيقية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">تقييم اللياقة البدنية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">التغذية الرياضية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">اساسيات في المكملات الغذائية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">فسيولوجيا التمارين التطبيقية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">تقييم اللياقة البدنية</span></span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">اعتماد الشهادة :</span></span></span></span></u></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">The Swedish Academy of Sport Training (SAST)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">Global Council of Sport Science (GCSS)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">International Accreditation of Sport Education (IASE)</span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">الاختبار النهائي للدورة</span></span></span></span></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#787878\">يجب على الطالب اجتيار اختبار نهاية الدورة وبنسبة نجاح 60%</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#787878\">يشمل الامتحان النهائي 20 سؤالا بطريقة اختيار الجواب الصحيح من خلال اربعة اجوبة مقترحة </span></span></span></span><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">Multichoice</span></span></span></span> <span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#787878\">.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#787878\">وقت اداء الاختبار 40 دقيقة من وقت البدأ بالاختبار.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#787878\">يمكن لكل طالب اداء الامتحان مرتين كاقصى حد من اجل النجاح.</span></span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">يمكن للذين لم ينجحوا بالمحاولتين ان يطلبوا امتحان اضافي لقاء مبلغ اضافي قدره 50 دولار امريكي لكل محاولة اضافية</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">رسوم الاشتراك في الدورة:</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">2000 </span></span></span><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"> <span style=\"color:gray\">ريال سعودي</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:18.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">طرق التسجيل:</span></span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">الاتصال بممثلنا في المملكة العربية السعودية الكابتن مشاري الحجيلي 0508356640-0557011130</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">او من خلال الايميل </span></span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#002060\">Malhijily@gmail.com </span></span></span></p>\r\n', NULL, NULL, NULL, 'ar'),
(45, 21, 'اعلان المدرب الشخصي المستوى الاول في السعودية', 'ICii', NULL, NULL, NULL, NULL, NULL, 'en'),
(46, 22, 'دورة اللياقة البدنية وبناء الاجسام للسيدات في الكويت', 'F9nq', NULL, '<p dir=\"RTL\" style=\"text-align:right\">يعلن المجلس العالمي للعلوم الرياضية GCSS وبالتعاون مع الاكاديمية السويدية للتدريب الرياضي SAST وبرعاية اكاديمية مايلوجي الرياضية عن اقامة دورة اللياقة البدنية وبناء الاجسام للسيدات.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#5b9bd5\">متى؟</span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">27-29 سبتمبر 2017</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#5b9bd5\">اين</span></span></strong><strong> </strong><strong><span style=\"font-size:14.0pt\"><span style=\"color:#5b9bd5\">؟</span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">الكويت &ndash; صباح السالم &ndash; نادي ديفا</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#5b9bd5\">من يقدمها</span></span></strong><strong> </strong><strong><span style=\"font-size:14.0pt\"><span style=\"color:#5b9bd5\">؟</span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;بطلة الفيغر سارة حسين</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#5b9bd5\">محاور الدورة</span></span></strong><strong> </strong><strong><span dir=\"LTR\" style=\"font-size:14.0pt\"><span style=\"color:#5b9bd5\">&nbsp;: </span></span></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\">تصميم البرامج التدريبية</li>\r\n	<li dir=\"RTL\" style=\"text-align:right\">تجنب الاصابات من خلال الاداء المهاري الصحيح</li>\r\n	<li dir=\"RTL\" style=\"text-align:right\">الاهتمام بالصحة العامة للحامل</li>\r\n	<li dir=\"RTL\" style=\"text-align:right\">دور المدرب داخل وخارج صالة التدريب</li>\r\n	<li dir=\"RTL\" style=\"text-align:right\">التغلب على الصعوبات للوصول الى الاهداف التدريبية</li>\r\n	<li dir=\"RTL\" style=\"text-align:right\">المكملات الغذائية وانواعها</li>\r\n	<li dir=\"RTL\" style=\"text-align:right\">تاثير الهرمونات على الفتيات</li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#5b9bd5\">اجور الاشتراك:</span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;200 دينار كويتي</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#5b9bd5\">التسجيل والاستفسار</span></span></strong></p>\r\n\r\n<p style=\"text-align:right\"><span dir=\"RTL\" lang=\"AR-IQ\">00</span>965 55360347</p>\r\n\r\n<p style=\"text-align:right\"><span dir=\"RTL\" lang=\"AR-IQ\">00</span>965 97557763</p>\r\n\r\n<p style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#5b9bd5\">اعتماد الشهادة :</span></span></span></u></strong></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span dir=\"LTR\" style=\"font-size:12.0pt\">The Swedish Academy of Sport Training (SAST)</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span dir=\"LTR\" style=\"font-size:12.0pt\">Global Council of Sport Science (GCSS)</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span dir=\"LTR\" style=\"font-size:12.0pt\">International Accreditation of Sport Education (IASE)</span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p style=\"text-align:right\">&nbsp;</p>\r\n', NULL, NULL, NULL, 'ar'),
(47, 22, 'دورة اللياقة البدنية وبناء الاجسام للسيدات في الكويت', 'u5YD', NULL, NULL, NULL, NULL, NULL, 'en'),
(48, 23, 'انهاء خدمات', 'nXXI', NULL, '<p dir=\"RTL\" style=\"text-align:right\">قررت ادارة المجلس العالمي للعلوم الرياضية في السويد على انهاء خدمات ممثل المجلس في المملكة العربية السعودية الكابتن عادل وليد المبيض لبعض الخلافات الادارية. وعليه فهو غير مخول باستخدام اسم المجلس او ما يتعلق بها في التفاوض او التعامل مع اي جهة اخرى فردية كانت او حكومية .</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">بدوره يتقدم المجلس بالشكر والامتنان لما قدمه المبيض في الفترة الماضية من اعمال خلال فترة تمثيله للمجلس في السعودية .. متمنين له التوفيق في خطواته القادمة.</p>\r\n', NULL, NULL, NULL, 'ar'),
(49, 23, 'انهاء خدمات', 'kxfU', NULL, NULL, NULL, NULL, NULL, 'en'),
(50, 24, 'تفويض لادارة مكتبنا في المملكة العربية السعودية', 'Gi7j', NULL, '<p dir=\"RTL\" style=\"text-align:right\">قررت ادارة المجلس العالمي للعلوم الرياضية في السويد تكليف الاستاذ مشاري الحجيلي بمنصب مدير مكتب المجلس في المملكة العربية السعودية ، كما تم تكليف الاستاذ فيصل العليو مساعدا للمدير. اضافة الى واجباتهما كمحاضرين معتمدين.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">سيمنحان من خلال هذا التفويض حق العمل بأسم المجلس وكل المؤسسات المتعلقة به ومتابعة اعماله الادارية والمالية والعلمية والتفاوض بالنيابة عنه وتوقيع العقود والبروتوكلات وادارة تنظيم الدورات التدريبية وجميع اعمال المجلس المناطة بهما ضمن هذا التفويض.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">اتى هذا القرار لما قدماه للمجلس من اعمال واجتهاد ومثابرة في الفترة الاخيرة ومساهمتهما الفعلية في رفع اداء المجلس والاكاديمية السويدية داخل المملكة العربية السعودية.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">نحن كأدرة ومدربين ووكلاء للمجلس نتمنى لهم التوفيق والتقدم باعمالهم القادمة .</p>\r\n', NULL, NULL, NULL, 'ar'),
(51, 24, 'تفويض لادارة مكتبنا في المملكة العربية السعودية', '7wVK', NULL, NULL, NULL, NULL, NULL, 'en'),
(52, 25, 'دورة المدرب الشخصي المستوى الاول', 'JeRT', NULL, '<p dir=\"RTL\" style=\"text-align:center\"><span style=\"font-size:12.0pt\">يعلن المجلس العالمي للعلوم الرياضية في السويد </span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\">GCSS</span> <span style=\"font-size:12.0pt\">و الاكاديمية السويدية للتدريب الرياضي </span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\">SAST</span> <span style=\"font-size:12.0pt\">وبالتعاون مع المركز التأهيل الدولي في مصر عن اقامة دورة المدرب الشخصي المستوى الاول</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:12.0pt\">اين ومتى؟</span></strong><span style=\"font-size:12.0pt\"> مصر &ndash; القاهرة، للفترة 14-18 اكتوبر 2017</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:12.0pt\">يقدمها :</span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\">د.أمين محمد، مدرس في كلية التربية الرياضية بالهرم </span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\">د.أيمن غنيم، مدرس في كلية التربية الرياضية بني سويف</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:12.0pt\">محاور الدورة:</span></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\">التشريح الرياضي ومكونات الخلية</span><span dir=\"LTR\" style=\"font-size:12.0pt\">.</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\">الهورمونات والانزيمات وعلم الامراض</span><span dir=\"LTR\" style=\"font-size:12.0pt\">.</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\">فسيولوجيا التمارين التطبيقية</span>&nbsp;</li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\">تقييم اللياقة البدنية</span><span dir=\"LTR\" style=\"font-size:12.0pt\">.</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\">التغذية الرياضية</span><span dir=\"LTR\" style=\"font-size:12.0pt\">.</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\">اساسيات في المكملات الغذائية</span><span dir=\"LTR\" style=\"font-size:12.0pt\">.</span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:12.0pt\"><span style=\"background-color:white\">اعتماد الشهادة</span></span></strong><strong><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"> :</span></span></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\">The Swedish Academy of Sport Training (SAST)</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\">Global Council of Sport Science (GCSS)</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\">International Accreditation of Sport Education (IASE)</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\">International Rehabilitation center (IRC)</span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:12.0pt\">رسوم الاشتراك في الدورة:</span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\">280 دولار</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:12.0pt\">طرق التسجيل:</span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\">الاتصال بهواتف المركز الدولي للتأهيل ومتاحة ايضا واتس اب&nbsp; </span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\">002-01098066670</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\">002-01098099950</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:12.0pt\">ملاحظة: يمكن توفير السكن لمن هو خارج مصر باجور اضافية مناسبة</span></strong></p>\r\n', NULL, NULL, NULL, 'ar'),
(53, 25, 'دورة المدرب الشخصي المستوى الاول', 'Cadl', NULL, NULL, NULL, NULL, NULL, 'en'),
(54, 26, 'افتتاح مكتبنا في مصر', 'rgdk', NULL, '<p dir=\"RTL\" style=\"text-align:right\">ضمن خطط المجلس العالمي للعلوم الرياضية في السويد GCSS والاكاديمية السويدية للتدريب SAST في التوسع في العالم العربي والشرق الاوسط، تم عقد بروتكول تعاون مع مركز التأهيل الدولي في مصر للتعاون طويل المدى ، وعلى اثره تم تعين الدكتور محمد حسين مديرا لمكتبنا في مصر لادارة الدورات وعقد الندوات وتفويضه بعقد التفاهمات والمفاوضات مع جميع المؤسسات الرياضية حكومية كانت ام اهلية.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">يذكر ان مركز التأهيل الدولي في مصر هو من اهم المراكز التدريبية الرياضية في العاصمة المصرية القاهرة ولهم افرع متعددة في مختلف محافظات مصر.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">وتتويجا لباكورة هذا التعاون تم الاعلان عن الدورة التدريبية للمدرب الشخصي المستوى الاول في مصر للفترة من 14 لغاية 18 اكتوبر 2017. وهي الدورة الاولى من نوعها التي تهتم باعداد المدرب الشخصي ومدربي اللياقة البدنية داخل الصالات وباعتمادات اوربية وعالمية باعلى المستويات.</p>\r\n', NULL, NULL, NULL, 'ar'),
(55, 26, 'افتتاح مكتبنا في مصر', 'Bi5x', NULL, NULL, NULL, NULL, NULL, 'en'),
(56, 27, 'دورة المدرب الشخصي المستوى الاول في الدمام ', 'b8wL', NULL, '<p dir=\"RTL\" style=\"text-align:center\"><span style=\"font-size:13.0pt\">يعلن المجلس العالمي للعلوم الرياضية في السويد </span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:13.0pt\">GCSS</span> <span style=\"font-size:13.0pt\">و الاكاديمية السويدية للتدريب الرياضي </span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:13.0pt\">SAST</span> <span style=\"font-size:13.0pt\">عن اقامة دورة المدرب الشخصي المستوى الاول</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:15.0pt\">للرجال والنساء</span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:15.0pt\">اين ومتى؟</span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">في الدمام 5-7 اكتوبر 2017</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:15.0pt\">من يقدمها؟</span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">البطل العالمي واخصائي التغذية الكابتن فيصل العليو</span><span style=\"font-size:13.0pt\">،</span><span style=\"font-size:13.0pt\"> المعتمد من </span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:13.0pt\">GCSS</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:15.0pt\">محاور الدورة:</span></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">التشريح الرياضي ومكونات الخلية</span><span dir=\"LTR\" style=\"font-size:13.0pt\">.</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">الهورمونات والانزيمات وعلم الامراض</span><span dir=\"LTR\" style=\"font-size:13.0pt\">.</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">فسيولوجيا التمارين التطبيقية</span>&nbsp;</li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">تقييم اللياقة البدنية</span><span dir=\"LTR\" style=\"font-size:13.0pt\">.</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">التغذية الرياضية</span><span dir=\"LTR\" style=\"font-size:13.0pt\">.</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">اساسيات في المكملات الغذائية</span><span dir=\"LTR\" style=\"font-size:13.0pt\">.</span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:15.0pt\"><span style=\"background-color:white\">اعتماد الشهادة</span></span></strong><strong><span style=\"font-size:15.0pt\"><span style=\"background-color:white\"> :</span></span></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:13.0pt\">The Swedish Academy of Sport Training (SAST)</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:13.0pt\">Global Council of Sport Science (GCSS)</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:13.0pt\">International Accreditation of Sport Education (IASE)</span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:15.0pt\">رسوم الاشتراك:</span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">2000 ريال سعودي</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:15.0pt\">التسجيل والاستفسار</span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:13.0pt\">0536677718</span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n', NULL, NULL, NULL, 'ar'),
(57, 27, 'دورة المدرب الشخصي المستوى الاول في الدمام ', 'PsDZ', NULL, NULL, NULL, NULL, NULL, 'en'),
(58, 28, 'المدرب الشخصي المستوى الثاني في الدمام', 'PLC2', NULL, '<p dir=\"RTL\" style=\"text-align:center\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">يعلن المجلس العالمي للعلوم الرياضية في السويد </span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">GCSS</span></span> <span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">و الاكاديمية السويدية للتدريب الرياضي </span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">SAST</span></span> <span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">عن اقامة دورة المدرب الشخصي المستوى الثاني</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\">للرجال والنساء</span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\">اين ومتى؟</span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\">في الدمام 26-28 اكتوبر 2017</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\">من يقدمها؟</span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\">البطل العالمي واخصائي التغذية الكابتن فيصل العليو</span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\">،</span></span><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"> المعتمد من </span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:13.0pt\">GCSS</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">محاور الدورة:</span></span></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">تدريب المرونة.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">تدريبات اللياقة القلبية التنفسية.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">تمارين الاستقرار الاساسي.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">التمارين الوظيفية.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">التمارين الحركية.</span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:16.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">اعتماد الشهادة</span></span></span></strong><strong><span style=\"font-size:16.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"> :</span></span></span></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">The Swedish Academy of Sport Training (SAST)</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Global Council of Sport Science (GCSS)</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">International Accreditation of Sport Education (IASE)</span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">رسوم الاشتراك:</span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">2300 ريال سعودي</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\">التسجيل والاستفسار</span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\">0536677718</span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n', NULL, NULL, NULL, 'ar'),
(59, 28, 'المدرب الشخصي المستوى الثاني في الدمام', 'QIHQ', NULL, NULL, NULL, NULL, NULL, 'en');
INSERT INTO `news_translations` (`id`, `news_id`, `title`, `slug`, `short_description`, `content`, `meta_title`, `meta_keyword`, `meta_description`, `lang`) VALUES
(60, 29, 'دورة اعداد وتطوير مدربي اللياقة البدنية', 'jUSf', NULL, '<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">يعلن المجلس العالمي للعلوم الرياضية في السويد </span></span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">GCSS</span></span></span> <span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">و الاكاديمية السويدية للتدريب الرياضي </span></span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">SAST</span></span></span><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\"> عن اقامة دورة </span></span></span><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">دورة اعداد وتطوير مدربي اللياقة البدنية</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">من يقدمها :</span></span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:gray\">خبير اللياقة السويدي : زولتان غريمسبيرغر </span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">&nbsp;اين ومتى :</span></span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:gray\">في تونس 1-6 نوفمبر 2017</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">ماذا يمكن ان نتعلم</span></span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">سيتعلم الطالب بعد انهاء هذه الدورة كل مما ياتي:</span></span></span></span></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">مفهوم التدريب الرياضي و اللياقة البدنية</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">فيسيولوجيا الرياضة (التكيف , تأقلم القلب , تطور الاداء)</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">تأثير البيئة على الأداء وتقنيات التمارين </span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">التدريب الرياضي التخصصي (مختلف الرياضات )</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">النشاط البدني للصحة واللياقة البدنية </span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">التغذية الرياضية والمكملات </span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">تصميم البرامج التدريبية وتخطيط الاحمال </span></span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">اعتماد الشهادة :</span></span></span></u></strong></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">The Swedish Academy of Sport Training (SAST)</span></span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">Global Council of Sport Science (GCSS)</span></span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">International Accreditation of Sport Education (IASE)</span></span></span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">رسوم الاشتراك في الدورة:</span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">1000 دولار </span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">ماأ تشمل الاجور: </span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">السكن في منتجع بحري 5 نجوم في غرف مزدوجة شاملة ثلاث وجبات غذائية بوفيه مفتوح مع الوجبات البينية </span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">, اضافة الى النقل من والى المطار .</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><span style=\"font-size:18.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">للاستفسار والتسجيل :</span></span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">مكتب تونس : الاستاذ شاكر عنيد </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">,</span></span></span><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\"> 0021629861926</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; الانسة خولة توري , 0021622421393</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">مكتب السويد : 0046767045506</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">الايميل : </span></span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">admin@gcss.se</span></span></span></p>\r\n', NULL, NULL, NULL, 'ar'),
(61, 29, 'دورة اعداد وتطوير مدربي اللياقة البدنية', 'QISI', NULL, NULL, NULL, NULL, NULL, 'en'),
(62, 30, 'دورة مدربي اللياقة البدنية وتخطيط الاحمال', 'cAoi', NULL, '<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#00b0f0\">دورة مدربي اللياقة البدنية وتخطيط الاحمال</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\">يعلن المجلس العالمي للعلوم الرياضية في السويد</span> GCSS <span style=\"font-family:&quot;Arial&quot;,sans-serif\">والاكاديمية السويدية للتدريب الرياضي</span> SAST <span style=\"font-family:&quot;Arial&quot;,sans-serif\">عن اقامة دورة مدربي اللياقة البدنية&nbsp; وتخطيط الاحمال</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#00b0f0\">اين ومتى؟ </span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\">الكويت ، للفترة 17-15 ديسمبر 2017</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#00b0f0\">من يقدمها</span></span></span><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:14.0pt\"><span style=\"color:#00b0f0\"> :</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><em><span style=\"font-family:&quot;Arial&quot;,sans-serif\">استاذ علم التدريب الدكتور ايمن غنيم</span></em></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#00b0f0\">اعتماد الشهادة</span></span></span><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:14.0pt\"><span style=\"color:#00b0f0\"> :</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">1.&nbsp; The Swedish Academy of Sport Training (SAST)</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">2.&nbsp; Global Council of Sport Science (GCSS)</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">3.&nbsp; International Accreditation of Sport Education (IASE)</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#00b0f0\">رسوم الاشتراك في الدورة</span></span></span><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:14.0pt\"><span style=\"color:#00b0f0\">:</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;&nbsp; 200 <span style=\"font-family:&quot;Arial&quot;,sans-serif\">دينار كويتي</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#00b0f0\">طرق التسجيل</span></span></span><span dir=\"LTR\" lang=\"EN-US\" style=\"font-size:14.0pt\"><span style=\"color:#00b0f0\">:</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\">الاتصال بالدكتور محمد البقشي&nbsp; 0096597557763</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\">او الاتصال بمشرف التسجيل الكابتن علي البلوشي&nbsp; 0096555597959</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\">او الاتصال المباشر بجميع افرع شركة هيلث هاوس (شرق، كيفان، صباح السالم، الرقعي)</span>.</p>\r\n', NULL, NULL, NULL, 'ar'),
(63, 30, 'دورة مدربي اللياقة البدنية وتخطيط الاحمال', '4icr', NULL, NULL, NULL, NULL, NULL, 'en'),
(64, 31, 'الحصول على عضوية ICSSPE', 't7M7', NULL, '<p><span style=\"font-size:16px\">بعد سلسلة من التطورات العلمية في اعداد الدورات وتنظيمها والتقدم الملحوظ في عدد الطلبة المنخرطين في الدراسة لدينا سواءا في المجلس او الاكاديمية السويدية .. وبعد متابعة فريق العمل الدؤوب للمجلس العالمي للعلوم الرياضية ، تم الحصول على عضوية المجلس الدولي لعلوم الرياضة واللياقة البدنية ومقره في المانيا . حيث يعد ICSSPE &nbsp;من اهم المنظمات الاوربية والعالمية المتخصصة بالرياضة وينظوي تحت لواءه الكثير من المنظمات والمؤسسات التعليمية الرياضية.&nbsp;<br />\r\nنحن كادرة واعضاء في الاكاديمية السويدية والمجلس العالمي فخورون بهذه العضوية والاعتماد الجديد الذي يحفزنا على مواصلة مشوار التقدم والعطاء وفي مختلف التخصصات الرياضية حيث يجعلنا في مصاف اهم المؤسسات التدريبية الرياضية. ونوعد جمهورنا الشغوف بنجاحاتنا اننا سائرون الى الامام لتحقيق جميع طموحاتهم وتعزيز سمة التميز والسبق في جميع النواحي العلمية والتدريبية.</span></p>\r\n', NULL, NULL, NULL, 'ar'),
(65, 31, 'الحصول على عضوية ICSSPE', 'niEu', NULL, NULL, NULL, NULL, NULL, 'en'),
(66, 32, 'دورة المدرب الشخصي المستوى الثاني في السعودية ', 'LTPH', NULL, '<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">هي الخطوة الثانية لمواصلة المشوار في عالم اللياقة البدنية والتدريب الشخصي.</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">الرنامج التدريبي المقدم هنا معتمد من قبل</span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\"> &quot;Europactive&quot;. </span></span></span><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">وتقدمها الاكاديمية السويدية للتدريب الرياضي </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">The Swedish Academy of Sport Training (SAST)</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">وبالتعاون مع المجلس العالمي للعلوم الرياضية في السويد </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">Global Council of Sport Science (GCSS).</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">تشمل هذه الدورة الجانبين العملي والنظري. حيث يتطلب في الجانب العملي التطبيقي من كل طالب اداء بعض التمارين التطبيقية العملية .</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">وحسب المتطلبات المشار لها في المنهج الخاص للدورة. اما الجانب النظري فيشمل مادة علمية نظرية، يجب على كل طالب تجاوز اختباراتها النظرية.</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">من يقدمها : </span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"color:gray\">المحاضر المعتمد كابتن مشاري الحجيلي </span></span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">اين ومتى : </span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<div style=\"float:right\">\r\n<table cellspacing=\"0\" class=\"Table\" dir=\"rtl\" style=\"border-collapse:collapse; border:undefined; margin-left:8.6pt\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\">مكان البرنامج</span></strong></p>\r\n			</td>\r\n			<td style=\"width:103.05pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\">تاريخه</span></strong></p>\r\n			</td>\r\n			<td style=\"width:103.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\">الفئة المستهدفة</span></strong></p>\r\n			</td>\r\n			<td style=\"width:139.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"color:black\">المدة: كل دورة تكون 3 ايام</span></span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#0070c0; width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">الرياض</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#0070c0; width:103.05pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">21 - 12 -2017</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#0070c0; width:103.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">نساء</span></span></strong></p>\r\n			</td>\r\n			<td rowspan=\"3\" style=\"width:139.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:black\">خميس 4:30 م &ndash; 9:30 م</span></span></strong></p>\r\n\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"color:black\">جمعة 3 م &ndash; 8:00 م</span></span></span></strong></p>\r\n\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"color:black\">السبت 11:00 ص &ndash; 6:00م</span></span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#f99107; width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">جدة</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#f99107; width:103.05pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">28 - 12 -2017</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#f99107; width:103.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">رجال ونساء</span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#0070c0; width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">الرياض</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#0070c0; width:103.05pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">08 - 02 -2018</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#0070c0; width:103.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">رجال</span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n</div>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">مسمى الشهادة شهادة</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">المدرب الشخصي المستوى الثاني، مدرب اللياقة البدنية.</span></span></span></p>\r\n\r\n<p><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">Personal Trainer Certificate - Level 2, as a Fitness</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">مدة الدراسة</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">تشمل الدراسة 112 ساعة دراسية </span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">المؤهلون للتسجيل</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">كل من حصل على شهادة المدرب الشخصي المستوى الاول.</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">ماذا يمكن ان نتعلم</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">سيتعلم الطالب بعد انهاء هذه الدورة كل مما ياتي:</span></span></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">مفاهيم تدريب المرونة.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">تدريبات اللياقة القلبية التنفسية.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">تمارين الاستقرار الاساسي.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">التمارين الوظيفية.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">التمارين الحركية.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">تمارين المرونة</span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">اعتماد الشهادة :</span></span></span></u></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"color:gray\">The Swedish Academy of Sport Training (SAST)</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"color:gray\">Global Council of Sport Science (GCSS)</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"color:gray\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"color:gray\">International Accreditation of Sport Education (IASE)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"color:gray\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\">The European Register of Exercise Professionals (EREPS)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:10.5pt\"><span style=\"color:gray\">. International Council of Sport Science and Physical Education (ICSSPE)</span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">الاختبار النهائي للدورة</span></span></span></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">يجب على الطالب اجتياز اختبار نهاية الدورة وبنسبة نجاح 60%</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">يشمل الامتحان النهائي 20 سؤالا بطريقة اختيار الجواب الصحيح من خلال اربعة اجوبة مقترحة </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">Multichoice</span></span></span><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\"> .</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">وقت اداء الاختبار 40 دقيقة من وقت البدأ بالاختبار.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">يمكن لكل طالب اداء الامتحان مرتين كاقصى حد من اجل النجاح.</span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">يمكن للذين لم ينجحوا بالمحاولتين ان يطلبوا امتحان اضافي لقاء مبلغ اضافي قدره 50 دولار امريكي لكل محاولة اضافية</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"color:#00b0f0\">رسوم الاشتراك في الدورة:</span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"color:gray\">2600</span></span><span style=\"font-size:12.0pt\"> <span style=\"color:gray\">ريال سعودي</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:18.0pt\"><span style=\"color:#00b0f0\">طرق التسجيل:</span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">الاتصال بممثلنا في المملكة العربية السعودية الكابتن مشاري الحجيلي 0508356640-0557011130</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">او من خلال الايميل </span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"color:#002060\">Malhijily@gmail.com</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n', NULL, NULL, NULL, 'ar'),
(67, 32, 'دورة المدرب الشخصي المستوى الثاني في السعودية ', 'SQjS', NULL, NULL, NULL, NULL, NULL, 'en'),
(68, 33, 'دورة المدرب الشخصي المستوى الثالث في السعودية ', 'rpjM', NULL, '<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">نضع بين ايديكم دورة المدرب الشخصي للمستوى الثالث</span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">. </span></span></span><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">والمعتمد من قبل </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">&quot;Europactive&quot;. </span></span></span><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">والتي تقدمه الاكاديمية السويدية للتدريب الرياضي </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">The Swedish Academy of Sport Training (SAST)</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">وبالتعاون مع المجلس العالمي للعلوم الرياضية في السويد </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">Global Council of Sport Science (GCSS)</span></span></span><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">.</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">وحسب معيار منظمة الاعتماد الدولية للتعليم الرياضي </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">International Accreditation of Sport Education</span></span></span><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">. </span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">قد حاولنا ان نشمل كل ما يحتاجه المتخصص في ميدان التدريب الشخصي واللياقة البدنية، كي</span></span></span><span style=\"font-size:12.0pt\"> <span style=\"background-color:white\"><span style=\"color:#787878\">يكون الشخص الذي ينهي هذه الدورة مدرباً مهنياً محترفاً الذي يكسب ثقة عملاءه</span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">.</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">من يقدمها : </span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"color:gray\">المحاضر المعتمد كابتن مشاري الحجيلي </span></span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">اين ومتى : </span></span></span></u></strong></p>\r\n\r\n<div>\r\n<table cellspacing=\"0\" class=\"Table\" dir=\"rtl\" style=\"border-collapse:collapse; border:undefined\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\">مكان البرنامج</span></strong></p>\r\n			</td>\r\n			<td style=\"width:121.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\">تاريخه</span></strong></p>\r\n			</td>\r\n			<td style=\"width:85.05pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\">الفئة المستهدفة</span></strong></p>\r\n			</td>\r\n			<td style=\"width:130.2pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"color:black\">المدة: كل دورة تكون 3 ايام</span></span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#0070c0; width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">الرياض</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#0070c0; width:121.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">4 - 1 -2018</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#0070c0; width:85.05pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">نساء</span></span></strong></p>\r\n			</td>\r\n			<td rowspan=\"3\" style=\"width:130.2pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:black\">خميس 4:30 م &ndash; 9:30 م</span></span></strong></p>\r\n\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"color:black\">جمعة 3 م &ndash; 8:00 م</span></span></span></strong></p>\r\n\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"color:black\">السبت 11:00 ص &ndash; 6:00م</span></span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#bf8f00; width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">جدة</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#bf8f00; width:121.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">11 - 1 - 2018</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#bf8f00; width:85.05pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">رجال ونساء</span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#0070c0; width:91.9pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">الرياض</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#0070c0; width:121.5pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">22 - 2 - 2018</span></span></strong></p>\r\n			</td>\r\n			<td style=\"background-color:#0070c0; width:85.05pt\">\r\n			<p dir=\"RTL\" style=\"text-align:center\"><strong><span style=\"font-size:16.0pt\"><span style=\"color:white\">رجال</span></span></strong></p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n</div>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">مسمى الشهادة شهادة</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">مدرب اللياقة البدنية المستوى الثالث، مدرب اختصاصي للياقة البدنية.</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:left\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">Personal Trainer Certificate - Level 3, as a Specialist Fitness Trainer</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">مدة الدراسة</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">تشمل الدراسة 144 ساعة دراسية </span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">المؤهلون للتسجيل</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">كل من حصل على شهادة المدرب الشخصي المستوى الثاني.</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">ماذا يمكن ان نتعلم</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">سيتعلم الطالب بعد انهاء هذه الدورة كل مما ياتي:</span></span></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">مفاهيم تدريبات مركز الجسم (الجذع) </span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">مفاهيم تدريبات التوازن </span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">مفاهيم تمارين البلايومتريك وسرعة الاستجابة</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">تدريب السرعة والرشاقة وسرعة البديهة</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">مفهوم التدريب على التحمل</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">تصميم البرامج التدريبية المتكاملة ونموذج التدريب للأداء الأمثل </span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">مدخل إلى طرق ممارسة التمارين </span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#3498db\">اعتماد الشهادة </span></span></span></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\">Global Council of Sport Science (GCSS)</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\">The Swedish Academy of Sports Training (SAST)</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\">EuropeActive</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\">International Accreditation of Sport Education (IASE)</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#2b2b2b\">The European Register of Exercise Professionals (EREPS)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\">International Council of Sport Science and Physical Education (ICSSPE)</span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">الاختبار النهائي للدورة</span></span></span></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">يجب على الطالب اجتيار اختبار نهاية الدورة وبنسبة نجاح 60%</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">يشمل الامتحان النهائي 20 سؤالا بطريقة اختيار الجواب الصحيح من خلال اربعة اجوبة مقترحة </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">Multichoice</span></span></span><span style=\"font-size:12.0pt\"> <span style=\"background-color:white\"><span style=\"color:#787878\">.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">وقت اداء الاختبار 40 دقيقة من وقت البدأ بالاختبار.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">يمكن لكل طالب اداء الامتحان مرتين كاقصى حد من اجل النجاح.</span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#787878\">يمكن للذين لم ينجحوا بالمحاولتين ان يطلبوا امتحان اضافي لقاء مبلغ اضافي قدره 50 دولار امريكي لكل محاولة اضافية</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"color:#00b0f0\">رسوم الاشتراك في الدورة:</span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">2800 ريال سعودي</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:18.0pt\"><span style=\"color:#00b0f0\">طرق التسجيل:</span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">الاتصال بممثلنا في المملكة العربية السعودية الكابتن مشاري الحجيلي</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">0508356640-0557011130</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">او من خلال الايميل </span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"color:#002060\">Malhijily@gmail.com </span></span></p>\r\n', NULL, NULL, NULL, 'ar'),
(69, 33, 'دورة المدرب الشخصي المستوى الثالث في السعودية ', 'lno8', NULL, NULL, NULL, NULL, NULL, 'en');
INSERT INTO `news_translations` (`id`, `news_id`, `title`, `slug`, `short_description`, `content`, `meta_title`, `meta_keyword`, `meta_description`, `lang`) VALUES
(70, 34, 'دورة المدرب الشخصي المستوى الاول في الدمام', '75eS', NULL, '<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">يعلن المجلس العالمي للعلوم الرياضية في السويد </span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"color:gray\">GCSS</span></span> <span style=\"font-size:12.0pt\"><span style=\"color:gray\">و الاكاديمية السويدية للتدريب الرياضي </span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"color:gray\">SAST</span></span><span style=\"font-size:12.0pt\"><span style=\"color:gray\"> عن اقامة دورة المدرب الشخصي المستوى الاول</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">من يقدمها :</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">البطل العالمي واخصائي التغذية الكابتن فيصل العليو، المعتمد من </span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"color:gray\">GCSS</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">اين ومتى :</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">في الدمام 4-5-6 يناير 2018</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"color:#00b0f0\"><span style=\"font-size:24px\"><strong><u>محاور الدورة :</u></strong></span></span></p>\r\n\r\n<ol>\r\n	<li dir=\"rtl\" style=\"text-align:right\"><span style=\"color:gray; font-size:12pt\">التشريح الرياضي ومكونات الخلية</span><span dir=\"LTR\" style=\"font-size:12pt\"><span style=\"color:gray\">.</span></span></li>\r\n	<li dir=\"rtl\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">الهورمونات والانزيمات وعلم الامراض</span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"color:gray\">.</span></span></li>\r\n	<li dir=\"rtl\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">فسيولوجيا التمارين التطبيقية</span></span></li>\r\n	<li dir=\"rtl\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">تقييم اللياقة البدنية</span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"color:gray\">.</span></span></li>\r\n	<li dir=\"rtl\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">التغذية الرياضية</span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"color:gray\">.</span></span></li>\r\n	<li dir=\"rtl\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">اساسيات في المكملات الغذائية</span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"color:gray\">.</span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">اعتماد الشهادة :</span></span></span></u></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"color:gray\">&nbsp;<span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\">Global Council of Sport Science (GCSS)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"color:gray\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\">The Swedish Academy of Sports Training (SAST)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"color:gray\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\">EuropeActive</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"color:gray\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\">International Accreditation of Sport Education (IASE)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"color:gray\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\">The European Register of Exercise Professionals (EREPS)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"color:gray\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\">International Council of Sport Science and Physical Education (ICSSPE)</span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">رسوم الاشتراك في الدورة:</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:gray\">2000 ريال سعودي</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">طرق التسجيل:</span></span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">الاتصال بممثلنا في المملكة العربية السعودية الكابتن فيصل </span></span><strong><span dir=\"LTR\" style=\"font-size:11.5pt\"><span style=\"background-color:white\"><span style=\"color:gray\">0544424202</span></span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n', NULL, NULL, NULL, 'ar'),
(71, 34, 'دورة المدرب الشخصي المستوى الاول في الدمام', 'HEwA', NULL, NULL, NULL, NULL, NULL, 'en'),
(72, 35, 'دورة المدرب الشخصي المستوى الثاني في الدمام', 'UYvH', NULL, '<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">يعلن المجلس العالمي للعلوم الرياضية في السويد </span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"color:gray\">GCSS</span></span> <span style=\"font-size:12.0pt\"><span style=\"color:gray\">و الاكاديمية السويدية للتدريب الرياضي </span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"color:gray\">SAST</span></span><span style=\"font-size:12.0pt\"><span style=\"color:gray\"> عن اقامة دورة المدرب الشخصي المستوى الثاني</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">من يقدمها :</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">البطل العالمي واخصائي التغذية الكابتن فيصل العليو، المعتمد من </span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"color:gray\">GCSS</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">اين ومتى :</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:#767171\">في الدمام 25-26-27 يناير 2018</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"color:#00b0f0\"><strong><u>محاور الدورة :</u></strong></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#767171\">تدريب المرونة.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#767171\">تدريبات اللياقة القلبية التنفسية.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#767171\">تمارين الاستقرار الاساسي.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#767171\">التمارين الوظيفية.</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:#767171\">التمارين الحركية.</span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">اعتماد الشهادة :</span></span></span></u></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"color:gray\">&nbsp;<span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\">Global Council of Sport Science (GCSS)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"color:gray\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\">The Swedish Academy of Sports Training (SAST)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"color:gray\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\">EuropeActive</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"color:gray\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\">International Accreditation of Sport Education (IASE)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"color:gray\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\">The European Register of Exercise Professionals (EREPS)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"color:gray\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\">International Council of Sport Science and Physical Education (ICSSPE)</span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">رسوم الاشتراك في الدورة:</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"color:gray\">2300 ريال سعودي</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"color:#00b0f0\">طرق التسجيل:</span></span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"color:gray\">الاتصال بممثلنا في المملكة العربية السعودية الكابتن فيصل </span></span><strong><span dir=\"LTR\" style=\"font-size:11.5pt\"><span style=\"background-color:white\"><span style=\"color:gray\">0544424202</span></span></span></strong></p>\r\n\r\n<p>&nbsp;</p>\r\n', NULL, NULL, NULL, 'ar'),
(73, 35, 'دورة المدرب الشخصي المستوى الثاني في الدمام', 'cGJh', NULL, NULL, NULL, NULL, NULL, 'en'),
(74, 36, ' دورة المدرب الشخصي المستوى الرابع في السعودية ', 'qqzu', NULL, '<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:24px\"><strong>يعلن المجلس العالمي للعلوم الرياضية في السويد والاكاديمية السويدية للتدريب الرياضي وبالتعاون مع&nbsp;<span dir=\"LTR\"> EuropeActive </span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:24px\"><strong>عن اقامة دورة <span style=\"color:#3498db\">المدرب الشخصي المستوى الرابع</span>، للحصول على اجازة المدرب الشخصي الاوربية الدولية<span dir=\"LTR\"> .</span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"color:#3498db\"><strong><span style=\"font-size:18.0pt\">مكان وتاريخ الدورة:</span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:18.0pt\">المكان والزمان</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:13.0pt\">- 30-01-2018 </span><span style=\"font-size:13.0pt\">الرياض (للنساء)</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:13.0pt\">- 06-02-2018 </span><span style=\"font-size:13.0pt\">الرياض (للرجال)</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:13.0pt\">- 27-02-2018 </span><span style=\"font-size:13.0pt\">جــــــده (للنساء)</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"color:#3498db\"><strong><span style=\"font-size:18.0pt\">محاور الدورة</span></strong><strong><span dir=\"LTR\" style=\"font-size:18.0pt\">:</span></strong></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">كتابة البرامج التدريبية</span><span dir=\"LTR\" style=\"font-size:13.0pt\">.</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">المرونة والاداء الحركي</span><span dir=\"LTR\" style=\"font-size:13.0pt\">.</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">تمارين التحمل</span><span dir=\"LTR\" style=\"font-size:13.0pt\">.</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">طرق واساليب الاختبارات</span><span dir=\"LTR\" style=\"font-size:13.0pt\">.</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">فن الاتصال مع المتدربين والعملاء</span><span dir=\"LTR\" style=\"font-size:13.0pt\">.</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">الاختبارات العملية النهائية</span><span dir=\"LTR\" style=\"font-size:13.0pt\">.</span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"color:#3498db\"><strong><span style=\"font-size:18.0pt\">اعتماد الشهادة</span></strong><strong><span dir=\"LTR\" style=\"font-size:18.0pt\">:</span></strong></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:13.0pt\">Global Council of Sport Science (GCSS)</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:13.0pt\">The Swedish Academy of Sports Training (SAST)</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:13.0pt\">EuropeActive</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:13.0pt\">International Accreditation of Sport Education (IASE)</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:13.0pt\">The European Register of Exercise Professionals (EREPS)</span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:13.0pt\">International Council of Sport Science and Physical Education (ICSSPE)</span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:13.0pt\">يحصل المتخرج على كارت المدرب الشخصي&nbsp;</span></strong><strong><span dir=\"LTR\" style=\"font-size:13.0pt\"> (Licensed ID for Personal Trainer)</span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong>&nbsp;</strong><strong><span style=\"font-size:13.0pt\">يحصل المتخرج على رخصه مدرب شخصي معتمد من منظمه&nbsp;</span></strong><strong><span dir=\"LTR\" style=\"font-size:13.0pt\"> ereps</span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"color:#3498db\"><strong><span style=\"font-size:18.0pt\">المشمولين بالتسجيل</span></strong><strong><span dir=\"LTR\" style=\"font-size:18.0pt\">:</span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">كل الذي حصل على شهادة المدرب الشخصي المستوى الثالث</span><span dir=\"LTR\" style=\"font-size:13.0pt\">.</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"color:#3498db\"><strong><span style=\"font-size:18.0pt\">طرق التسجيل</span></strong><strong><span dir=\"LTR\" style=\"font-size:18.0pt\">:</span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">الاتصال بممثلنا في المملكة العربية السعودية الكابتن مشاري الحجيلي</span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:13.0pt\">0508356640-0557011130</span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:13.0pt\">او من خلال الايميل</span> <strong><span dir=\"LTR\" style=\"font-size:13.0pt\">Malhijily@gmail.com</span></strong></p>\r\n', NULL, NULL, NULL, 'ar'),
(75, 36, ' دورة المدرب الشخصي المستوى الرابع في السعودية ', 'YPd1', NULL, NULL, NULL, NULL, NULL, 'en'),
(76, 37, 'دورة اعداد وتطوير مدربي اللياقة البدنية', 'iapQ', NULL, '<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">يعلن المجلس العالمي للعلوم الرياضية في السويد </span></span><span dir=\"LTR\" style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">GCSS</span></span><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"> و الاكاديمية السويدية للتدريب الرياضي </span></span><span dir=\"LTR\" style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">SAST</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">عن اقامة دورة دورة اعداد وتطوير مدربي اللياقة البدنية</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"color:#3498db\"><strong><u><span style=\"font-size:17.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">من يقدمها :</span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">خبير اللياقة السويدي : زولتان غريمسبيرغر</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"color:#3498db\"><strong><u><span style=\"font-size:17.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">اين ومتى :</span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">في تونس 20-24 فبراير 2018</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"color:#3498db\"><strong><u><span style=\"font-size:17.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">ماذا يمكن ان نتعلم</span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">سيتعلم الطالب بعد انهاء هذه الدورة كل مما ياتي:</span></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">مفهوم التدريب الرياضي و اللياقة البدنية</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">فيسيولوجيا الرياضة (التكيف , تأقلم القلب , تطور الاداء)</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">تأثير البيئة على الأداء وتقنيات التمارين</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">التدريب الرياضي التخصصي (مختلف الرياضات )</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">النشاط البدني للصحة واللياقة البدنية</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">التغذية الرياضية والمكملات</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">تصميم البرامج التدريبية وتخطيط الاحمال</span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"color:#3498db\"><strong><u><span style=\"font-size:17.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">اعتماد الشهادة :</span></span></u></strong></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">The Swedish Academy of Sport Training (SAST)</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Global Council of Sport Science (GCSS)</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">International Accreditation of Sport Education (IASE)</span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">International Council of Sport Science and Physical Education (ICSSPE)</span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"color:#3498db\"><strong><u><span style=\"font-size:17.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">رسوم الاشتراك في الدورة:</span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">1000 دولار</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"color:#3498db\"><strong><u><span style=\"font-size:17.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">ماأ تشمل الاجور: </span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">السكن في منتجع بحري 5 نجوم في غرف مزدوجة شاملة ثلاث وجبات غذائية بوفيه مفتوح مع الوجبات البينية</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">, اضافة الى النقل من والى المطار .</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"color:#3498db\"><strong><span style=\"font-size:17.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">للاستفسار والتسجيل :</span></span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">مكتب تونس : الاستاذ شاكر عنيد , 0021629861926</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">الاستاذ مصعب الصويعي, 0021655889604</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">مكتب السويد : 0046767045506</span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">الايميل : </span></span><span dir=\"LTR\" style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">admin@gcss.se</span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n', NULL, NULL, NULL, 'ar'),
(77, 37, 'دورة اعداد وتطوير مدربي اللياقة البدنية', 'kNve', NULL, NULL, NULL, NULL, NULL, 'en'),
(78, 38, ' مواعيد دورات المدرب فيصل العليو في المملكة العربية السعودية', 'Z7AF', NULL, '<p><span style=\"font-size:18px\">يعلن المجلس العالمي للعلوم الرياضية في السويد&nbsp;<span style=\"color:#f1c40f\"><strong>GCSS</strong></span></span></p>\r\n\r\n<p><span style=\"font-size:18px\">والاكاديميـــــــة السويديــــة للتدريــــــب الرياضــــي&nbsp;<span style=\"color:#3498db\"><strong>SAST</strong>&nbsp;</span>عن</span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:20px\"><span style=\"color:#f1c40f\"><strong><strong>مواعيد دورات الكابتن فيصل العليو</strong></strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"color:#16a085\"><span style=\"font-size:18px\"><strong><strong>في المملكة العربية السعودية / الاحساء</strong></strong></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<ol>\r\n	<li><span style=\"font-size:18px\">دورة مفاهيم علمية&nbsp;<strong>2018/02/22</strong></span></li>\r\n	<li><span style=\"font-size:18px\">&nbsp;دورة مدرب شخصي المستوى الأول&nbsp;<strong>2018/03/22</strong></span></li>\r\n	<li><span style=\"font-size:18px\">دورة مدرب شخصي المستوى الأول&nbsp;<strong>2018/04/19</strong></span></li>\r\n	<li><span style=\"font-size:18px\">دورة مدرب شخصي المستوى الثاني&nbsp;<strong>2018/05/18</strong></span></li>\r\n</ol>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:18px\"><strong>اعتماد الشهادة:</strong></span></p>\r\n\r\n<p style=\"direction:rtl\"><span style=\"font-size:18px\"><strong>(</strong>Global Council of Sport Science&nbsp;<strong>(GCSS</strong></span></p>\r\n\r\n<p style=\"direction:rtl\"><span style=\"font-size:18px\"><strong>(</strong>The Swedish Academy of Sports Training&nbsp;<strong>(SAST</strong></span></p>\r\n\r\n<p style=\"direction:rtl\"><span style=\"font-size:18px\"><strong>(</strong>The European Register of Exercise Professionals&nbsp;<strong>(EREPS</strong></span></p>\r\n\r\n<p style=\"direction:rtl\"><span style=\"font-size:18px\"><strong>(</strong>International Accreditation of Sport Education&nbsp;<strong>(IASE</strong></span></p>\r\n\r\n<p style=\"direction:rtl\"><span style=\"font-size:18px\">EuropeActive</span></p>\r\n', NULL, NULL, NULL, 'ar'),
(79, 38, ' مواعيد دورات المدرب فيصل العليو في المملكة العربية السعودية', 'LltC', NULL, NULL, NULL, NULL, NULL, 'en'),
(80, 39, 'دورة المدرب الشخصي المستوى الأول في السعودية ', '57AZ', NULL, '<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><span style=\"font-size:13.5pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">توصيف</span></span></span></strong><strong><span dir=\"LTR\" style=\"font-size:13.5pt\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\"><span style=\"color:#787878\"> :</span></span></span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">نحن ومن خلال برنامج المدرب الشخصي المستوى الاول متحمسون ومهتمون لأن نضع بين يديك ما يساعدك على بناء وتطوير مهاراتك فـي مجال التدريب الشخصي واللياقة البدنية .</span></span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">إذا كنت تريد أن تتعلم أفضل الممارسات في &ldquo;التدريب الشخصي&rdquo; والــحصول عـلـى مـؤهـلات جـوهـريـة ومـوضـوعـيـة تسـتـنـد عـلـى مـنـهـجـيـة عـلـمـية وعلى أساس متين من الخبرة العمليّة</span></span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">ما عليك الا الاستمرار معنا من خلال هذه الدورة التي تعد الخطوة الى مستقبل الاحتراف المهني. حيث سنتعلم في هذه الدورة على اساسيات مهنة المدرب الشخصي</span></span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">.</span></span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">من يقدمها :</span></span></span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">المحاضر المعتمد كابتن مشاري الحجيلي (مدير مكتب </span></span></span></span></strong><strong><span dir=\"LTR\" style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">GCSS </span></span></span></span></strong><strong><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">&nbsp;في السعودية)</span></span></span></span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">اين ومتى :</span></span></span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">- 22-02-2018 الرياض (للنساء)</span></span></span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">- 12-03-2018 الرياض (للرجال)</span></span></span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">- 15-03-2018 جدة (للرجال والنساء)</span></span></span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">- 29-03-2018المدينة (للرجال والنساء)</span></span></span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">مسمى الشهادة شهادة</span></span></span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">المدرب الشخصي المستوى الاول، مساعد مدرب اللياقة البدنية.</span></span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:left\"><span style=\"background-color:white\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">Personal Trainer Certificate - Level 1, as an Assistant Fitness Trainer</span></span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">مدة الدراسة</span></span></span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">تشمل الدراسة 96 ساعة دراسية</span></span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">المؤهلون للتسجيل</span></span></span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">كل من له الرغبة والطموح في دخول ميدان التدريب الشخصي واللياقة البدنية (الخبرات السابقة غير مطلوبة).</span></span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">ماذا يمكن ان نتعلم</span></span></span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">سيتعلم الطالب بعد انهاء هذه الدورة كل مما ياتي:</span></span></span></span></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">اساسيات في التشريح العضلي .</span></span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">الغذيات الكبرى وأهميتها للجسم.</span></span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">أساسيات في المكملات الغذائية.</span></span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">أنظمة الطاقة في الجسم وكيفية عملها.</span></span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">تقييم اللياقة البدنية.</span></span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">مبادئ تمارين القوة والتحمل.</span></span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">التعامل مع بعض الأمراض الشائعة.</span></span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">الاستشفاء بعد التدريبات الرياضية.</span></span></span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">اعتماد الشهادة :</span></span></span></span></u></strong></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\">EuropeActive</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">The Swedish Academy of Sport Training (SAST)</span></span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">Global Council of Sport Science (GCSS)</span></span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">International Accreditation of Sport Education (IASE)</span></span></span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">الاختبار النهائي للدورة</span></span></span></span></strong></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">يجب على الطالب اجتيار اختبار نهاية الدورة وبنسبة نجاح 60%</span></span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">يشمل الامتحان النهائي 20 سؤالا بطريقة اختيار الجواب الصحيح من خلال اربعة اجوبة مقترحة </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Multichoice</span></span></span><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"> .</span></span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">وقت اداء الاختبار 40 دقيقة من وقت البدأ بالاختبار.</span></span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">يمكن لكل طالب اداء الامتحان مرتين كاقصى حد من اجل النجاح.</span></span></span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">يمكن للذين لم ينجحوا بالمحاولتين ان يطلبوا امتحان اضافي لقاء مبلغ اضافي قدره 50 دولار امريكي لكل محاولة اضافية</span></span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">رسوم الاشتراك في الدورة:</span></span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">2000 ريال سعودي</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><span style=\"font-size:18.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">طرق التسجيل:</span></span></span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">الاتصال بممثلنا في المملكة العربية السعودية الكابتن مشاري الحجيلي 0508356640-0557011130</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">او من خلال الايميل </span></span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#002060\">Malhijily@gmail.com</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n', NULL, NULL, NULL, 'ar'),
(81, 39, 'دورة المدرب الشخصي المستوى الأول في السعودية ', '7duP', NULL, NULL, NULL, NULL, NULL, 'en');
INSERT INTO `news_translations` (`id`, `news_id`, `title`, `slug`, `short_description`, `content`, `meta_title`, `meta_keyword`, `meta_description`, `lang`) VALUES
(82, 40, 'دورة المدرب الشخصي المستوى الثاني في السعودية ', 'bAUT', NULL, '<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">هي الخطوة الثانية لمواصلة المشوار في عالم اللياقة البدنية والتدريب الشخصي.</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">الرنامج التدريبي المقدم هنا معتمد من قبل</span></span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\"> &quot;Europactive&quot;. </span></span></span></span><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">وتقدمها الاكاديمية السويدية للتدريب الرياضي </span></span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">The Swedish Academy of Sport Training (SAST)</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">وبالتعاون مع المجلس العالمي للعلوم الرياضية في السويد </span></span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">Global Council of Sport Science (GCSS).</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">تشمل هذه الدورة الجانبين العملي والنظري. حيث يتطلب في الجانب العملي التطبيقي من كل طالب اداء بعض التمارين التطبيقية العملية .</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">وحسب المتطلبات المشار لها في المنهج الخاص للدورة. اما الجانب النظري فيشمل مادة علمية نظرية، يجب على كل طالب تجاوز اختباراتها النظرية.</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">من يقدمها : </span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">المحاضر المعتمد كابتن </span></span></span></span></strong><strong><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#767171\">مشاري </span></span></span></span></strong><strong><span style=\"font-size:14.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">الحجيلي </span></span></span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">اين ومتى : </span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#767171\">- 08-03-2018 الرياض (للنساء)</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#767171\">- 19-03-2018 الرياض (للرجال)</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#767171\">- 05-04-2018 جدة (للرجال والنساء)</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#767171\">- 12-04-2018 المدينة (للرجال والنساء)</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">مسمى الشهادة شهادة</span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">المدرب الشخصي المستوى الثاني، مدرب اللياقة البدنية.</span></span></span></span></p>\r\n\r\n<p><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">Personal Trainer Certificate - Level 2, as a Fitness</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">مدة الدراسة</span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">تشمل الدراسة 112 ساعة دراسية </span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">المؤهلون للتسجيل</span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">كل من حصل على شهادة المدرب الشخصي المستوى الاول.</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">ماذا يمكن ان نتعلم</span></span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">سيتعلم الطالب بعد انهاء هذه الدورة كل مما ياتي:</span></span></span></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">مفاهيم تدريب المرونة.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">تدريبات اللياقة القلبية التنفسية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">تمارين الاستقرار الاساسي.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">التمارين الوظيفية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">التمارين الحركية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">تمارين المرونة</span></span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">اعتماد الشهادة :</span></span></span></span></u></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">The Swedish Academy of Sport Training (SAST)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">Global Council of Sport Science (GCSS)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">International Accreditation of Sport Education (IASE)</span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">The European Register of Exercise Professionals (EREPS)</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:10.5pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">. International Council of Sport Science and Physical Education (ICSSPE)</span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">الاختبار النهائي للدورة</span></span></span></span></strong></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">يجب على الطالب اجتياز اختبار نهاية الدورة وبنسبة نجاح 60%</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">يشمل الامتحان النهائي 20 سؤالا بطريقة اختيار الجواب الصحيح من خلال اربعة اجوبة مقترحة </span></span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">Multichoice</span></span></span></span><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\"> .</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">وقت اداء الاختبار 40 دقيقة من وقت البدأ بالاختبار.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">يمكن لكل طالب اداء الامتحان مرتين كاقصى حد من اجل النجاح.</span></span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#787878\">يمكن للذين لم ينجحوا بالمحاولتين ان يطلبوا امتحان اضافي لقاء مبلغ اضافي قدره 50 دولار امريكي لكل محاولة اضافية</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">رسوم الاشتراك في الدورة:</span></span></span></u></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">2600</span></span></span><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"> <span style=\"color:gray\">ريال سعودي</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><strong><span style=\"font-size:18.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">طرق التسجيل:</span></span></span></strong></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">الاتصال بممثلنا في المملكة العربية السعودية الكابتن مشاري الحجيلي 0508356640-0557011130</span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">او من خلال الايميل </span></span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#002060\">Malhijily@gmail.com</span></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n', NULL, NULL, NULL, 'ar'),
(83, 40, 'دورة المدرب الشخصي المستوى الثاني في السعودية ', 'PbIF', NULL, NULL, NULL, NULL, NULL, 'en'),
(84, 41, 'تنبيه واشعار لكل طلبة الاكاديمية السويدية للتدريب الرياضي', 'VPNn', NULL, '<p dir=\"RTL\" style=\"margin-left:0in; margin-right:0in; text-align:right\"><br />\r\n<span style=\"background-color:white\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Helvetica&quot;,sans-serif\"><span style=\"color:#4472c4\">تنبيه واشعار لكل طلبة الاكاديمية السويدية للتدريب الرياضي</span></span></span></strong><strong> </strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"margin-left:0in; margin-right:0in; text-align:right\"><br />\r\n<span style=\"background-color:white\"><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Helvetica&quot;,sans-serif\"><span style=\"color:#1d2129\">بدأ من تاريخ 3 ابريل وحتى تاريخ 5 ابريل سيتوقف موقع الاكاديمية للتدريب الرياضي عن تقديم خدماته للطلبة وذلك بسبب التحديث وتطوير الموقع وعليه لن يكون الموقع متاح خلال هذه الفترة على ان يعاود العمل والتشغيل يوم 6 ابريل باذن الله</span></span></span><span dir=\"LTR\" style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Helvetica&quot;,sans-serif\"><span style=\"color:#1d2129\"> .</span></span></span><br />\r\n<span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Helvetica&quot;,sans-serif\"><span style=\"color:#1d2129\">نعتذر لهذا التوقف بسبب تحسين وتطوير مميزات الموقع بما يخدم الطلبة, نشكر تفهمكم وتعاونكم</span></span></span><span dir=\"LTR\" style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Helvetica&quot;,sans-serif\"><span style=\"color:#1d2129\">.</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"margin-left:0in; margin-right:0in; text-align:right\"><br />\r\n<span style=\"background-color:white\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Helvetica&quot;,sans-serif\"><span style=\"color:#4472c4\">لاي استفسار برجاء التواصل مع فريق الدعم الفني من خلال</span></span></span></strong><strong> </strong><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Helvetica&quot;,sans-serif\"><span style=\"color:#4472c4\">:</span></span></span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"margin-left:0in; margin-right:0in; text-align:right\"><br />\r\n<span style=\"background-color:white\"><strong><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Helvetica&quot;,sans-serif\">واتس <span style=\"color:#1d2129\">/ </span><span style=\"color:#36102e\">فايبر</span><span style=\"color:#1d2129\"> / اتصال</span></span></span></strong><strong> </strong><br />\r\n<span dir=\"LTR\" style=\"font-size:14.0pt\"><span style=\"font-family:&quot;inherit&quot;,serif\"><span style=\"color:#1d2129\">0046767045506</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"margin-left:0in; margin-right:0in; text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"margin-left:0in; margin-right:0in; text-align:right\"><span style=\"background-color:white\"><strong><span style=\"font-size:14.0pt\"><span style=\"font-family:&quot;Helvetica&quot;,sans-serif\">او عبر ايميلاتنا</span></span></strong><br />\r\n<span dir=\"LTR\" style=\"font-size:14.0pt\"><span style=\"font-family:&quot;inherit&quot;,serif\"><span style=\"color:#1d2129\">info@swedish-academy.se</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"margin-left:0in; margin-right:0in; text-align:right\"><span style=\"background-color:white\"><span dir=\"LTR\" style=\"font-size:14.0pt\"><span style=\"font-family:&quot;inherit&quot;,serif\"><span style=\"color:#1d2129\">admin@gcss.se</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">&nbsp;</p>\r\n', NULL, NULL, NULL, 'ar'),
(85, 41, 'تنبيه واشعار لكل طلبة الاكاديمية السويدية للتدريب الرياضي', 'L6Jk', NULL, NULL, NULL, NULL, NULL, 'en'),
(86, 42, 'دورة مفاهيم علمية لقوام رياضي صحي / الدمام / ابريل 2018', 'uKT8', NULL, '<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">يعلن المجلس العالمي للعلوم الرياضية في السويد </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\"><span style=\"color:gray\">GCSS</span></span></span><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\"> و الاكاديمية السويدية للتدريب الرياضي </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\"><span style=\"color:gray\">SAST</span></span></span><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\"> عن اقامة دورة مفاهيم علمية لقوام رياضي صحي </span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">من يقدمها :</span></span></span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">البطل العالمي واخصائي التغذية الكابتن فيصل العليو، المعتمد من </span></span></span><span dir=\"LTR\" lang=\"SV\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\"><span style=\"color:gray\">GCSS</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">اين ومتى :</span></span></span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">في الدمام </span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\"><span style=\"color:gray\">12</span></span></span><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">-</span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\"><span style=\"color:gray\">14</span></span></span> <span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">ابريل</span></span></span><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\"> 2018</span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">من محاور الدورة :</span></span></span></u></strong></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:gray\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">تعلم صنع البرامج الغذائية الخاصة لكل هدف.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:gray\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">عن المكملات الغذائية الخاصة لكل هدف.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:gray\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">التوازن الغذائي وطرق عمل الماكروز بدقة.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:gray\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">المغذيات الكبرى والصغرى لجسم الانسان.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:gray\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">طرق عديدة لفحص إحتمالات المخاطر الصحية.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:gray\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">مبادئ رياضة كمال الاجسام.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:gray\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">أساسيات الرياضة وطرق التعامل معها.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:gray\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">مخاطر سوء التغذية على الرياضيين.</span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">طرق الاستفادة من التمارين الهوائية في حرق الدهون وتطوير الداء</span></span></span><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\"><span style=\"color:gray\">.</span></span></span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">اعتماد الشهادة :</span></span></span></span></u></strong></span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\"><span style=\"color:gray\">Global Council of Sport Science (GCSS)</span></span></span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\"><span style=\"color:gray\">The Swedish Academy of Sports Training (SAST)</span></span></span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\"><span style=\"color:gray\">International Accreditation of Sport Education (IASE)</span></span></span></span></span></span></li>\r\n	<li dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"color:#787878\"><span dir=\"LTR\" style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\"><span style=\"color:gray\">International Council of Sport Science and Physical Education (ICSSPE)</span></span></span></span></span></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><u><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">رسوم الاشتراك في الدورة:</span></span></span></span></u></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">2500 ريال سعودي</span></span></span></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><strong><span style=\"font-size:18.0pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:#00b0f0\">طرق التسجيل:</span></span></span></span></strong></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\"><span style=\"background-color:white\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:gray\">الاتصال بممثلنا في المملكة العربية السعودية الكابتن فيصل </span></span></span><strong><span dir=\"LTR\" style=\"font-size:11.5pt\"><span style=\"background-color:white\"><span style=\"font-family:&quot;Droid Arabic Kufi&quot;,serif\"><span style=\"color:gray\">0544424202</span></span></span></span></strong></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n', NULL, NULL, NULL, 'ar'),
(87, 42, 'دورة مفاهيم علمية لقوام رياضي صحي / الدمام / ابريل 2018', 'qxUb', NULL, NULL, NULL, NULL, NULL, 'en'),
(88, 43, 'تنبيه واشعار لكل طلبة الاكاديمية السويدية للتدريب الرياضي', 'pdyK', NULL, '<p dir=\"RTL\"><br />\r\n<strong>تنبيه واشعار لكل طلبة الاكاديمية السويدية للتدريب الرياضي</strong><strong> </strong></p>\r\n\r\n<p dir=\"RTL\"><br />\r\nبدأ من تاريخ 3 ابريل وحتى تاريخ 5 ابريل سيتوقف موقع الاكاديمية للتدريب الرياضي عن تقديم خدماته للطلبة وذلك بسبب التحديث وتطوير الموقع وعليه لن يكون الموقع متاح خلال هذه الفترة على ان يعاود العمل والتشغيل يوم 6 ابريل باذن الله .<br />\r\nنعتذر لهذا التوقف بسبب تحسين وتطوير مميزات الموقع بما يخدم الطلبة, نشكر تفهمكم وتعاونكم.</p>\r\n\r\n<p dir=\"RTL\"><br />\r\n<strong>لاي استفسار برجاء التواصل مع فريق الدعم الفني من خلال</strong><strong> </strong><strong>:</strong></p>\r\n\r\n<p dir=\"RTL\"><br />\r\n<strong>واتس / فايبر / اتصال</strong><strong> </strong><br />\r\n0046767045506</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\"><strong>او عبر ايميلاتنا</strong><br />\r\ninfo@swedish-academy.se</p>\r\n\r\n<p dir=\"RTL\">admin@gcss.se</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n', NULL, NULL, NULL, 'ar'),
(89, 43, 'تنبيه واشعار لكل طلبة الاكاديمية السويدية للتدريب الرياضي', 'VZiH', NULL, NULL, NULL, NULL, NULL, 'en'),
(90, 10, 'طاقة شبابية جديدة تنضم الى الاكاديمية', 'طاقة_شبابية', 'تم انضمام المدربة الشابة براءة التوبة الى سرب المدربين والخبراء العاملية في الاكاديمية السويدية للتدريب الرياضي SAST . وكلنا فخر وسرور بانضمامها معنا لما تحمله', '<p dir=\"RTL\" style=\"text-align:right\">تم انضمام المدربة الشابة براءة التوبة الى سرب المدربين والخبراء العاملية في الاكاديمية السويدية للتدريب الرياضي SAST . وكلنا فخر وسرور بانضمامها معنا لما تحمله من طاقات رياضية واعدة، وامكانيات بدنية وعلمية مميزة ولاقتة للانظار.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">يذكر ان المدربة براءة التوبة لها خبرات سابقة وتاريخ رائع في التدريب البدني والايروبكس والزومبا والتغذية الرياضية ولها محطات عمل متفرقة وعديدة في مختلف الدول منها سوريا والمملكة العربية السعودية وحاليا في المانيا.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:right\">نتمنى لها النجاح والتوفيق في عملها الجديد في الاكاديمية السويدية للتدريب الرياضي SAST والمجلس العالمي للعلوم الرياضية GCSS.</p>', NULL, NULL, NULL, 'ar'),
(91, 10, 'New youth energy joins the Academy', 'energy', 'The young female coach Bara Al Tuba has joined the team of trainers and working experts at the SAST Swedish Academy of Sport Training.', '<p dir=\"ltr\" style=\"text-align:left\">The young female coach Bara Al Tuba has joined the team of trainers and working experts at the SAST Swedish Academy of Sport Training. We are all proud and pleased to join us with its promising sports capabilities, unique and temporary physical and scientific capabilities to see. </p>\r\n\r\n<p dir=\"ltr\" style=\"text-align:left\">It is worth mentioning that the trainer, who has repentance, has previous experiences and a great history in physical training, aerobics, sports nutrition, and has several separate and numerous workstations in different countries, including Syria, Saudi Arabia and now in Germany. </p>\r\n\r\n<p dir=\"ltr\" style=\"text-align:left\">We wish her success in her new work at the Swedish Academy of Sport Training (SAST) and the Global Council of Sport Sciences (GCSS).</p>', NULL, NULL, NULL, 'en'),
(92, 44, 'الخطوة الأولى للأكاديمية السويدية للتدريب الرياضي و المجلس العالمي للعلوم الرياضية بالسويد  في تونس', '1st-etape', NULL, '<p style=\"text-align: right;\"><br /><br />تم اليوم اختتام أول دورات الأكاديمية السويدية للتدريب الرياضي و المجلس العالمي للعلوم الرياضية بالسويد في تونس (دورة المدرب الشخصي المستوى الأول ) حيث قام الدكتور علي فالح سلمان بالقاء كلمة شكر و ثناء على المشاركين و محاضر الدورة و قام بتوزيع الشهادات على الناجحين بعد اجتياز الاختبار النهائي</p>\r\n<p style=\"text-align: right;\"></p>\r\n<p style=\"text-align: right;\"><br />و تعد هذه الخطوة الأولى للمجلس العالمي للعلوم الرياضية بالسويد و الأكاديمية السويدية للتدريب الرياضي في تونس و نأمل أن تكون بادرة خير و نواصل العمل و التألق<br /><br /><br /></p>\r\n<p style=\"text-align: right;\"></p>\r\n<p style=\"text-align: right;\">الأكاديمية السويدية للتدر<span class=\"text_exposed_show\">يب الرياضي...طموحك معنا غير</span></p>\r\n<div class=\"text_exposed_show\">\r\n<p style=\"text-align: right;\"></p>\r\n</div>', NULL, NULL, NULL, 'ar'),
(93, 44, 'الخطوة الأولى للأكاديمية السويدية للتدريب الرياضي و المجلس العالمي للعلوم الرياضية بالسويد  في تونس', '1st-etape', NULL, NULL, NULL, NULL, NULL, 'en'),
(146, 71, 'التستوستيرون و الأستروجين', 'التستوستيرون-و-الأستروجين', 'هرموني التستوستيرون و الأستروجين هما هرموني الذكورة و الأنوثة الجنسية..مثلا المرأة لديها 5 % من مستوى هرمون التستوستيرون عند الرجال و لكن على الرغم من ذلك تعت', '<p style=\"text-align:right\"><span style=\"font-size:18px\"><strong>التستوستيرون و الأستروجين</strong></span></p>\r\n\r\n<ol>\r\n	<li style=\"text-align: right;\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>:تعريف</strong></span></span></li>\r\n</ol>\r\n\r\n<p style=\"text-align:right\">هرموني التستوستيرون و الأستروجين هما هرموني الذكورة و الأنوثة الجنسية..مثلا المرأة لديها 5 % من مستوى هرمون التستوستيرون عند الرجال و لكن على الرغم من ذلك تعتمد على مستوى التستوستيرون الطبيعي لصحة أفضل. يتم افراز هرمون التستوستيرون عند الرجال في الخصيتين بالأساس و بصفة قليلة في الأنسجة الشحمية و الغدد الكظرية</p>\r\n\r\n<p style=\"text-align:right\">بينما يكون الإنتاج عند الاناث في المبيضين و أيضا الى حد أقل في الأنسجة الشحمية و الغدد الكظرية</p>\r\n\r\n<p style=\"text-align:right\"><br />\r\nيتوفر هرمون تستوستيرون في اثنين من المتغيرات في الجسم هما هرمون تستوستيرن و ديهروتستوستيرون..أما هرمون الأستروجين فهو متوفر من ثلاثة أنواع في الجسم(ايسترون-الايستريول و استراديول.)</p>\r\n\r\n<ul>\r\n	<li style=\"text-align: right;\"><strong>كيف يتم افراز الهرمونين؟</strong></li>\r\n</ul>\r\n\r\n<p style=\"text-align:right\"><span style=\"font-size:14px\"><strong>.الدهون الكافية في الغذاء</strong></span></p>\r\n\r\n<p style=\"text-align:right\">أظهرت الدراسات أن الغذاء المحتووي في 25 % منه على الدهون ينتج عنه مستويات منخفضة من التستوستيرون</p>\r\n\r\n<p style=\"text-align:right\"><span style=\"font-size:14px\"><strong>.البروتين</strong></span></p>\r\n\r\n<p style=\"text-align:right\">يشير البروتين الى النمو الذي بدوره يشير الى افراز التستوستيرون</p>\r\n\r\n<p style=\"text-align:right\"><span style=\"font-size:14px\"><strong>.التدريب المكثف</strong></span></p>\r\n\r\n<p style=\"text-align:right\">بصفة خاصة تزيد تمرينات القوة عالية الكثافة من نسبة هرمون التستوستيرون</p>\r\n\r\n<p style=\"text-align:right\">-يتم افراز التستوستيرون بشكل رئيسي في اليل مع نبضات القلب لمدة 90 دقيقة و يعتبر النوم مفيدا أيضا لمستويات التستوستيرون.</p>\r\n\r\n<p style=\"text-align:right\">-يرتفع مستوى افراز هرمون التستوستيرون في العشرينات ثم سنخفض مع التقدم في السن و هذا هو السبب الرئيسي وراء انخفاض كتلة العضلات مع التقدم في العمر.</p>\r\n\r\n<p style=\"text-align:right\">-يتم افراز هرمون الأستروجين وفقا لدورة الطمث عند الاناث و هذا يعني زيادة المستويات في وقت التبويض.</p>\r\n\r\n<ul>\r\n	<li style=\"text-align: right;\"><span style=\"font-size:14px\"><strong>مؤثرات التستوستيرون و الأستروجين</strong></span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:right\">يجب اعتبار التستوستيرون هرمونا حيويا يجب أن يمتلك كل من الرجل و المرأة مستويات طبيعية منه لصحة أفضل..وهرمون الأسترجين هو الهرمون الذي يتوازن بواسطة البروجسترون و تعتمد المرأة على التقلبات الطبيعية لهذه الهرمونات لصحة أفضل</p>\r\n\r\n<p style=\"text-align:right\">كما أن الأثار المترتبة على النمو و المزاج و الاستنساخ و اثار هرموني التستوستيرون و الأسترجين كما يلي</p>\r\n\r\n<ul>\r\n	<li style=\"text-align: right;\"><span style=\"font-size:14px\"><strong>.زيادة الكتلة العضلية</strong></span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:right\">يؤدي التستوستيرون الى زيادة الكتلة العضلية و هذا هو السبب الرئيسي وراء عدم كبر حجم عضلات المرأة مثل الرجال.</p>\r\n\r\n<ul>\r\n	<li style=\"text-align: right;\"><span style=\"font-size:14px\"><strong>.عظام أقوى</strong></span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:right\">يعمل كل من التستوستيرون و الأستروجين على تقوية العظام و هذا التأثير يقل أثناء فترة انقطاع الطمث عند السيدات عند هبوط مستويات الأستروجين</p>\r\n\r\n<ul>\r\n	<li style=\"text-align: right;\"><strong>.زيادة حرق الدهون</strong></li>\r\n</ul>\r\n\r\n<p style=\"text-align:right\">يؤدي كلا من التستوستيرون و الأستروجين الى زيادة استهلاك الدهون مع الملاحظة أن حرق الدهون ليس هو نفسه فقدان الوزن.و لكن بدلا من ذلك يستخذم الجسم الأحماض الدهنية بدلا من الكلوكوز للحصول على الوقود.</p>\r\n\r\n<p style=\"text-align:right\">و تعتبر كثرة هرمون التستوستيرون غير صحية للنساء فقد يؤدي الى ادخال خصائص الذكورة و زيادة مخاطر الإصابة بالعقم كما أن كثرة هرمون الأسترجين تعد غير صحية للرجال على الرغم من القواسم المشتركة فمثلا عندما تتراكم الدهون في جسم الرجل يزداد تحول التستوستيرون الى الأستروجين في رواسب الدهون و نتيجة ذلك مثلا تكون الثدي عند الرجال.</p>', NULL, NULL, NULL, 'ar'),
(147, 71, 'Testosterone and Estrogen\r\n', 'tes+astrojin', 'The two hormones of testosterone and estrogen are hormones of masculinity and female sex. For example, women have 5% of the testosterone level in men however', '<p style=\"text-align:left\"><span style=\"font-size:18px\"><strong>Testosterone and Estrogen</strong></span></p>\r\n\r\n<ol>\r\n<li style=\"text-align: left;direction: ltr;\"><span style=\"font-size:16px\"><span style=\"color:#000000\"><strong>Definition :</strong></span></span></li>\r\n</ol>\r\n\r\n<p style=\"text-align:left;direction: ltr;\">The two hormones of testosterone and estrogen are hormones of masculinity and female sex. For example, women have 5% of the testosterone level in men however; it depends on the natural level of testosterone for better health. Testosterone is mainly excreted in the testicles and is very small in fat tissue and adrenal glands. While production in females is in the ovaries and to a lesser extent in adipose tissue and adrenal glands. </p>\r\n\r\n<p style=\"text-align:left;direction: ltr;\">While production in females is in the ovaries and also to a lesser extent in adipose tissue and adrenal glands</p>\r\n\r\n<p style=\"text-align:left;direction: ltr;\"><br />Testosterone is available in two variables in the body: testosterone and dihydrotestosterone.\r\n<ul>\r\n	<li style=\"text-align: left;direction: ltr;\"><strong>How is hormone secretion?</strong></li>\r\n</ul>\r\n\r\n<p style=\"text-align:left;direction: ltr;\"><span style=\"font-size:14px\"><strong>Adequate fat in food</strong></span></p>\r\n\r\n<p style=\"text-align:left;direction: ltr;\">Studies have shown that a 25% fat-containing diet results in low levels of testosterone</p>\r\n\r\n<p style=\"text-align:left\"><span style=\"font-size:14px\"><strong>Protein </strong></span></p>\r\n\r\n<p style=\"text-align:left;direction: ltr;\">Protein refers to growth, which in turn indicates testosterone secretion</p>\r\n\r\n<p style=\"text-align:left;direction: ltr;\"><span style=\"font-size:14px\"><strong>Intensive training</strong></span></p>\r\n\r\n<p style=\"text-align:left;direction: ltr;\">In particular, high-intensity strength training increases testosterone</p>\r\n\r\n<p style=\"text-align:left;direction: ltr;\">- Testosterone is secreted mainly at night with a heartbeat for 90 minutes and sleep is also beneficial for testosterone levels. </p>\r\n\r\n<p style=\"text-align:left;direction: ltr;\">-The level of testosterone secretion rises in the twenties and then we will decrease with age and this is the main reason behind the decrease in muscle mass with age. </p>\r\n\r\n<p style=\"text-align:left;direction: ltr;\">-Estrogen is secreted according to the menstrual cycle in females, which means increased levels at the time of ovulation.</p>\r\n\r\n<ul>\r\n	<li style=\"text-align: left;direction: ltr;\"><span style=\"font-size:14px\"><strong>Testosterone and estrogen stimulants</strong></span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:left;direction: ltr;\">Testosterone should be considered a vital hormone. Both men and women should have normal levels of it for better health. Estrogen is the hormone that is balanced by progesterone and women rely on the natural fluctuations of these hormones for better health.</p>\r\n\r\n<p style=\"text-align:left;direction: ltr;\">The effects of growth, mood, reproduction and the effects of testosterone and estrogen are as follows:</p>\r\n\r\n<ul>\r\n	<li style=\"text-align: left;direction: ltr;\"><span style=\"font-size:14px\"><strong>Increased muscle mass</strong></span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:left;direction: ltr;\">Testosterone leads to increased muscle mass and this is the main reason why women are not as big as men</p>\r\n\r\n<ul>\r\n	<li style=\"text-align: left;direction: ltr;\"><span style=\"font-size:14px\"><strong>Stronger bones</strong></span></li>\r\n</ul>\r\n\r\n<p style=\"text-align:left;direction: ltr;\">Testosterone and estrogen work to strengthen bones and this effect decreases during menopause in women when estrogen levels drop.</p>\r\n\r\n<ul>\r\n	<li style=\"text-align: left;direction: ltr;\"><strong>Increased fat burning</strong></li>\r\n</ul>\r\n\r\n\r\n<p style=\"text-align:left;direction: ltr;\">Both testosterone and estrogen increase fat intake, noting that burning fat is not the same as losing weight. Instead, the body uses fatty acids instead of glucose for fuel. </p>\r\n\r\n<p style=\"text-align:left;direction: ltr;\">The high incidence of testosterone is considered unhealthy for women, which may lead to the introduction of masculinity properties and increased risk of infertility, and the high incidence of estrogen is considered unhealthy for men despite common denominators, for example, when fat accumulates in the man\'s body, testosterone becomes increasingly estrogen in fat deposits and as a result, for example, the breast is in men.</p>', NULL, NULL, NULL, 'en'),
(150, 73, 'اللياقة البدنية. مفهومها و مبادئها.', 'اللياقة-البدنية.-مفهومها-و-مبادئها.', 'اللياقة البدنية من المصطلحات القليلة في التربية الرياضية و البدنية التي لاقت الذيوع و الانتشار بين الناس\r\nفاللياقة البدنية تعني سلامة البدن و كفاءته في مواج', '<p dir=\"rtl\">-اللياقة البدنية من المصطلحات القليلة في التربية الرياضية و البدنية التي لاقت الذيوع و الانتشار بين الناس.</p>\r\n\r\n<p dir=\"rtl\">-فاللياقة البدنية تعني سلامة البدن و كفاءته في مواجهة التحديات التي تواجه الانسان خلال تعامله في الحياة حيث تكون الأجهزة العضوية للجسم تتمتع بالصحة الوذيفية و الكفاية في الأداء بما يمكنها من جعل الشخص قادرا على القيام بالأعمال اليومية القوية و المشاركة أنشطة وقت الفراغ.</p>\r\n\r\n<p dir=\"rtl\"><strong>مبادئ اللياقة البدنية</strong></p>\r\n\r\n<p dir=\"rtl\">-هناك مبادئ أساسية عامة تعتبر الأساس في العملية التدريبية و حسب نوع النشاط و الفعالية الرياضية.. مع الأخذ بعين الاعتبار بأن يكون البرنامج التدريبي شاملا على مفردات دقيقة لذا فان من أهم المبادئ العامة التي يجب الأخذ بها و العمل على تطبيقها في أي برنامج يهدف الى تحقيق لياقة بدنية بشكل عام للوصول الى الإنجاز في الفعاليات الرياضية .. و يمكن تحديد ذلك بالمبادئ الرئيسية التالية</p>\r\n\r\n<p dir=\"rtl\"><strong>1-الانتظام</strong></p>\r\n\r\n<p dir=\"rtl\">-ان تطبيق هذا المبدأ يتطلب تبويب المفردات و إخراجها بشكل منتظم مع الأخذ بأن تكون عدد الوحدات التدريبية واضحة الأهداف ضمن الدائرة التدريبية و حسب نوع الصفة البدنية المراد تطويرها..فعملية الانتظام تتطلب الاستمرارية في العملية التدريبية دون حدوث أي انقطاع لأن ذلك يؤثر على اللياقة البدنية حيث أشارت الدراسات بأن فترة الانقطاع من(5-7) أيام سوف تؤثر على المستوى الرياضي كما تؤدي الى خفض اللياقة البدنية.</p>\r\n\r\n<p dir=\"rtl\"><strong>2-التدرج</strong></p>\r\n\r\n<p dir=\"rtl\">-ان مبدأ التدرج في برامج اللياقة البدنية ضرورة يجب الأخذ بها و العمل على تطبيقها من خلال مراعاة تسلسل المفردات أو التمرينات و درجة صعوبتها..لذلك عند البدأ بالبرنامج التدريبي يجب أن نبدأ بتمرينات الاحماء و التهيئة الجسمية بشكل عام ثم الى الاحماء الخاص و الانتقال الى الجزء الرئيس وصولا الى القسم الختامي من خلال استخدام تمرينات الاسترخاء و التهدئة.</p>\r\n\r\n<p dir=\"rtl\"><strong>3-التخصص</strong></p>\r\n\r\n<p dir=\"rtl\">-ان العملية التدريبية لابد من أن تأخذ الدقة في الاختصاص لغرض تطوير اللياقة البدنية.</p>\r\n\r\n<p dir=\"rtl\">من هنا يتوجب على المدربين اجراء اختبارات للاعبين من أجل معرفة امكاناتهم و قدراتهم ..حيث أن مثل هذه الاختبارات و الفحوصات سوف تعطي لنا مؤشرا لقابلية و إمكانية الرياضيين اخذين بعين الاعتبار العمر و الجانب الصحي ..لذا يتطلب عند وضع البرنامج التدريبي أن يكون هناك هدفه واضحا و محددا و التركيز عليه لا على أهداف أخرى.</p>\r\n\r\n<p dir=\"rtl\"><strong>4-درجة الحمل</strong></p>\r\n\r\n<p dir=\"rtl\">-المقصود هنا زيادة درجة الحمل من خلال استخدام درجة تصعيب الشدة لذا فان أي برنامد يخص اللياقة البدنية لابد أن يستند على مكونات الحمل الرئيسة..اذ يمكن استخدام أنواع من الطرق لرفع درجة الحمل التدريبي مثل(زيادة الوزن أو زيادة وقت أداء التمرين أو تقليل فترة الراحة أو زيادة شدة أداء التمرين أ زيادة تكرارات التمرين)..من هذه المبادئ الأربعة التي تم ذكرها تشكل القاعدة الأساس لبرامج اللياقة البدنية.. و في حالة عدم الأخذ بها سيؤدي ذلك الى حدوث خلل في البرنامج التدريبي..هذا مما يتطلب من المدربين ضرورة الالتزام بذلك لغرض تحقيق الهدف المطلوب من أجل الوصول الى أعلى درجات الإنجاز من اتباع الأسس العلمية الصحيحة.</p>\r\n\r\n<p dir=\"rtl\">للتعرف أكثر على الأسس العلمية الصحيحة يمكنك الاشتراك في هذه <a href=\"https://l.facebook.com/l.php?u=https%3A%2F%2Fswedish-academy.se%2Fcourses%2F62%3Ffbclid%3DIwAR29tluqC2CCPDsKQ6yi4uelNdaMigj-D8DGAhw59e_yEYmjspKNACggjwc&amp;h=AT2bRiE1LAVgky4jpomyhdZ5cCS3juCUy3DCSDFiCjz_iCyfR-Agq9FyiFnRQHyUAp18FSQ7EQC5JfvNFav5NSQK-ImJbxxIncZNxza4aIXEllZ5a-sX_53LQtskRjuAHW0\" rel=\"noopener nofollow\" target=\"_blank\">الدورة </a>و الحصول على شهادة معتمدة دوليا و أوروبيا.</p>', NULL, NULL, NULL, 'ar');
INSERT INTO `news_translations` (`id`, `news_id`, `title`, `slug`, `short_description`, `content`, `meta_title`, `meta_keyword`, `meta_description`, `lang`) VALUES
(151, 73, 'Fitness : Concept and principles.', 'اللياقة-البدنية.-مفهومها-و-مبادئها.', 'Physical fitness is one of the few terms in physical and physical education that has received panic and spread among people', '<p dir=\"ltr\">-Physical fitness is one of the few terms in sports and physical education that has become widespread among people. </p>\r\n\r\n<p dir=\"ltr\">-Physical fitness means the safety and efficiency of the body in the face of the challenges faced by man during his life, where the organs of the body are healthy and have the sufficient performance to enable the person to be able to do strong daily tasks and participate leisure activities.</p>\r\n\r\n<p dir=\"ltr\"><strong> Fitness principles </strong> </p>\r\n\r\n<p dir=\"ltr\">- There are general basic principles that are the basis of the training process and by type of activity and sports effectiveness. In addition to the fact that the training program is comprehensive in terms of accurate vocabulary, one of the most important general principles to be adopted and applied in any program that aims at achieving overall fitness to achieve achievement in sports events. This can only be determined by the following main principles. </p>\r\n\r\n<p dir=\"ltr\"><strong> 1. Regularity </strong> </p>\r\n\r\n<p dir=\"ltr\">- The application of this principle requires the regular tabulation and graduation of vocabulary, with the number of modules clearly targeted within the training course and depending on the type of physical attribute to be developed. The regularity process requires continuity in the training process without interruption because this affects fitness, as studies have suggested that the period of interruption from 5 to 7 days will affect the athletic level and reduce fitness.</p>\r\n\r\n<p dir=\"ltr\"><strong> 2. Gradualism </strong></p>\r\n\r\n<p dir=\"ltr\">- The principle of the gradualism of fitness programs is a necessity that must be taken into account and applied by taking into account the sequence and the degree of difficulty of the vocabulary or exercises.\r\nThis is when you start the course you should start with the warm-up and body conditioning exercises in general, then to your own warm-up and move to the main part to the final section by using the relaxation and calming exercises. </p>\r\n\r\n<p dir=\"ltr\"><strong> 3. Specialization </strong></p>\r\n\r\n<p dir=\"ltr\">- The training process must take the precision of competence to develop fitness. </p>\r\n\r\n<p dir=\"ltr\">- This is why the trainers should conduct tests for players to know their potential and abilities, and tests will give us an indication of the ability of athletes, taking into account age and health.Therefore, in developing the training program, it is necessary to have a clear and specific goal and focus on it and not other goals. </p>\r\n\r\n<p dir=\"ltr\"><strong> 4. Load degree  </strong> </p>\r\n\r\n<p dir=\"ltr\">-Intended here to increase the Load  degree through the use of the degree of difficulty of intensity, so any fitness program should be based on the main components of load degree … can be used types of methods to raise the degree of training load (such as weight gain or increase the time of exercise or reduce the duration of exercise rest or increase the intensity of the performance of the exercise and Increase the frequency of exercise) ... of these four principles that are the basis for fitness programs … If not adopted will lead to a malfunction in the training program. This requires trainers need commitment to the purpose of achieving the desired goal in order to reach a on the achievement scores of following the correct scientific foundations.  </p>\r\n\r\n<p dir=\"ltr\">To learn more about the correct scientific foundations you can subscribe to these  <a href = \"https://l.facebook.com/l.php?u=https%3A%2F%2Fswedish-academy.se%2Fcourses%2F62%3Ffbclid%3DIwAR29tluqC2CCPDsKQ6yi4uelNdaMigj -D8DGAhw59e_yEYmjspKNACggjwc & amp; h = AT2bRiE1LAVgky4jpomyhdZ5cCS3juCUy3DCSDFiCjz_iCyfR-Agq9FyiFnRQHyUAp18FSQ7EQC5JfvNFav5NSQK-ImJbxxIncZNxza4aIXEllZ5a-sX_53LQtskRjuAHW0 \"rel =\" noopener nofollow \"target =\" _ blank \"> courses </a>and get internationally accredited certification and European. </ p>\r\n', NULL, NULL, NULL, 'en'),
(152, 74, 'التمزق العضلي..ما هو؟أسبابه و أعراضه.', 'التمزق-العضلي..ما-هو؟أسبابه-و-أعراضه.', 'يعد التمزق العضلي من أكثر الإصابات التي تصيب الجهاز الحركي و تكثر بشكل كبير عند الرياضيين في إصابات الملاعب و ذلك لأن النشاط الرياضي يعتمد بشكل كبير على فعال', '<p style=\"text-align:right\">&nbsp;</p>\r\n\r\n<p style=\"text-align:right\"><span dir=\"RTL\">* يعد التمزق العضلي من أكثر الإصابات التي تصيب الجهاز الحركي و تكثر بشكل كبير عند الرياضيين في إصابات الملاعب و ذلك لأن النشاط الرياضي يعتمد بشكل كبير على فعالية النشاط البدني المعتمد أساسا على الجهاز الحركي من عظام</span></p>\r\n\r\n<p style=\"text-align:right\"><span dir=\"RTL\">،</span><span dir=\"RTL\">عضلات</span> <span dir=\"RTL\">،</span><span dir=\"RTL\">غضاريف.</span> <span dir=\"RTL\">،</span><span dir=\"RTL\">أربطة</span><span dir=\"RTL\">أوتار.</span><br />\r\n&nbsp;</p>\r\n\r\n<p style=\"text-align:right\"><strong><span dir=\"RTL\">1- ما هو التمزق العضلي</span></strong></p>\r\n\r\n<p style=\"text-align:right\"><span dir=\"RTL\">- التمزق العضلي هو تلف جزئي أو كلي في النسيج العضلي نتيجة كدمة خارجية خارجية من جراء الالتحام الجسم في الفعاليات الفرقية التي يحدث فيها اتصالات جسدية ككرة القدم و كرة اليد و كرة السلة و غيرها.</span></p>\r\n\r\n<p style=\"text-align:right\"><span dir=\"RTL\">- أو من خلال الحمل الزائد المسلط على العضلة الذي يفوق قدرتها الفسلجية كما يحدث عند تدريب القوة و رفع الأثقال.<br />\r\n<br />\r\n* التمزق العضلي غالبا ما يرافقه نزيف دموي تختلف شدته حسب نوع العضلة و كمية النسيج المتمزق.</span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"text-align:right\"><span dir=\"RTL\">- التمزق العضلي غالبا يحدث في الأنشطة الرياضية..لكن هذا لا يمنع من حدوثه في أي عمل عضلي في الحياة اليومية جراء تسليط حمل أكبرمن قدرة العضلة عليها<br />\r\n<br />\r\n* قد يحدث التمزق العضلي مع بقاء غشاء العضلة سليما فيكون النزيف تحت الغشاء و لا يكون واضحا بالنظر الى مكان الإصابة و باستمراره يولد ضغط على غشاء العضلة مما يسبب تضرر بعد عدة أيام اذا أهمل المصاب علاجه فتتكون كدمة زرقاء اللون فوق الجلد تكون واضحة للعيان.</span></p>\r\n\r\n<p style=\"text-align:right\"><strong><span dir=\"RTL\">2- كيف نشعر بالتمزق العضلي؟</span></strong><br />\r\n<br />\r\n.التمزق العضلي يكون من خلال الاحساس بألم كبير في العضلة و يمكن تشبيهه باحساس الانفجار داخل العضلة -<br />\r\n<span dir=\"RTL\">مثلا اذا كان التمزق عند الجري و بدون أي اتصال مع منافس اخر أو الأدوات الرياضية فغالبا ما يكون التمزق بسيط و سطحي و يكون تلف الألياف العضلية فيه قليل</span> <span dir=\"RTL\">،<br />\r\nأما اذا كان من خلال الحمل الزائد أو من خلال رفع الأثقال الكبيرة و بشكل مباشر فيؤدي هذا الى تمزق في النسيج العضلي أكبر و أعمق من سابق</span></p>\r\n\r\n<p style=\"text-align:right\"><span dir=\"RTL\">أما أعراضه فهي الأعراض التقليدية لأغلب الاصابات (ارتفاع درجة الحرارة..التورم و الألم في المنطقة المصابة و انخفاض في الأداء الوظيفي للجزء المصاب)</span></p>\r\n\r\n<p style=\"text-align:right\"><span dir=\"RTL\">* لكن في التمزق الكامل للعضلة نلاحظ وجود تورم كبير مع ازرقاق المنطقة مباشرة بعد الإصابة.</span><br />\r\n<br />\r\n<strong><span dir=\"RTL\">3- ما هي أسباب التمزق العضلي؟</span></strong></p>\r\n\r\n<p style=\"text-align:right\"><span dir=\"RTL\">- من بعض الأسباب هو أن يكون الرياضي غير مكتمل الاعداد و لا يمتلك الفورمة الرياضية الخاصة بحجم التدريب العالي فيكون عرضة لاصابات التمزق العضلي و نرى أيضا أن التعب و الاجهاد يزيدان من إمكانية حدوث التمزق العضلي حتى بعد التمرين.</span></p>\r\n\r\n<p style=\"text-align:right\"><span dir=\"RTL\">- من الأسباب الأخرى التي تسبب التمزق العضلي هي مباشرة التمارين الرياضية و الفعاليات البدنية دون احماء متدرج و مناسب</span><br />\r\n<span dir=\"RTL\">لمستوى الوحدة التدريبية فمثلا الشدة المفاجئة في العمل العضلي تؤدي الى تلف النسيج العضلي و تمزقه فعلى سبيل المثال الركض و الانطلاقات السريعة أو<br />\r\nركل الكرة بقوة قد تسبب التمزق العضلي.</span></p>\r\n\r\n<p style=\"text-align:right\"><span dir=\"RTL\">- و قد يحدث التمزق العضلي بسبب عودة الرياضة للنشاط البدني بعد الإصابة دون تأهيل جيد و عدم التأكد من امكانيته بمزاولة النشاط الرياضي مرة أخرى و بشكل تام.</span><br />\r\n<br />\r\n<span dir=\"RTL\">* لذلك نؤكد على ضرورة التأهيل الجيد للإصابة و أخذ الوقت اللازم لعلاجها بشكل امل و التأكد بنسبة 110 %</span></p>\r\n\r\n<p style=\"text-align:right\"><span dir=\"RTL\">من أن الجزء المصاب عاد الى وضعه الطبيعي قبل الإصابة.</span><br />\r\n&nbsp;</p>\r\n\r\n<p style=\"text-align:center\"><span dir=\"RTL\"><strong><span style=\"font-size:16px\">بقلم الدكتور&nbsp;<br />\r\nسفيان قاسمي&nbsp;</span></strong></span></p>\r\n\r\n<p style=\"text-align:right\">&nbsp;</p>', NULL, NULL, NULL, 'ar'),
(153, 74, 'Muscle Rupture…what are its causes and symptoms?', 'التمزق-العضلي..ما-هو؟أسبابه-و-أعراضه.', 'The most severe injuries to the motor system and the most frequent injuries to athletes', '<p style=\"text-align:left\"></p>\r\n\r\n<p style=\"text-align:left\"><span dir=\"ltr\">The most severe injuries to the motor system and the most frequent injuries to athletes in playgrounds are muscle rupture, because athletic activity depends heavily on the effectiveness of physical activity based primarily on the motor system such as bones, muscles, cartilage and ligaments Strings. </span></p>\r\n\r\n\r\n<p style=\"text-align:left\"><strong><span dir=\"ltr\">1- What is muscle rupture</span></strong></p>\r\n\r\n<p style=\"text-align:left\"><span dir=\"ltr\">- Muscle rupture is partial or total damage to the muscular tissue caused by external external shock due to the body\'s contact with the fractional events where physical contact such as football, handball, basketball and others occurs.</span></p>\r\n<p style=\"text-align:left\"><span dir=\"ltr\">- Or by overloading the muscle that exceeds its ability to claw, such as when training strength and lifting weights. </span></p> \r\n<p style=\"text-align:left\"><span dir=\"ltr\">- Muscular rupture is often accompanied by a hemorrhage whose intensity varies depending on the type of muscle and the amount of tissue that is torn apart. </span> </p>\r\n<p style=\"text-align:left\"><span dir=\"ltr\">- Muscle rupture often occurs in sports...but this does not prevent it from occurring in any muscle work in everyday life due to a more muscular load <br />\r\n* Muscle rupture may occur while the muscular membrane remains intact and the bleeding is under the membrane and is not visible by the location of the infection and It is not clear in view of the location of the infection and its persistence generates pressure on the muscle membrane, which causes damage after several days if the patient neglects his treatment and becomes a blue blood over the skin that is clear to the eye. </span> </p>\r\n<p style=\"text-align:left;direction: ltr;\"><strong><span dir=\"ltr\">2- How do we feel muscle rupture?</span></strong><br />\r\n<br />\r\nThe muscle rupture is by feeling a major pain in the muscle and can be compared to the sensation of explosion inside the muscle.<br />\r\n<span dir=\"ltr\">For example, if the rupture when running and without any contact with another competitor or sports equipment, the rupture is often simple and superficial and there is little damage to the muscle fibers.</span><br />\r\nIf it is through overload or by lifting directly large weights and, this will tear the muscular tissue larger and deeper than before.</span> </p>\r\n<p style=\"text-align:left;direction: ltr;\">The symptoms are the typical symptoms of most injuries (high temperature, swelling, pain in the affected area and reduced functional performance of the affected part).<span dir=\"ltr\"></span></p>\r\n\r\n<p style=\"text-align:left\"><span dir=\"ltr\">* In the case of a full rupture we notice a blue large swelling area immediately after injury.</span><br />\r\n<br />\r\n<strong><span dir=\"ltr\">3- What are the causes of muscle rupture?<span></strong></p>\r\n\r\n<p style=\"text-align:left\"><span dir=\"ltr\">- Some of the causes are that the athlete is not fully prepared and does not have the right athletic physique that is susceptible to muscular rupture injuries and we also see that fatigue and stress increase the possibility of muscular rupture even after exercise.</span> </p>\r\n<p style=\"text-align:left\"><span dir=\"ltr\">- Other causes that cause muscle rupture are exercise and physical activity without proper warming</span><br />\r\n<span dir=\"ltr\"> Other Reasons that cause muscle rupture are exercise and physical activity without proper warming for or the level of the training unit, for example, the sudden intensity in the work of the muscles lead to damage to the muscle tissue and rupture, for example jogging and quick releases o kicking the ball hard can cause muscle rupture.</span> </p>\r\n<p style=\"text-align:left\"><span dir=\"ltr\">- muscle rupture may occur due to returning to physical activities after the injury without proper rehabilitation and the failure to ensure that the exercise can be conducted again and fully.</span> <br />\r\n<br />\r\n\r\n<span dir=\"ltr\">* Therefore, we emphasize the need for good rehabilitation of the injury and to take the time necessary to treat it with hope and make sure that the injured part has returned to its normal position before injury by 110%. <span></p>\r\n\r\n<p style=\"text-align:center\"><span dir=\"ltr\"><strong><span style=\"font-size:16px\">By Dr.Sofiane kasemi</span></strong></span></p>\r\n\r\n\r\n', NULL, NULL, NULL, 'en'),
(169, 88, 'الرياضة و ضغط الدم..التمارين الموصى بها مع بعض الارشادات ', 'الرياضة-و-ضغط-الدم..التمارين-الموصى-بها-مع-بعض-الارشادات', 'ضغط الدم المرتفع \r\nضغط الدم المرتفع هو حالة يكون فيها ضغط الدم مرتفع و ثابت في شرايين الجسم حيث يكون', '<p dir=\"rtl\">الرياضة و ضغط الدم..التمارين الموصى بها مع بعض الارشادات&nbsp;<br />\r\n<strong>1.ضغط الدم المرتفع&nbsp;</strong><br />\r\nضغط الدم المرتفع هو حالة يكون فيها ضغط الدم مرتفع و ثابت في شرايين الجسم حيث يكون مرتفعا عن المعدل الطبيعي أي أعلى من 80/120 و يكون ذلك نتيجة لعدة أسباب منها&nbsp;<br />\r\nالتعرض المفرط للضغوطات النفسية..السمنة و التدخين ... و يأتي هذا الارتفاع مصحوبا ببعض الأعراش مثل الصداع..الدوخة أو الطمس أي عدم رؤية الأشياء بوضوح.<br />\r\nعدم معالجة ضغط الدم لفترة طريلة قد تعزز من خطر الإصابة بسكتة دماغبة.<br />\r\n<br />\r\nكما أن قلة ممارسة التمارين الرياضية تعد عاملا خطرا و قد تؤدي الى تفاقم الحالة و الإصابة بأمراض أخرى متعلقة بارتفاع ضغط الدم<br />\r\n<br />\r\n<strong>2.فوائد الرياضة لمرضى ضغط الدم</strong><br />\r\n<br />\r\nتعد ممارسة تمارين اللياقة البدينة بصفة منتظمة عاملا أساسيا في الحد من خطورة أعراض ارتفاع ضغط الدم و من فوائدها زيادة الطاقة و الراحة التنفسية مما يساهم في تقليل ضغط الدم إضافة الى تقوية جهاز المناعة و التخفيف من حدة التوتر كما أن لها فوائد أخرى أيضا كتقوية القلب و الأوعيىة و الدموية و زيادة قدرة الرئتين و تحسين الدورة الدموية مما يساعد الجسم على استخدام الأكسجين بشكل أفضل.<br />\r\n<br />\r\n<strong>3.التمارين الموصى بها لمرضى ضغط الدم المرتفع</strong><br />\r\n<br />\r\nتمارين الأيروبيك&nbsp;<br />\r\nحيث لابد لجدولك الأسبوعي أن يكون به على الأقل ثلاثة مواعيد لممارسة هذه الرياضة..كذلك ينصح بممارسة السباحة و ركوب الخيل 3 مرات أو أكثر أسبوعيا إضافة الى المشي.<br />\r\n<br />\r\n<strong>4.التمارين غير المسموح بها لمرضى ضغط الدم المرتفع</strong><br />\r\n<br />\r\nبالنسبة لمرضى ضغط الدم يجب عليهم تجنب كل التمارين التي تؤدي الى افراز العرق بصفة شديدة تجنبا للإصابة بالجفاف كما ينصح أيضا بعدم رفع الأوزان الثقيلة و خاصة التي ترفع فوق الذراعين.<br />\r\n<br />\r\n<strong>5.ارشادات مهمة لمرضى ضغط الدم المرتفع قبل التمارين</strong><br />\r\n<br />\r\nينصح أولا بمراجعة الطبيب و عمل الفحوصات اللازمة لعضلة القلب و معالجة المشاكل المصاحبة لارتفاع ضغط الدم كالسكري و ارتفاع نسبة الكولسترول و ذلك لمنع حوث أي مضاعفات أثناء القيام بالتمارين.<br />\r\n<br />\r\nالحرص على أن تكون فترة التدريب بين 40-60 دقيقة للوصول الى النتائج المطلوبة مع الحرص على التمرن مع مدرب متخصص لاختيار التمارين الازمة و يجب التوقف فورا في حال الشعور بصداع أو الغثيان أو ضيق التنفس و حتى التعب الشديد.</p>', NULL, NULL, NULL, 'ar'),
(170, 88, 'Sports & Blood Pressure. Recommended workouts with some instructions.', 'الرياضة-و-ضغط-الدم..التمارين-الموصى-بها-مع-بعض-الارشادات', 'High blood pressure is a condition in which blood pressure is high and constant in the body arteries where it is', '<p dir=\"ltr\">Sports & Blood Pressure. Recommended workouts with some instructions. <br /> \r\n<br />\r\n<strong>1. High blood pressure</strong><br />High blood pressure is a condition in which blood pressure is high and constant in the body arteries where it is higher than the normal rate of 80/120, and for a number of reasons.<br />\r\nExcessive exposure to psychological stress…obesity and smoking ... This height comes with some bedding like headache, dizziness or blurring any obvious lack of visibility of things.<br />\r\nFailure to treat blood pressure for a trimmed period may increase the risk of a brain stroke. <br />\r\n<br />Lack of exercise is also a risk factor and may lead to an aggravation of the situation and other high blood pressure diseases. <br /><br />\r\n\r\n<strong>2. Sports benefits for blood pressure patients</strong><br />\r\nRegular physical exercise is a key factor in reducing the risk of high blood pressure symptoms and its benefits increase energy and respiratory comfort, which contributes to reduce blood pressure in addition to strengthening the immune system and alleviate stress. Blood vessels and increase the ability of the lungs and improve blood circulation, which helps the body to use oxygen better. <br />\r\n<br />\r\n<strong>3. Recommended exercises for high blood pressure patients</strong><br />\r\n\r\nAerobic exercises <br />\r\nYour weekly schedule must have at least three times for this exercise...swimming and horse riding are recommended 3 times or more per week as well as walking. <br /><br />\r\n<strong>4. Unauthorized exercises for high blood pressure patients</strong><br />\r\n\r\nFor blood pressure patients, avoid all sweat-wicking exercises to avoid dehydration and heavy weights, especially those raised above the arms, are not recommended.\r\n<br /><br />\r\n<strong>5.important guidelines for high blood pressure patients before exercise</strong><br />\r\nFirst check with your doctor and make the necessary myocardial examinations and address problems associated with high blood pressure such as diabetes and high cholesterol to prevent any complications from being induced during exercise. <br />\r\nEnsure that the training period is between 40-60 minutes to reach the desired results, being sure to work out with a qualified trainer to choose crisis exercises, stop immediately if you feel headache, nausea, shortness of breath and even extreme fatigue. </p>', NULL, NULL, NULL, 'en'),
(203, 110, 'متطلبات المكملات الغذائية للأداء الرياضي', 'COMPL-SPORT', 'تختلف الحاجة الى الكربوهيدرات من رياضة الى أخرى كما تختلف من فرد الى اخر..لذلك فان الحل الأفضل يتمثل في تخصيص كمية', '<p style=\"text-align:right\"><span style=\"color:#00FFFF\"><span style=\"font-size:18px\"><strong>متطلبات المكملات الغذائية للأداء الرياض</strong></span></span><br />\r\n<br />\r\n<span style=\"font-size:14px\"><strong>تختلف الحاجة الى الكربوهيدرات من رياضة الى أخرى كما تختلف من فرد الى اخر..لذلك فان الحل الأفضل يتمثل في تخصيص كمية الكربوهيدرات الملائمة لكل فرد و لكل رياضة..و بصفة عامة تتراوح توصية الكربوهيدرات بين 55 و 65 بالمائة من اجمالي<br />\r\nالطاقة التي نحصل عليها من مصادر الجودة كالأرز و البطاطس و الفاكهة و دقيق الشوفان و التوت و المشروبات الرياضية&nbsp;<br />\r\n<br />\r\n<br />\r\nيجب أن يكون حجم الكربوهيدرات عند 6-10 جرامات من الكربوهيدرات لكل كيلوجرام من وزن الجسم في اليوم<br />\r\n<br />\r\nعندما يتعلق الأمر برياضات التحمل فان المزيد و المزيد من الأبحاث تدعم النظام الغذائي الذي يحتوي على كمية أعلى من الدهون و كمية قليلة من الكربوهيدرات عند اقتراب المنافسة و يهدف هذا النظام الى رفع مستوى قدرة الجسم على استخدام الدهون في<br />\r\nالكثافات العالية&nbsp;<br />\r\nيؤدي استخدام الدهون كوقود الى انخفاض استهلاك الكليكوجين في العضلات و ينتج عن ذلك ربما يكون من الممكن الحفاظ على وتيرة أعلى من خلال المنافسة و هذه النظام يطلق عليه اسم:تدرب قليلا و تنفس أكثر</strong></span></p>', NULL, NULL, NULL, 'ar'),
(204, 110, 'Requirements of Dietary Supplements for Athletic Performance', 'COMPL-SPORT', 'The need for carbohydrates varies from one sport to another and varies from one individual to another\r\n', '<p dir=\"ltr\">\r\nThe need for carbohydrates varies from one sport to another and varies from one individual to another. Therefore, the best solution is to allocate the right amount of carbohydrates to each individual and sport. Generally, the carbohydrate recommendation ranges from 55 to 65 percent of the total energy we receive from quality sources such as rice, potatoes, fruit, oats, berries and sports drinks.\r\n</p>\r\n<p dir=\"ltr\">\r\nCarbohydrates must be 6-10 g carbohydrates per kg of body weight per day.\r\n</p>\r\n<p dir=\"ltr\">\r\nWhen it comes to Endurance Sports, more and more research supports a diet that contains a higher amount of fat and a small amount of carbohydrates as the competition approaches. This system aims to increase the body\'s ability to use fat in high densities.\r\n</p>\r\n<p dir=\"ltr\">\r\nThe use of fat as fuel results in reduced muscle glycogen consumption, and this may result in a higher rate being maintained through competition, which is called \"little training and more breathing\"\r\n</p>', NULL, NULL, NULL, 'en'),
(205, 111, 'البروتين بعد التمرين', 'protein-after-work', 'تتطلب قدرة الجسم على التعافي من الألعاب أو الممارسات أو التدريبات المكثفة الى الراحة و التغذية السليمة', '<p style=\"text-align: right;\"><br />\r\n<span style=\"color:#00FFFF\"><span style=\"font-size:18px\"><strong>البروتين بعد التمرين</strong></span></span></p>\r\n\r\n<p style=\"text-align: right;\"><strong><span dir=\"RTL\">تتطلب قدرة الجسم على التعافي من الألعاب أو الممارسات أو التدريبات المكثفة الى الراحة و التغذية السليمة.</span></strong><br />\r\n<br />\r\n<strong><span dir=\"RTL\">- يستهلك الجسم عنصرا هاما في عملية الإنعاش كل من الكربوهيدرات و البروتين بعد وقت قصير من عملية استعادة الجليكوجين في العضلات و تحفز على تخليق البروتين في العضلات.<br />\r\n<br />\r\n<br />\r\n* تناول الطعام<br />\r\n<br />\r\n- عليك بالأخذ في الاعتبار أن الغذاء هو الطاقة و يجب على الرياضيين تجنب التدريب أو الألعاب بدون ما يكفي من الأغذية لدعم متطلبات الطاقة لهذه الرياضة.<br />\r\nو لكي يحافظ الرياضيين على الطاقة بشكل صحيح و الوفاء لاحتياجات البروتين يرجى اسخدتم المبادئ التوجيهية لتناول الطعام.<br />\r\n<br />\r\n<br />\r\n- تناول&nbsp;وجبة الإفطار حيث تعد أفضل طريقة لبدء يوم جديد مفعم بالطاقة و تشمل الأغذية التي تحتوي على الكربوهيدرات و البروتين مثل الحليب الخالي من الدسم أو اللبن أو البيض.<br />\r\n<br />\r\n<br />\r\n- قم بإضافة الكربوهيدرات و البروتين بعد تناول وجبات الطعام ..و توفر بعض قوالب الطاقة الكربوهيدرات لتجديد مخازن الجليكوجين في العضلات و البروتينات للمساعدة على بناء و اصلاح العضلات.</span></strong><br />\r\n<br />\r\n&nbsp;</p>\r\n\r\n<p style=\"text-align: right;\"><strong><span dir=\"RTL\">* تخلص من المكملات الغذائية</span></strong></p>\r\n\r\n<p style=\"text-align: right;\"><strong><span dir=\"RTL\">يجب على الرياضيين الاعتماد على البروتين من مصادر الغذاء أولا بدلا من المكملات الغذائية حيث يساعد هذا في ضمان توازن الوجبات الغذائية للصحة و الأداء.. و بالإضافة&nbsp; الى اللحوم ذات المصادر الغنية بالبروتين فان منتجات الألبان و المكسرات و البذور يمكن بسهولة أن تضاف الى أي وجبة.</span></strong><br />\r\n&nbsp;</p>', NULL, NULL, NULL, 'ar'),
(206, 111, 'Protein After Exercise\r\n', 'protein-after-work', 'The body\'s ability to recover from intense games, practices, or exercises requires rest and proper nutrition', '<p style=\"text-align: left;\"><br />\r\n<span style=\"color:#00FFFF\"><span style=\"font-size:18px\"><strong>Protein after exercise</strong></span></span></p>\r\n\r\n<p style=\"text-align:left;\"><strong><span dir=\"ltr\">The body\'s ability to recover from intense games, practices, or exercises requires rest and proper nutrition</span></strong><br />\r\n<br />\r\n<strong><span dir=\"ltr\">The body consumes an important element in the recovery process both carbohydrates and protein shortly after the recovery of glycogen in muscle and stimulates the creation of protein in muscle. <br />\r\n<br />\r\nHave Food.<br />\r\n<br />- Keep in mind that food is energy and athletes should avoid training or games without enough food to support the energy requirements of the sport.\r\n<br />- Keep in mind that nutrition is energy and athletes should avoid training or games without enough food to support the energy requirements of the sport. To keep energy right and meet protein needs, please use our eating guidelines.\r\n<br />- Breakfast is the best way to start a new energy day and includes carbohydrates and protein foods such as skim milk, yogurt or eggs. \r\n\r\n<br /> - Add carbohydrates and protein after eating meals. Some carbohydrate energy templates provide for the renewal of glycogen stores in muscles and proteins to help build and repair muscles. \r\n</span> \r\n</strong> \r\n\r\n</p>\r\n\r\n<p style=\"text-align: left;\"><strong><span dir=\"ltr\">Ditch Dietary Supplement.</span></strong></p>\r\n\r\n<p style=\"text-align: left;\"><strong><span dir=\"ltr\">Athletes should rely on protein from food sources first rather than dietary supplements as this helps to ensure that meals are balanced for health and performance. In addition to meat from protein-rich sources, dairy products, nuts and seeds can easily be added to any meal. </span> </strong> </p>', NULL, NULL, NULL, 'en'),
(207, 112, 'متطلبات المكملات الغذائية للأداء الرياضي', 'متطلبات-المكملات-الغذائية-للأداء-الرياضي', 'تختلف الحاجة الى الكربوهيدرات من رياضة الى أخرى كما تختلف من فرد الى اخر..لذلك فان الحل الأفضل يتمثل في تخصيص كمية الكربوهيدرات الملائمة لكل فرد و لكل رياضة', '<p dir=\"rtl\"><br />\r\nتختلف الحاجة الى الكربوهيدرات من رياضة الى أخرى كما تختلف من فرد الى اخر..لذلك فان الحل الأفضل يتمثل في تخصيص كمية الكربوهيدرات الملائمة لكل فرد و لكل رياضة..و بصفة عامة تتراوح توصية الكربوهيدرات بين 55 و 65 بالمائة من اجمالي الطاقة التي نحصل عليها من مصادر الجودة كالأرز و البطاطس و الفاكهة و دقيق الشوفان و التوت و المشروبات الرياضية.&nbsp;<br />\r\nيجب أن يكون حجم الكربوهيدرات عند 6-10 جرامات من الكربوهيدرات لكل كيلوجرام من وزن الجسم في اليوم.<br />\r\nعندما يتعلق الأمر برياضات التحمل فان المزيد و المزيد من الأبحاث تدعم النظام الغذائي الذي يحتوي على كمية أعلى من الدهون و كمية قليلة من الكربوهيدرات عند اقتراب المنافسة و يهدف هذا النظام الى رفع مستوى قدرة الجسم على استخدام الدهون في الكثافات العالية.&nbsp;<br />\r\nيؤدي استخدام الدهون كوقود الى انخفاض استهلاك الكليكوجين في العضلات و ينتج عن ذلك ربما يكون من الممكن الحفاظ على وتيرة أعلى من خلال المنافسة و هذه النظام يطلق عليه اسم&quot;تدرب قليلا و تنفس أكثر&quot;</p>', NULL, NULL, NULL, 'ar'),
(208, 112, 'Requirements of Dietary Supplements for Athletic Performance', 'متطلبات-المكملات-الغذائية-للأداء-الرياضي', 'The need for carbohydrates varies from one sport to another and varies from one individual to another\r\n', '<p dir=\"ltr\">\r\nThe need for carbohydrates varies from one sport to another and varies from one individual to another. Therefore, the best solution is to allocate the right amount of carbohydrates to each individual and sport. Generally, the carbohydrate recommendation ranges from 55 to 65 percent of the total energy we receive from quality sources such as rice, potatoes, fruit, oats, berries and sports drinks.\r\n</p>\r\n<p dir=\"ltr\">\r\nCarbohydrates must be 6-10 g carbohydrates per kg of body weight per day.\r\n</p>\r\n<p dir=\"ltr\">\r\nWhen it comes to Endurance Sports, more and more research supports a diet that contains a higher amount of fat and a small amount of carbohydrates as the competition approaches. This system aims to increase the body\'s ability to use fat in high densities.\r\n</p>\r\n<p dir=\"ltr\">\r\nThe use of fat as fuel results in reduced muscle glycogen consumption, and this may result in a higher rate being maintained through competition, which is called \"little training and more breathing\"\r\n</p>', NULL, NULL, NULL, 'en'),
(210, 114, 'نصائح تضخيم العضلات', 'tadh5im-muscles', 'لتتمكن من تضخيم عضلاتك عليك بهاته النصائح...', '<p dir=\"rtl\">نصائح لتحقق الضخامة العضلية :<br />\r\n<br />\r\nلتتمكن من الحصول على عضلات ضخمة عليك أن تضع نصب أعينك هاته النصائح الثلاث :<br />\r\n&nbsp;</p>\r\n\r\n<p dir=\"rtl\">1- رفع الاوزان أو المقاومة الهيدروليكية في الأجهزة.<br />\r\n2- برنامج غذائي خاص يحتوي على كمية عالية من البرتين.<br />\r\n3-&nbsp;راحة كافية ونوم جيد ليلاً وقلة السهر لأن نمو العضلات يكون ليلاً.</p>', NULL, NULL, NULL, 'ar'),
(211, 114, 'Tips for Bigger Muscles\r\n', 'tadh5im-muscles', 'In order to get bigger muscles, you have to keep in mind these three tips', '<p dir=\"ltr\">Tips to make your muscles bigger: <br />\r\n<br />\r\nIn order to get bigger muscles, you have to keep in mind these three tips: <br /> </p>\r\n\r\n<p dir=\"ltr\">1- lifting weights or hydraulic-Resistance on equipment. <br />\r\n2- A special diet containing a high amount of protein. <br />\r\n3- enough comfort, a good night sleep and not staying up late because muscle growth is at night. </p>', NULL, NULL, NULL, 'en'),
(212, 115, 'تكبير عضلات الصدر', 'bench-muscle', 'تكبير عضلات الصدر من الأمور المهمة لأي رجل، وهو التمرين الأول لأي رجل في الصالة الرياضية، فالجميع يطمع في عضلات صدر قوية وضخمة، ولكن البعض يرتكب بعض الأخطاء ال', '<p style=\"text-align:right\">تكبير عضلات الصدر</p>\r\n\r\n<p dir=\"rtl\" style=\"text-align:justify\">تكبير عضلات الصدر من الأمور المهمة لأي رجل، وهو التمرين الأول لأي رجل في الصالة الرياضية، فالجميع يطمع في عضلات صدر قوية وضخمة، ولكن البعض يرتكب بعض الأخطاء الساذجة التي تقلل من تأثير أي تمارين على الصدر، ومن بين تلك الأخطاء:<br />\r\n&nbsp;</p>\r\n\r\n<p dir=\"rtl\" style=\"text-align:justify\"><br />\r\n:ـ 1)&nbsp;عدم حمل الوزن بشكل صحيح، فقد يسقط الوزن مباشرة على الصدر فيسبب العديد من المشاك.<br />\r\n&nbsp;- 2)زيادة التكرارات مع تمارين الوزن الثقيل، وهو ما يؤثر بالسلب على عضلات الصدر، بتكرارات كثيرة مع كثافة متزايدة.</p>\r\n\r\n<p dir=\"RTL\">- 3)&nbsp;الضغط الزائد عن الحد فيما يتعلق برفع الوزن والذي يمكن أن يسبب آلام شديدة للعضلة والكتفين، فيجب أن يكون الضغط متنوع فيها يتعلق بتمارين الصدر.</p>\r\n\r\n<p dir=\"RTL\">- 4)&nbsp;زيادة الجهود لرفع المزيد من الوزن بغض النظر عن وزن الجسم، أو كمية البروتين التي تتناولها، أو التكرارات أو البرنامج التدريبي الذي تسير عليه.</p>\r\n\r\n<p dir=\"RTL\">- 5)&nbsp;تغيير زوايا الرفع باستمرار فيما يتعلق برفع الوزن والذي يسبب تشتت كبير للعضلات وإرهاق كبير لها، ولا يحقق الفائدة المرجوة منه.</p>\r\n\r\n<p dir=\"RTL\">- 6)&nbsp;الاعتماد على رفع الوزن دون الحركة، فتكون الحركات قليلة مع التركيز على كمية الوزن المرفوع، وهو أمر خاطئ في تدريب الصدر الذي يجب أن تركز فيه على حركة الذراعين ومجالهما.</p>', NULL, NULL, NULL, 'ar'),
(213, 115, 'Build Bigger Chest Muscles\r\n', 'bench-muscle', 'To Build a bigger chest muscles is important for any man, the first workout in the gym, everyone is wagging for strong, big muscles, but some are making some naïve mistakes\r\n', '<p style=\"text-align:left\"> Build Bigger Chest Muscles </p>\r\n\r\n<p dir=\"ltr\" style=\"text-align:justify\">To Build a bigger chest muscles is important for any man, the first workout in the gym, everyone is wagging for strong, big muscles, but some are making some naïve mistakes that reduce the impact of any chest workout, including: </p>\r\n\r\n<p dir=\"ltr\" style=\"text-align:justify\">1) not carrying the weight correctly, the weight may fall directly on the chest and cause a lot of discomfort. </p>\r\n\r\n<p dir=\"ltr\" style=\"text-align:justify\">2) increase reps with heavy-weight exercises, which negatively affect your chest muscles, in many iterations with increased intensity.</p>\r\n\r\n<p dir=\"ltr\" style=\"text-align:justify\"> 3) over-weight lifting pressure that can cause severe muscle and shoulder pain, should be varied with chest exercises.</p>\r\n\r\n<p dir=\"ltr\" style=\"text-align:justify\">4) increase efforts to increase weight regardless of body weight, protein intake, repetitions or your training. </p>\r\n\r\n<p dir=\"ltr\" style=\"text-align:justify\">5) continually changing lift angles in terms of weight gain that causes significant muscle spasm and discomfort, and does not benefit. </p>\r\n\r\n<p dir=\"ltr\" style=\"text-align:justify\">6) rely on lifting weight without movement, making movements small with a focus on the amount of lifted weight, which is wrong with your chest training where you should focus on the movement and scope of your arms.</p>', NULL, NULL, NULL, 'en'),
(214, 116, 'اصدار العدد الأول من المجلة السويدية للبحث العلمي', 'SJSR-01', 'تم بكل فخر و اعتزاز اطلاق الاصدار الاول من العدد السادس من المجلة السويدية للبحث العلمي \r\n The Swedish Journal of Scientific Research SJSR\r\nو جاء هذا الجهد بعد ت', '<p dir=\"rtl\">تم بكل فخر و اعتزاز اطلاق الاصدار الاول من العدد السادس من المجلة السويدية للبحث العلمي&nbsp;<br />\r\n&nbsp;The Swedish Journal of Scientific Research SJSR<br />\r\nو جاء هذا الجهد بعد تعب و سهر من خيرة الاساتذة و الدكاترة العرب و الدوليين الذين عملوا و تعبوا على تنقيح و تجميع كل البحوث و المعلومات حسب اخر التطورات و الأبحاث لنقدمها لكم مجانا و نضعها بين أيديكم بسهولة و تجدونها عبر هذا الرابط :<br />\r\n&nbsp;sjsr.se/en/issue.php?issue=41&amp;vol=6</p>\r\n\r\n<p style=\"text-align:right\">يذكر ان المجلة السويدية سوف تستمر باصدار الابحاث العلمية المتخصصة بعلوم الرياضة باصدارات ربع سنوية اي كل ٣ اشهر.. سوف يكون العدد القادم في مطلع شهر سبتمبر من هذا العام.<br />\r\nلهذا ندعو جميع الباحثين الرياضين بارسال ابحاثهم ليكون لهم السبق والريادة ونشرها في مجلتنا الغراء</p>', NULL, NULL, NULL, 'ar'),
(215, 116, 'Launching the first issue of the Swedish Journal of Scientific Research', 'SJSR-01', 'The first issue of the sixth issue of the Swedish Journal of Scientific Research was  proudly launched The Swedish Journal of Scientific Research SJSR', '<p style=\"text-align:left;direction:ltr;\"> The first issue of the sixth issue of the Swedish Journal of Scientific Research was  proudly launched The Swedish Journal of Scientific Research SJSR <br />\r\nThis effort came after the effort and infiltration of the best Arab and international professors and doctors who worked and worked to refine and compile all research and information according to the latest developments and research, to be submitted to you free of charge and easily put in your hands and find it through this <a href=\"http://sjsr.se/en/issue.php?issue=41&vol=6\"> link </a></p>\r\n\r\n<p style=\"text-align:left;direction:ltr;\"> The Swedish magazine will continue to issue scientific research specialized in sports sciences with quarterly issues every 3 months. The next issue will be in early September this year. <br />\r\nThis is why we invite all the sports researchers to send their research to be proactive and lead and to publish it in our magazine.</p>\r\n', NULL, NULL, NULL, 'en'),
(216, 117, 'خلع في الكتف (تعريفه، اعراضه، علاجه)', 'خلع-في-الكتف-(تعريفه،-اعراضه،-علاجه)', 'الخلع في الكتف هو من الإصابات البالغة والمؤلمة وغالبًا ما تحدث في الرياضات التي تتطلب الاحتكاك الجسدي أو من السقوط.', '<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<h1 dir=\"RTL\" style=\"text-align:center\"><span style=\"color:#0000FF\"><strong>خلع في الكتف </strong><strong>(تعريفه، اعراضه، علاجه)</strong></span></h1>\r\n\r\n<h1 dir=\"RTL\" style=\"text-align:center\"><u><strong>الدكتور علي فالح</strong></u></h1>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:center\">الخلع في الكتف هو من الإصابات البالغة والمؤلمة وغالبًا ما تحدث في الرياضات التي تتطلب الاحتكاك الجسدي أو من السقوط.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:center\"><br />\r\nينخلع (يخرج) عظم الذراع العلوي من مكانه الطبيعي ويؤدي إلى أضرار كبيرة بالأنسجة الرخوة المحيطة (العضلات والأوتار والأربطة) إذا كنت تشك في وجود خلع في الكتف فأنت بحاجة إلى عناية طبية فورية. برنامج التأهيل الكامل هو أمر ضروري إذا كان الرياضي يريد تجنب إصابة الكتف مرة أخري.</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:center\"><img alt=\"\" src=\"https://www.swedish-academy.se/uploads/kcfinder/upload/image/im6.jpg\" /></p>\r\n\r\n<table align=\"right\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" dir=\"rtl\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"height:10px; width:638px\">\r\n			<h2 dir=\"RTL\"><span style=\"color:#0000FF\"><strong>الأعراض</strong></span></h2>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<h2 dir=\"RTL\">&nbsp;</h2>\r\n\r\n<h2 dir=\"RTL\">&nbsp;</h2>\r\n\r\n<p dir=\"RTL\">انخلاع الكتفين غالبًا ما يحدث نتيجةً للسقوط على الذراع وهي ممدودة، أو التواء أو اصطدام الكتف. سوف تشعر بألم شديد مفاجئ في وقت وقوع الإصابة بالإضافة إلى ظهور التورم والكدمات في وقت لاحق. سيشعر المصاب بأن الكتف خرج فجأة من المفصل وغالبًا ما سيجد الجانب المصاب أكثر انخفاضًا من الجانب غير المصاب.</p>\r\n\r\n<p dir=\"RTL\">عادةً سيقوم المصاب بعقد الذراع بالقرب من جسده وسيقاوم نقله أو تحريكه إلى الخارج. إذا كان هناك أي ضرر في الأعصاب أو الأوعية الدموية فسوف يجد المصاب احمرارًا شديدًا أو تنميل أو تغير اللون من الذراع وحتى اليد.</p>\r\n\r\n<h2 dir=\"RTL\">&nbsp;</h2>\r\n\r\n<h2 dir=\"RTL\"><span style=\"color:#0000FF\"><strong>ما هو خلع الكتف؟</strong></span></h2>\r\n\r\n<p dir=\"RTL\">يحدث انخلاع الكتف عندما يخرج رأس عظم العضد فجأة من مفصل الكتف. عادة ما يحدث هذا الانخلاع إما من الخلف حيث ينخلع رأس عظم الذراع العلوي أو العضد من الجزء الخلفي للمفصل أو الأكثر شيوعًا هو انخلاع الكتف من الأمام حيث يخرج فجأة للأمام.</p>\r\n\r\n<p dir=\"RTL\">في معظم الحالات، تُضطر قمة عظم الذراع العلوي من الخروج للأمام عندما يُعقد الذراع إلى الجانب ويتحرك إلى الخارج. وهذا ما يسمى بالخلع الأمامي للكتف ويحدث في حوالي 95٪ من إجمالي الإصابات.</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\">ويمثل الخلع الخلفي حوالي 3٪ من الخلع في الكتف ويمكن أن يحدث خلال نوبات الصرع أو عند السقوط على اليد الممدودة.<br />\r\n&nbsp;</p>\r\n\r\n<p dir=\"RTL\">مفصل الكتف عرضة للإصابة بشكل خاص نظرًا لكثرة حركاته الواسعة، والتي تؤدي إلى عدم الاستقرار. وغالبا تكثر في الانشطة الرياضية وتدريبات اللياقة البدنية، معظم إصابات خلع الكتف تسبب تمزقات في الرباط الحقاني (<span dir=\"LTR\">Glenoid Labrum</span>) والذي هو عبارة عن حلقة غضروفية يعمل بمثابة كأس يستند عليه عظم العضد.</p>\r\n\r\n<p dir=\"RTL\">من المرجح حدوث أضرار للأربطة والأوتار والأعصاب والأوعية الدموية المحيطة وكسور في عظام أخرى. الإصابات المتكررة هو أمر شائع جدًّا لذلك فمن الضروري أن يتم برنامج تأهيل الكتف بصورة كافية حتى يتم الشفاء التام.</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<table align=\"right\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" dir=\"rtl\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"height:10px; width:638px\">\r\n			<h2 dir=\"RTL\"><u><strong>ا<span style=\"color:#0000FF\">لعلاج</span></strong></u></h2>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\">العلاج الفوري لخلع الكتف يمر بمرحلتين. أولًا حماية مفصل الكتف ومنع المزيد من الضرر، وثانيًّا الحصول على العناية الطبية في أقرب وقت ممكن.</p>\r\n\r\n<h4 dir=\"RTL\"><span style=\"color:#FF0000\"><span style=\"font-size:14px\"><strong>الإسعافات الأولية الفورية </strong></span></span></h4>\r\n\r\n<p dir=\"RTL\">الحصول على العناية الطبية على الفور. الذهاب إلى غرفة الطوارئ في المستشفى أو العثور على الطبيب في أقرب وقت ممكن. لا تتأخر! ولا تحرك مفصل الكتف. قم بتثبيت الذراع في حمالة إن أمكن ذلك لحمايته من مزيد من الضرر.</p>\r\n\r\n<p dir=\"RTL\">وضع الثلج أو العلاج البارد قد يساعد على تقليل الألم والتورم. لا تضع الثلج مباشرة على الجلد وعند وضعه تجنب تحريك المفصل. يمكن وضع الثلج لمدة 10 إلى 15 دقيقة كل ساعة في البداية، وتقليل التكرار حسب الحاجة.</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\"><span style=\"color:#FF0000\"><strong>إلارجاع </strong></span></p>\r\n\r\n<p dir=\"RTL\">الإرجاع حيث يتم إعادة عظم العضد المخلوع إلى المفصل. ينبغي إرجاع الكتف أو إعادتها إلى مكانه بواسطة المهنيين الطبيين المدربين فقط في أقرب وقت ممكن. أبدًا لا تحاول إرجاع الكتف إلى مكانه فقد تسبب مزيدًا من الضرر! من الأفضل عمل أشعة سينية قبل عملية الإرجاع لاستبعاد الكسور. إذا لم يكن هذا ممكنًا فيجب عمل أشعة سينية بعد الإرجاع. إذا كانت عملية الإرجاع صعبة فمن الضروري إجراؤها تحت التخدير. تشير الدلائل إلى أن الإرجاع الجراحي هو أفضل مسار لعلاج البالغين النشطين الشباب الذين تقل أعمارهم عن 30 عامًا ولديهم معدلات تكرار أقل ونتائج أفضل بشكل عام في نوعية الحياة.</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\"><span style=\"color:#FF0000\"><strong>التثبيت (التعطيل عن الحركة) </strong></span></p>\r\n\r\n<p dir=\"RTL\">بشكل تقليدي يتم تثبيت الكتف في حمالة في دوران وسطي مع الذراع حول الجسم حتى تلتئم الأنسجة. سوف يحتاج الكتف إلى تأهيل كامل لاستعادة الحركة والقوة. بعد عملية الإرجاع سوف يخبرك الطبيب بضرورة الراحة وتثبيت حركة الكتف في حمالة لمدة 5-7 أيام، وستطول هذه الفترة في حالة وجود كسور أو تلف شديد في الأنسجة الرخوة. قد يصف لك الطبيب مضادات الالتهابات غير الستيرويدية مثل الإيبوبروفين لتخفيف الألم والالتهاب.</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\"><span style=\"color:#FF0000\"><strong>التمارين </strong></span></p>\r\n\r\n<p dir=\"RTL\">بعد فترة من تدريبات التثبيت الأولية سيتم القيام بزيادة تدريجية في الحركة بدون ألم. يجب عمل تدريبات لتقوية عضلات الكفة المدورة والتي تدعم مفصل الكتف لمنع تكرار الإصابة. تمارين الدوران الوسطي في النطاق الداخلي هي تمارين مهمة. التمارين التي تُسْتَخدم فيها شريط مقاومة هي تمرينات ممتازة في المراحل المبكرة لهذه الإصابة.</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<table align=\"right\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" dir=\"rtl\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"height:10px; width:638px\">\r\n			<h2 dir=\"RTL\"><u><span style=\"color:#0000FF\"><strong>الجراحة</strong></span></u></h2>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"width:638px\">&nbsp;</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\">قد تتطلب بعض الحالات عملية جراحية إذا أصيب الكتف بخلع أكثر من مرة، أو إذا كان هناك كسر في أي عظم. أيضًا تكون الجراحة ضرورية بعد الإصابة بخلع في الكتف إذا كانت هناك أضرار واسعة للعضلات أو الأوتار أو الأعصاب أو الأوعية الدموية أو الرباط. عادة ما يتم إجراء العملية الجراحية في أقرب وقت ممكن بعد الإصابة. في حالات خلع الكتف المتكررة، فمن الأفضل القيام بالعملية الجراحية لمحاولة تحقيق الاستقرار في المفصل.</p>\r\n\r\n<p dir=\"RTL\">هناك عدد من العمليات التي يمكن القيام بها. القرار حول إجراء أي عملية يعتمد إلى حد كبير على حياة المصابين ونشاطهم. بعض العمليات تؤدي إلى خفض الدوران الخارجي للكتف ومثل هذه العملية لا تصلح للرياضيين المشاركين في رياضات رمي الرمح أو المضرب وسوف تؤثر على الأداء.</p>', NULL, NULL, NULL, 'ar'),
(217, 117, 'Dislocated shoulder', 'Dislocated-shoulder)', NULL, NULL, NULL, NULL, NULL, 'en'),
(218, 118, 'تحفيز الأعصاب الكهربائي عن طريق الجلد TENS', 'تحفيز-الأعصاب-الكهربائي-عن-طريق-الجلد-TENS', 'تحفيز العصب الكهربائي عبر الجلد (TENS) هو وسيلة لتخفيف الآلام. وكما يوحي اسمها، فهي تشتمل على تعريض المنطقة المصابة للتيار الكهربائي، ويتحقق ذلك عن طريق عدد من', '<p dir=\"RTL\" style=\"text-align:center\"><span style=\"font-size:24px\"><span style=\"color:#0000FF\">&nbsp;<strong>تحفيز الأعصاب الكهربائي عن طريق الجلد</strong><strong><span dir=\"LTR\"> TENS </span></strong></span></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:center\"><span style=\"font-size:18px\"><u><strong>-- الدكتور علي فالح --</strong></u></span></p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:center\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\" style=\"text-align:center\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\">تحفيز العصب الكهربائي عبر الجلد<span dir=\"LTR\"> (TENS) </span>هو وسيلة لتخفيف الآلام<span dir=\"LTR\">. </span>وكما يوحي اسمها، فهي تشتمل على تعريض المنطقة المصابة للتيار الكهربائي، ويتحقق ذلك عن طريق عدد من الأقطاب الكهربائية التي يتم تثبيتها على الجلد<span dir=\"LTR\">.</span></p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\">كيف يعمل تحفيز العصب الكهربائي عبر الجلد <span dir=\"LTR\">TENS</span></p>\r\n\r\n<p dir=\"RTL\">يخفف هذا الأسلوب من الألم بشكل رئيسي من خلال تحفيز آلية بوابة الألم. عندما تصبح الأنسجة تالفة، ستصبح الألياف العصبية في منطقة الألم مثارة وحساسة على نحو متزايد الأمر الذي يؤدي إلى الإدراك المتزايد بالألم في تلك المنطقة، ومع ذلك، في تلك المنطقة يوجد أيضاً عدد من المستقبلات الميكانيكية<span dir=\"LTR\"> mechanoreceptors </span>&nbsp;التي تستجيب إلى اللمس. تحفيز هذه الألياف العصبية يمكن أن تجاوز نبضات الألم من هذه المنطقة، وهذا يعرف باسم آلية بوابة الألم، كما يمكن لهذه المستقبلات أن تحفز التيار الكهربائي عند ترددات معينة (عادة <span dir=\"LTR\">90-130 </span>هرتز) على النحو المنصوص عليه في جهاز<span dir=\"LTR\"> TENS </span>والذي بدوره يؤدي إلى تأثير تخفيف الألم<span dir=\"LTR\">.</span></p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\">يعتبر استخدام أسلوب<span dir=\"LTR\"> TENS </span>وسيلة منتشرة للغاية لتخفيف الألم، فهي رخيصة نسبياً وسهلة الاستخدام والآثار الجانبية لها ضئيلة بالمقارنة مع بعض المسكنات التي تم تناولها عن طريق الفم، كما يعتقد أن هذا الأسلوب يمكن أن يخفف الآلام في ما يقرب من 70٪ من الحالات التي تعاني من الإصابات الحادة<span dir=\"LTR\">.</span></p>\r\n\r\n<p dir=\"RTL\"><span style=\"color:#0000FF\"><span style=\"font-size:18px\"><strong>تطبيق أسلوب <span dir=\"LTR\">TENS</span></strong></span></span></p>\r\n\r\n<p dir=\"RTL\">يمكن الآن شراء أجهزة<span dir=\"LTR\"> TENS </span>بسهولة من بعض تجار التجزئة المتخصصين، ويسهل تطبيقها، ولكن بقدر معين من العناية حيث يجب أن تؤخذ على أنه توجد نسبة صغيرة من المرضى الذين يعانون من الحساسية للمادة الموصلة بجانب الأقطاب أنفسهم أو الشريط الذي يستخدم لتأمينها في المكان<span dir=\"LTR\">. </span>معظم الآلات الجديدة تأتي مع أقطاب ذاتية اللصق والتي يمكن تغييرها بعد كل تطبيق لتقليل خطر انتقال العدوى إذا كان الجهاز يستخدمه أكثر من شخص، وحيث أن أعراض كل مريض تختلف تبعاً لها الإعدادات على جهاز<span dir=\"LTR\"> TENS </span>لذلك يجب أن يتم تعديلها لتلائم الأفراد، ونحن دائما ننصح باتباع التعليمات التي تأتي مع الجهاز أو التماس المشورة المهنية، وعادة ما تحتوي أجهزة <span dir=\"LTR\">TENS</span> على ثلاث متغيرات رئيسية للإعدادات هي<span dir=\"LTR\">:</span></p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\"><span style=\"color:#FF0000\"><strong>التردد</strong></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\">معظم الأجهزة تعرض تردد يقترب من 2-200 هرتز. لتحفيز المستقبلات الميكانيكية يجب أن يكون التردد عادة في المنطقة بين 90 و130 هرتز.</p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\"><span style=\"color:#FF0000\"><strong>الكثافة</strong></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\">يمكن أيضاً قابلية ضبط شدة التيار ومعظم الأجهزة قادرة على الوصول إلى شدة بين 80 و 100 ملي أمبير.</p>\r\n\r\n<ol>\r\n	<li dir=\"RTL\"><span style=\"color:#FF0000\"><strong>اتساع النبض</strong></span></li>\r\n</ol>\r\n\r\n<p dir=\"RTL\">يتحكم هذا الإعداد في الفترة الزمنية التي يمر فيها التيار الكهربائي عبر الأقطاب الكهربائية. العديد من المهنيين وضعوا تركيزاً أقل على هذا الإعداد من شدة وتردد في حين أن بعض الأجهزة حتى لا يوجد بها هذا التحكم المعين</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\"><span style=\"color:#0000FF\"><span style=\"font-size:18px\"><strong>هل سوف يسبب جهاز </strong><strong><span dir=\"LTR\">&nbsp;TENS</span></strong><strong> ألم؟</strong></span></span></p>\r\n\r\n<p dir=\"RTL\">يجب ألا تسبب أجهزة<span dir=\"LTR\"> TENS </span>عدم الراحة ولكن سيكون من الممكن أن يشعر الفرد بوخز خفيف عندما يكون الجهاز في وضع التشغيل، ومرة أخرى، ومع الاختلاف بين كل شخص من حيث ضبط الإعدادات أعلاه، فمن المهم للغاية الحصول على أعلى تأثير من الجهاز<span dir=\"LTR\">.</span></p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\"><span style=\"color:#0000FF\"><span style=\"font-size:18px\"><strong>موقع القطب</strong></span><strong><span dir=\"LTR\">:</span></strong></span></p>\r\n\r\n<p dir=\"RTL\">كما هو الحال مع الإعدادات أعلاه يجوز تغيير موقع الأقطاب في استجابة لأعراض الفرد، وعادة ما يتم وضع القطب كهربائي على أي من جانبي المنطقة المؤلمة ولكن قد يظهر أي عدد من الاختلافات. يركز بعض الممارسين على استهداف عصب هامشي أو نقطة وخز معينة</p>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\"><span style=\"color:#0000FF\"><span style=\"font-size:18px\"><strong>موانع الاستخدام</strong></span></span></p>\r\n\r\n<p dir=\"RTL\">ينبغي توخي الحذر في الحالات التالية<span dir=\"LTR\">:</span></p>\r\n\r\n<ul>\r\n	<li dir=\"RTL\">إذا كانت المنطقة من الجلد بها إحساس غير طبيعي<span dir=\"LTR\">.</span></li>\r\n	<li dir=\"RTL\">إذا كان المريض يعاني من نوبات الصرع.</li>\r\n	<li dir=\"RTL\">استخدام أجهزة<span dir=\"LTR\"> TENS </span>مع الأطفال، ويرجع إلى حقيقة أن مناطق نمو الطفل قد تتأثر بالتيار الكهربائي.</li>\r\n	<li dir=\"RTL\">إذا كان المصاب امرأة حامل يفضل طلب المشورة من المتخصص<span dir=\"LTR\">.</span></li>\r\n</ul>\r\n\r\n<p dir=\"RTL\">&nbsp;</p>\r\n\r\n<p dir=\"RTL\"><span style=\"color:#0000FF\"><span style=\"font-size:18px\"><strong>يجب أن لا تستخدم جهاز </strong><strong><span dir=\"LTR\">TENS</span></strong><strong> في الحالات التالية</strong><strong><span dir=\"LTR\">:</span></strong></span></span></p>\r\n\r\n<ul>\r\n	<li dir=\"RTL\">المرضى مستخدمي جهاز تنظيم ضربات القلب.</li>\r\n	<li dir=\"RTL\">المرضى الذين لديهم حساسية تجاه الأقطاب، أو مادة الجيل أو الرباط اللاصق.</li>\r\n	<li dir=\"RTL\">المرضى بأي أمراض جلدية مثل الأكزيما.</li>\r\n	<li dir=\"RTL\">المرضى الذين يعانون من الجروح المفتوحة في المنطقة.</li>\r\n	<li dir=\"RTL\">المرضى الذين لديهم مشاكل في الدورة الدموية.</li>\r\n	<li dir=\"RTL\">تطبيق العلاج في الرقبة ومنطقة أعلى الجذع<span dir=\"LTR\">.</span>\r\n	<p dir=\"RTL\">&nbsp;</p>\r\n	</li>\r\n</ul>', NULL, NULL, NULL, 'ar'),
(219, 118, 'TENS . transcutaneous electrical nerve stimulation', 'TENS-.-transcutaneous-electrical-nerve-stimulation', 'Transcutaneous electrical nerve stimulation (TENS) is a method of pain relief. As its name suggests, it involves exposing the affected area to electric current', NULL, NULL, NULL, NULL, 'en');
